"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"WordPress.org España\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"https://es.wordpress.org\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:5:\"width\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:6:\"height\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"32\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}s:4:\"item\";a:10:{i:0;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:43:\"WordPress 6.9 RC (candidata a definitiva) 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://es.wordpress.org/2025/11/12/wordpress-6-9-rc-candidata-a-definitiva-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"https://es.wordpress.org/2025/11/12/wordpress-6-9-rc-candidata-a-definitiva-1/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 12 Nov 2025 20:03:18 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:2:\"RC\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=736103\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:336:\"¡La primera versión candidata (RC1) para WordPress 6.9 ya está lista para su descarga y prueba! Esta versión de WordPress aún está en desarrollo . No la instales, ejecutes ni pruebes en sitios web de producción o críticos. En su lugar, se recomienda evaluar RC1 en un servidor y sitio de pruebas. WordPress 6.9 RC1 se [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:10642:\"\n<p>¡La primera versión candidata (RC1) para WordPress 6.9 ya está lista para su descarga y prueba!</p>\n\n\n\n<p><strong>Esta versión de WordPress aún está en desarrollo</strong> . No la instales, ejecutes ni pruebes en sitios web de producción o críticos. En su lugar, se recomienda evaluar RC1 en un servidor y sitio de pruebas.</p>\n\n\n\n<p>WordPress 6.9 RC1 se puede probar utilizando cualquiera de los siguientes métodos:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instala y activa el plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Beta Tester</a> en una instalación de WordPress. Selecciona el canal «Beta» y la transmisión «Solo Beta/ RC».</td></tr><tr><td><strong>Descarga directa</strong></td><td>Descarga la <a href=\"https://wordpress.org/wordpress-6.9-RC1.zip\" rel=\"nofollow\">versión RC1 (zip)</a> e instálala en un sitio web de WordPress.</td></tr><tr><td><strong>Línea de comandos</strong></td><td>Utiliza este comando <a href=\"https://make.wordpress.org/cli/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WP-CLI</a> :<br><code>wp core update --version=6.9-RC1</code></td></tr><tr><td><strong>Campo de pruebas de WordPress</strong></td><td>Utiliza la  <a href=\"https://playground.wordpress.net/?php=8.3&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">instancia de WordPress Playground 6.9 RC1</a> para probar el software directamente en tu navegador. No requiere configuración: ¡simplemente haz clic y listo! </td></tr></tbody></table></figure>\n\n\n\n<p>La fecha de lanzamiento definitiva prevista para WordPress 6.9 es <strong>el 2 de diciembre de 2025.</strong> El <a href=\"https://make.wordpress.org/core/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">calendario de lanzamientos completo se puede consultar aquí</a> . Tu ayuda probando las versiones Beta y RC es fundamental para que esta versión sea lo más estable y potente posible.</p>\n\n\n\n<p>Por favor, continúa consultando el <a href=\"https://make.wordpress.org/core/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">blog Make WordPress Core</a> en las próximas semanas para obtener más información sobre <a href=\"https://make.wordpress.org/core/tag/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">las publicaciones relacionadas con la versión 6.9 .</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué novedades incluye WordPress 6.9 RC1?</h2>\n\n\n\n<p>Consulta el <a href=\"https://es.wordpress.org/2022/09/22/wordpress-6-1-beta-1-ya-disponible/\" data-type=\"post\" data-id=\"115714\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la Beta 1</a> para obtener más detalles sobre WordPress 6.9.</p>\n\n\n\n<p>Puedes consultar los detalles técnicos de todos los problemas abordados desde la Beta 4 utilizando estos enlaces:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.9?since=2025-11-07&amp;until=2025-11-11\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Commits de Gutenberg en la versión 6.9</a> desde el 7 de noviembre de 2025</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/log/?revs=61183-61203\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Cambios importantes en el núcleo para la versión 6.9</a> desde el 7 de noviembre de 2025</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=11%2F07%2F2025..11%2F11%2F2025&amp;milestone=6.9&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=changetime&amp;col=type&amp;order=id\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Tickets cerrados</a> desde el 7 de noviembre de 2025</li>\n</ul>\n\n\n\n<p>¿Quieres saber más sobre esta versión? Aquí tienes algunos de los aspectos más destacados:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Mejoras en el editor del sitio y creación de contenido perfeccionada\n<ul class=\"wp-block-list\">\n<li>Capacidad para ocultar bloques</li>\n\n\n\n<li>Nuevos bloques</li>\n\n\n\n<li>Notas en bloques</li>\n\n\n\n<li>Paleta de comandos universal en wp-admin</li>\n</ul>\n</li>\n\n\n\n<li>Novedades para desarrolladores\n<ul class=\"wp-block-list\">\n<li>Mejoras de los componentes de vistas de datos y formularios de datos</li>\n\n\n\n<li>Nuevas funcionalidades en la API</li>\n\n\n\n<li>Actualizaciones de la API de interactividad</li>\n\n\n\n<li>Actualizaciones de la API de enlace de bloques</li>\n</ul>\n</li>\n\n\n\n<li>Mejoras de rendimiento\n<ul class=\"wp-block-list\">\n<li>Mejora en la gestión de scripts y estilos</li>\n\n\n\n<li>Consultas y almacenamiento en caché optimizadas</li>\n\n\n\n<li>Se ha añadido la capacidad de gestionar la «fetchpriority» en los módulos de ES y los mapas de importación.</li>\n\n\n\n<li>Estandarización del almacenamiento en búfer de salida</li>\n</ul>\n</li>\n</ul>\n\n\n\n<p>El lanzamiento final está previsto para el 2 de diciembre. Como siempre, el éxito del lanzamiento depende de tu confirmación durante las pruebas. ¡Así que descarga y haz pruebas!</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo puedes contribuir</h2>\n\n\n\n<p>WordPress es un software de código abierto posible gracias a una comunidad apasionada de personas que colaboran y contribuyen a su desarrollo. Los recursos que se presentan a continuación describen diversas maneras en que puedes ayudar a la plataforma web de código abierto más popular del mundo, independientemente de tus conocimientos técnicos.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Participa en las pruebas</h3>\n\n\n\n<p>Realizar pruebas para detectar problemas es fundamental para el desarrollo de cualquier software. También es una forma valiosa para que cualquiera pueda contribuir.&nbsp;</p>\n\n\n\n<p>Tu ayuda para probar la versión RC1 de WordPress 6.9 es fundamental para garantizar que la versión final sea la mejor posible. Si bien probar el proceso de actualización es esencial, probar las nuevas funcionalidades es igualmente importante. Esta <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">guía detallada</a> te mostrará cómo probar las características de WordPress 6.9.</p>\n\n\n\n<h4 class=\"wp-block-heading\">Llamados a realizar pruebas</h4>\n\n\n\n<p>Gracias a todos los que ayudan a probar las siguientes mejoras y correcciones de errores:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2025/10/06/call-for-testing-accordion-block/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Bloque de acordeón</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2025/10/04/call-for-testing-ability-to-hide-blocks/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Capacidad para ocultar bloques</a></li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64099\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Estilos de bloques de carga de temas clásicos bajo demanda</a></li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/ticket/64204\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Avisos de notas modificadas</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/10/abilities-api-in-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">API de habilidades</a></li>\n</ul>\n\n\n\n<p>Si encuentras algún problema, infórmalo en la <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">sección Alfa/Beta</a> de los foros de soporte o directamente en el <a href=\"https://core.trac.wordpress.org/newticket\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Trac</a> si te sientes a gusto redactando un informe de error que permita reproducirlo. También puedes comprobar si tu problema coincide con la lista de <a href=\"https://core.trac.wordpress.org/tickets/major\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">errores conocidos</a> .</p>\n\n\n\n<p>¡Gracias a todos los que ayudan con las pruebas!</p>\n\n\n\n<h3 class=\"wp-block-heading\">Actualiza tu tema o plugin</h3>\n\n\n\n<p>Para los autores de plugins y temas, sus productos desempeñan un papel fundamental en la ampliación de la funcionalidad y el valor de WordPress para todos los usuarios.</p>\n\n\n\n<p>Gracias por seguir probando tus temas y plugins con las versiones beta de WordPress 6.9. Con RC1, deberás finalizar las pruebas y actualizar la versión <em>«Probado hasta» en </em><a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">el archivo README de tu plugin</a> a la versión 6.9.</p>\n\n\n\n<p>Si encuentras problemas de compatibilidad, publica información detallada en el <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">foro de soporte</a> .</p>\n\n\n\n<h3 class=\"wp-block-heading\">Prueba en tus plataformas de alojamiento.</h3>\n\n\n\n<p>Los servicios de alojamiento web proporcionan la infraestructura esencial para el soporte de WordPress y sus usuarios. </p>\n\n\n\n<p>Las pruebas en los sistemas de alojamiento ayudan a fundamentar el proceso de desarrollo, a la vez que garantizan que WordPress y las plataformas de alojamiento sean totalmente compatibles, estén libres de errores, optimizadas para la mejor experiencia de usuario posible y que las actualizaciones se implementen en los sitios web de los clientes sin problemas.</p>\n\n\n\n<p>¿Quieres probar WordPress en tu sistema de alojamiento? <a href=\"https://make.wordpress.org/hosting/test-results-getting-started/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Empieza a configurar las pruebas de alojamiento distribuido aquí</a> . </p>\n\n\n\n<p>¡Gracias a todos <a href=\"https://make.wordpress.org/hosting/test-results/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">los proveedores de alojamiento web que ayudan a probar WordPress</a> !</p>\n\n\n\n<p>¿Tienes curiosidad por probar las versiones en general? Sigue las <a href=\"https://make.wordpress.org/test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">iniciativas de pruebas en Make Core</a> y únete al <a href=\"https://wordpress.slack.com/messages/core-test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">canal #core-test</a> en <a href=\"https://wordpress.slack.com/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Making WordPress Slack</a> .</p>\n\n\n\n<h2 class=\"wp-block-heading\">Un haiku para la RC1</h2>\n\n\n\n<pre class=\"wp-block-verse\"><em>Al amanecer</em> ,<br><em>RC1 rompe su cascarón</em><br><em>y emerge fuerte</em> .</pre>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2025/11/12/wordpress-6-9-rc-candidata-a-definitiva-1/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"736103\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:73:\"\n		\n		\n					\n		\n		\n		\n				\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordCamp Valencia 2025: Cuando eres Tech a tope\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2025/11/03/wordcamp-valencia-2025-cuando-eres-tech-a-tope/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://es.wordpress.org/2025/11/03/wordcamp-valencia-2025-cuando-eres-tech-a-tope/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 03 Nov 2025 15:28:21 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=733080\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:308:\"Venga, que ya sabes de qué te voy a hablar, así que siéntate, coge tu móvil y abre la aplicación de la agenda para marcar en negrita los días 8 y 9 de noviembre de 2025, porque tendrá lugar el WordPress Tech Congress… ¿Cómo?&#8230; ¿Que no sabes de qué hablo? ¡Menos mal que me tienes [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:7925:\"\n<p>Venga, que ya sabes de qué te voy a hablar, así que siéntate, coge tu móvil y abre la aplicación de la agenda para marcar en negrita los días 8 y 9 de noviembre de 2025, porque tendrá lugar el WordPress Tech Congress…</p>\n\n\n\n<p>¿Cómo?&#8230; ¿Que no sabes de qué hablo?</p>\n\n\n\n<p>¡Menos mal que me tienes aquí, escribiendo como un loco, para informarte de todas las cosas chulas que ocurren en torno a nuestro CMS preferido!</p>\n\n\n\n<h2 class=\"wp-block-heading\">La cita: ¿dónde y cuándo?</h2>\n\n\n\n<p><strong>Los días 8 y 9 de noviembre tendrá lugar la WordCamp Valencia 2025: WordPress Tech Congress</strong> así que, como ya tienes abierta la app de tu móvil, mueve los dedos sobre la pantalla y reserva ese fin de semana para disfrutar, <strong>en el Complejo Deportivo Cultural “La Petxina”</strong>, de lo mejorcito en ponencias que vas a ver en mucho tiempo.</p>\n\n\n\n<p>¿Y por qué debes ir? Pues mira… Lo primero, porque es Valencia y ya sabes lo que eso significa, aunque tire de topicazos: Esa rica paellita que sólo allí puedes comer, ese sol que ilumina los días de un modo diferente y, cómo no, ese ambientazo que se respira en cada poro de la ciudad.</p>\n\n\n\n<p>Y si con esto no te he convencido, aquí va lo segundo…</p>\n\n\n\n<p><strong>Esta WordCamp Valencia 2025: WordPress Tech Congress se ha puesto las pilas a lo bestia</strong> y va a ser un eventazo de esos que no olvidarás en tu vida, con dos salas simultaneando unas ponencias que te ayudarán en tus proyectos presentes y futuros, haciéndolos mucho mejores de lo que ya son (porque sé de sobra que, aunque no me lo quieras confesar, eres un auténtico pro de WordPress).</p>\n\n\n\n<p><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué te vas a encontrar? (la parte jugosa)</h2>\n\n\n\n<p>Te vuelvo a recordar que <strong>la WordCamp Valencia 2025: WordPress Tech Congress tendrá lugar en el Complejo Deportivo Cultural “La Petxina” durante los días 8 y 9 de noviembre</strong> (vuelve a coger tu móvil por si acaso y confirma los datos, que nunca viene de más asegurarse).</p>\n\n\n\n<p>Bien, ¿dónde lo había dejado?&#8230; ¡Ah, sí!&#8230; Piensa en esas dos salas funcionando en paralelo a todo trapo durante el sábado, con unas charlas de lo más flipante y presentadas por unos ponentes que, si estuviéramos en un concierto de rock o de pop, serían las auténticas estrellas de la música.</p>\n\n\n\n<p>Estos cracks de la ponencia <strong>vienen con unos perfiles variados, pero con una única misión: Instruirte (con teoría o casos reales) y, de paso, soltarte truquitos prácticos</strong>, de esos que, antes de abrir la libreta, ya te han dado cinco ideas geniales para implementar el lunes en ese proyecto que tienes entre manos.</p>\n\n\n\n<p>Y entre estas charlas alucinantes encontrarás algunas como:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Potenciar WordPress</strong> con un agente de ecommerce</li>\n\n\n\n<li>Diseños que enganchan en <strong>la era de la IA</strong></li>\n\n\n\n<li><strong>SASS</strong> (el superviviente del apocalipsis CSS)</li>\n\n\n\n<li>Fidelizar y vender más con <strong>email marketing</strong></li>\n\n\n\n<li><strong>Sesgos cognitivos</strong> en el ecommerce</li>\n\n\n\n<li>Del SEO al AX</li>\n\n\n\n<li>Etc…</li>\n</ul>\n\n\n\n<p>Sé que la boca se te está haciendo agua, así que aprovecho de nuevo para decirte que <strong>la WordCamp Valencia 2025: WordPress Tech Congress tendrá lugar los días 8 y 9 de noviembre en el Complejo Deportivo Cultural “La Petxina”</strong> (esta vez no hace falta que revises la agenda del móvil, ya sé que lo has hecho bien).</p>\n\n\n\n<p><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Y después de aprender: ¡Fiesta, fiesta!</h2>\n\n\n\n<p>Porque ya sabes de sobra que <strong>las WordCamp no son solo charlas, ponentes, comida</strong>, café y patrocinadores que te regalan chapas, pegatinas, tazas y camisetas…</p>\n\n\n\n<p>Por cierto, ¡qué maravilla los patrocinadores!&#8230; Que sepáis que nunca os olvido y que, sin vosotros, no sería posible que estos eventos pudieran hacerse o que las entradas al evento tuvieran un precio muy por debajo de lo que realmente valen… ¡Gracias, patrocinadores!</p>\n\n\n\n<p>Por cierto, ¿por dónde iba que me he “despistao”?&#8230; Ah, sí… Las charlas, los ponentes…</p>\n\n\n\n<p>Vas a acabar cansado pero muy satisfecho porque el sábado <strong>vas a aprender muchísimo y vas a conocer a gente que merece mucho la pena</strong> y con la que hasta puedes entablar relaciones profesionales (eso que llaman networking).</p>\n\n\n\n<p>Pero, si me admites un consejo, no te vayas aún a la cama, porque tras acabar las ponencias del sábado… ¡Comienza la fiesta!</p>\n\n\n\n<p><strong>Así que anímate y desconecta</strong> con el resto de asistentes tomando algo, y es que en Valencia hay vida nocturna que te está esperando. Y si eres de los formales y no quieres juerga nocturna, pues durante el evento, tras cada ponencia, hay también unas tertulias en los pasillos igual de valiosas.</p>\n\n\n\n<p>En definitiva, que <strong>lo importante es volver el lunes a tu casa con la batería recargada y con esas conversaciones que “inspiran” revoloteando por tu cerebro.</strong></p>\n\n\n\n<p><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<p>Y ahora, inocente de ti, es cuando piensas que, como ya lo has dado todo durante el sábado (fiesta incluida), ya no tienes nada más que hacer… Pues que sepas que…</p>\n\n\n\n<h2 class=\"wp-block-heading\">¡El domingo no es momento de descansar!</h2>\n\n\n\n<p>Por si te ha parecido poco lo del sábado, <strong>el domingo es el Contributor Day</strong>. Si nunca has ido a uno, te lo explico rapidito: <strong>Te vas a poner manos a la obra y a colaborar en proyectos para la comunidad WordPress</strong>, aparte de conocer a gente que contribuye en temas, traducciones, marketing y en otras cosas que quizás ni sabías que existían.</p>\n\n\n\n<p>Y cuando llegues por fin a tu casa, sentirás esa gran y extraña satisfacción de:&nbsp;</p>\n\n\n\n<p>“<em>¡Qué guay! He hecho algo útil para la comunidad, pero sigo sin entender por qué me han puesto esa pegatina en el portátil, aunque para ser sincero, la verdad es que verla ahí me transmite un poco de orgullo</em>”.</p>\n\n\n\n<p>Así que ya lo sabes. Si eres desarrollador, traductor, diseñador, creador de contenidos o simplemente un fan con muchas ganas de dejar huella, el Contributor Day es tu sitio.&nbsp;</p>\n\n\n\n<p><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Ya no me enrollo más</h2>\n\n\n\n<p>No hace falta que revises tu móvil, porque en tu agenda han quedado grabados a fuego <strong>los días 8 y 9 de noviembre, fecha en la que tendrá lugar la WordCamp Valencia 2025: WordPress Tech Congress, en el Complejo Deportivo Cultural “La Petxina”</strong>.</p>\n\n\n\n<p>Si todavía tienes dudas sobre si ir o no, te lo pongo bien clarito: <strong>Vas a aprender muchas cosas prácticas, vas a conocer gente alucinante y muy profesional, puedes colaborar en el Contributor Day</strong> y, sobre todo, pasar un finde espectacular en Valencia…</p>\n\n\n\n<p>Y seamos francos, <strong>un par de días en Valencia le mejoran a cualquiera el ánimo, así que compra tu entrada</strong>, reserva en tu agenda esos dos días y prepárate para decir a tu regreso eso de: “¿Os conté lo de la charla de…?”</p>\n\n\n\n<p>¡Vais a fardar un huevo!</p>\n\n\n\n<p>¡Nos vemos en La Petxina!</p>\n\n\n\n<p><a href=\"https://valencia.wordcamp.org/2025/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entrada</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://es.wordpress.org/2025/11/03/wordcamp-valencia-2025-cuando-eres-tech-a-tope/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"733080\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.9 Beta 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://es.wordpress.org/2025/10/28/wordpress-6-9-beta-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"https://es.wordpress.org/2025/10/28/wordpress-6-9-beta-2/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 28 Oct 2025 22:28:57 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"beta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=729478\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:327:\"¡WordPress 6.9 Beta 2 ya está lista para probar! Esta versión beta de WordPress está en desarrollo . No instales, ejecutes ni pruebes esta versión de WordPress en sitios web en producción o esenciales. En su lugar, haz pruebas con la Beta 2 en un servidor y sitio de pruebas. Puedes probar WordPress 6.9 Beta 2 [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5522:\"\n<p>¡WordPress 6.9 Beta 2 ya está lista para probar!</p>\n\n\n\n<p><strong>Esta versión beta de WordPress está en desarrollo</strong> . No instales, ejecutes ni pruebes esta versión de WordPress en sitios web en producción o esenciales. En su lugar, haz pruebas con la Beta 2 en un servidor y sitio de pruebas.</p>\n\n\n\n<p>Puedes probar WordPress 6.9 Beta 2 de cualquiera de las siguientes maneras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Instala y activa el plugin <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> en una instalación de WordPress. (Selecciona el canal «Bleeding edge» y la transmisión «Beta/RC Only»).</td></tr><tr><td><strong>Descarga directa</strong></td><td>Descarga la <a href=\"https://wordpress.org/wordpress-6.9-beta2.zip\">versión Beta 2 (zip)</a> e instálela en un sitio web de WordPress.</td></tr><tr><td><strong>Línea de comandos</strong></td><td>Utiliza este comando <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> :<br><code>wp core update --version=6.9-beta2</code></td></tr><tr><td><strong>Zona de juegos de WordPress</strong></td><td>Usa la&nbsp;<a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">instancia de WordPress Playground 6.9 Beta 2</a>&nbsp;para probar el software directamente en tu navegador. No requiere configuración: ¡solo haz clic y listo!&nbsp;</td></tr></tbody></table></figure>\n\n\n\n<p>La fecha de lanzamiento final programada para WordPress 6.9 es <strong>el 2 de diciembre de 2025.</strong> El <a href=\"https://make.wordpress.org/core/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">calendario completo de lanzamientos se puede consultar aquí</a> . tu ayuda en las pruebas de las versiones Beta y RC es vital para que esta versión sea lo más estable y potente posible. Consulta el <a href=\"https://make.wordpress.org/core/\">blog Make WordPress Core</a> para obtener más información <a href=\"https://make.wordpress.org/core/tag/6-9/\">sobre la versión 6.9</a> en las próximas semanas. ¡Gracias a todos los que contribuyen con las pruebas! </p>\n\n\n\n<p><strong>Ponte al día con las novedades de WordPress 6.9</strong> : lee el <a href=\"https://make.wordpress.org/core/2025/10/21/wordpress-6-9-beta-1/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">anuncio de la versión Beta 1</a> para conocer los detalles y aspectos destacados.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo probar esta versión</h2>\n\n\n\n<p>Tu ayuda para probar la versión Beta 2 de WordPress 6.9 es clave para garantizar que todo en la versión sea óptimo. Si bien probar el proceso de actualización es esencial, probar nuevas funciones es igualmente importante. Esta <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">guía detallada</a> te guiará en el proceso de prueba de funcionalidades en WordPress 6.9.</p>\n\n\n\n<p>Si encuentras algún problema, infórmalo al <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">área Alfa/Beta</a> de los foros de soporte o directamente en el <a href=\"https://core.trac.wordpress.org/newticket\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Trac</a> si te sientes cómodo escribiendo un informe de errores reproducible. También puedes comparar tu problema con una lista de <a href=\"https://core.trac.wordpress.org/tickets/major\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">errores conocidos</a> .</p>\n\n\n\n<p>¿Te interesa probar las versiones en general? Sigue las <a href=\"https://make.wordpress.org/test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">iniciativas de pruebas en Make Core</a> y únete al <a href=\"https://wordpress.slack.com/messages/core-test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">canal #core-test</a> en <a href=\"https://wordpress.slack.com/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\"> el Slack de Making WordPress</a> .</p>\n\n\n\n<h2 class=\"wp-block-heading\">Actualizaciones y aspectos destacados de la versión Beta 2</h2>\n\n\n\n<p>WordPress 6.9 Beta 2 contiene más de 33 actualizaciones y correcciones del editor desde el lanzamiento de la versión Beta 1, incluidos 28 tiques para el núcleo de WordPress.</p>\n\n\n\n<p>Cada ciclo beta se centra en la corrección de errores; con tu ayuda durante las pruebas, se irán añadiendo más. Puedes consultar la información técnica de todos los problemas solucionados desde la Beta 1 en estos enlaces:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.9?since=2025-10-22&amp;until=2025-10-28\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Commits a GitHub para la versión 6.9</a> desde el 21 de octubre de 2025</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=10%2F22%2F2025..10%2F28%2F2025&amp;milestone=6.9&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Tiques del Trac cerrados</a> desde el 21 de octubre de 2025</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Un haiku de la Beta 2</h2>\n\n\n\n<pre class=\"wp-block-verse\"><em>Vuelve el rocío de la mañana,</em>\n<em>Los pequeños arreglos florecen en silencio.</em>\n<em>El código encuentra su equilibrio.</em></pre>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://es.wordpress.org/2025/10/28/wordpress-6-9-beta-2/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"729478\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"WordPress 6.9 Beta 1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://es.wordpress.org/2025/10/22/wordpress-6-9-beta-1/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:65:\"https://es.wordpress.org/2025/10/22/wordpress-6-9-beta-1/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 22 Oct 2025 23:38:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:3:\"6.9\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:4:\"beta\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=726287\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:376:\"¡WordPress 6.9 Beta 1 está lista para descargar y probar! Esta versión beta está destinada únicamente a pruebas y desarrollo . No instales, ejecutes ni pruebes esta versión de WordPress en sitios web de producción o esenciales. En su lugar, utiliza un entorno de pruebas o un sitio web local para explorar las nuevas funcionalidades. Cómo probar WordPress [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:12549:\"\n<p>¡WordPress 6.9 Beta 1 está lista para descargar y probar!</p>\n\n\n\n<p><strong>Esta versión beta está destinada únicamente a pruebas y desarrollo</strong> . No instales, ejecutes ni pruebes esta versión de WordPress en sitios web de producción o esenciales. En su lugar, utiliza un entorno de pruebas o un sitio web local para explorar las nuevas funcionalidades.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo probar WordPress 6.9 Beta 1</h2>\n\n\n\n<p>Puedes probar WordPress 6.9 Beta 1 de cualquiera de las siguientes maneras:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td class=\"has-text-align-left\" data-align=\"left\"><strong>Plugin&nbsp;Beta Tester de WordPress</strong></td><td class=\"has-text-align-left\" data-align=\"left\">Instala y activa el plugin <a href=\"https://es.wordpress.org/plugins/wordpress-beta-tester/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Beta Tester</a> en una instalación de WordPress. Selecciona el canal » Beta » y la transmisión «Solo Beta/ RC «.</td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\"><strong>Descarga directa</strong></td><td class=\"has-text-align-left\" data-align=\"left\">Descarga la <a href=\"https://wordpress.org/wordpress-6.9-beta1.zip\" rel=\"nofollow\">versión Beta 1 (zip)</a> e instálela en un sitio web de WordPress.</td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\"><strong>Línea de comandos (&nbsp;WP-CLI&nbsp;)</strong></td><td class=\"has-text-align-left\" data-align=\"left\">Utiliza este comando de <a href=\"https://make.wordpress.org/cli/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WP-CLI</a>:<br><code>wp core update --version=6.9-beta1</code></td></tr><tr><td class=\"has-text-align-left\" data-align=\"left\"><strong>Zona de juegos de WordPress</strong></td><td class=\"has-text-align-left\" data-align=\"left\">Usa una <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=r8nny4q18x\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">instancia de WordPress Playground 6.9 Beta 1</a> para probar el software directamente en tu navegador. No requiere configuración: ¡solo haz clic y listo!</td></tr></tbody></table></figure>\n\n\n\n<p>La fecha de lanzamiento final programada para WordPress 6.9 es <strong>el 2 de diciembre de 2025.</strong> El <a href=\"https://make.wordpress.org/core/6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">calendario completo de lanzamientos se puede consultar aquí</a> .</p>\n\n\n\n<p>Tu ayuda en las pruebas de las versiones Beta y RC es vital para que esta versión sea lo más estable y potente posible. ¡Gracias a todos los que contribuyen con sus pruebas!</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué importancia tienen tus pruebas?</h2>\n\n\n\n<p>La detección de problemas es fundamental en el desarrollo de cualquier software y una forma significativa de contribuir, independientemente de la experiencia.  <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Los detalles sobre qué probar en WordPress 6.9</a> están <strong>aquí</strong> .</p>\n\n\n\n<p>Si encuentras algún problema, compártelo en la <a href=\"https://wordpress.org/support/forum/alphabeta/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">sección Alfa/Beta</a> de los foros de soporte. Si no te importa enviar un informe de error reproducible, puedes hacerlo <a href=\"https://core.trac.wordpress.org/newticket\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">a través de WordPress Trac</a> . También puedes comparar tu problema con esta lista de <a href=\"https://core.trac.wordpress.org/tickets/major\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">errores conocidos</a> .</p>\n\n\n\n<p>¿Te interesa probar versiones en general y cómo empezar? Sigue las <a href=\"https://make.wordpress.org/test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">iniciativas de pruebas en Make Core</a> y únete al <a href=\"https://wordpress.slack.com/messages/core-test/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">canal #core-test</a> en <a href=\"https://wordpress.slack.com/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">el Slack de WordPress</a>.</p>\n\n\n\n<p>WordPress 6.9 incluirá muchas características nuevas que anteriormente solo estaban disponibles en el plugin Gutenberg . Obtén más información sobre las actualizaciones de Gutenberg desde WordPress 6.8 en las entradas de <a href=\"https://make.wordpress.org/core/tag/gutenberg-new/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">«Novedades de Gutenberg»</a> para las versiones <a href=\"https://make.wordpress.org/core/2025/06/05/whats-new-in-gutenberg-20-4-and-20-5/\">20.4 y 20.5</a> , <a href=\"https://make.wordpress.org/core/2025/06/11/whats-new-in-gutenberg-20-6-and-20-7/\">20.6 y 20.7</a> , <a href=\"https://make.wordpress.org/core/2025/06/11/whats-new-in-gutenberg-20-8-and-20-9/\">20.8 y 20.9</a> , <a href=\"https://make.wordpress.org/core/2025/06/11/whats-new-in-gutenberg-21-0-11-june/\">21</a> , <a href=\"https://make.wordpress.org/core/2025/07/02/whats-new-in-gutenberg-21-1/\">21.1</a> , <a href=\"https://make.wordpress.org/core/2025/07/18/whats-new-in-gutenberg-21-2-16-july/\">21.2</a> , <a href=\"https://make.wordpress.org/core/2025/07/30/whats-new-in-gutenberg-21-3/\">21.3</a> , <a href=\"https://make.wordpress.org/core/2025/08/14/whats-new-in-gutenberg-21-4-13-august/\">21.4</a> , <a href=\"https://make.wordpress.org/core/2025/08/28/whats-new-in-gutenberg-21-5/\">21.5</a> , <a href=\"https://make.wordpress.org/core/2025/09/10/whats-new-in-gutenberg-21-6-10-september/\">21.6</a> , <a href=\"https://make.wordpress.org/core/2025/09/29/whats-new-in-gutenberg-21-7-24-september/\">21.7</a> , <a href=\"https://make.wordpress.org/core/2025/10/08/whats-new-in-gutenberg-21-8-08-october/\">21.8</a> y 21.9.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué novedades hay en WordPress 6.9?</h2>\n\n\n\n<p>Esta versión trae importantes avances en edición, colaboración y capacidades para desarrolladores.&nbsp;</p>\n\n\n\n<h3 class=\"wp-block-heading\">Editor del sitio</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2025/10/03/help-test-changes-to-template-management/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Gestión de plantillas</a> ampliada : crea varias plantillas por slug, crea un borrador antes de publicar, activa o desactiva plantillas según sea necesario y conserva plantillas personalizadas al cambiar de tema.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Funciones de creación y edición de contenido</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Notas</strong>: ahora se pueden adjuntar notas a bloques individuales. Esto permite la colaboración asincrónica y flujos de trabajo editoriales más eficientes. Anteriormente se conocía como «Comentarios de bloques».</li>\n\n\n\n<li><strong>Ocultar bloques en la parte visible de la web</strong>: puedes ocultar bloques en la parte visible de la web y dejarlos editables en la administración, lo que facilita las pruebas, la exploración de diseños alternativos y los flujos de trabajo no destructivos.</li>\n\n\n\n<li><strong>Nuevos bloques</strong>: acordeón, consulta de términos, bloque matemático y tiempo de lectura. La opción de formato «Ajustar texto» ahora está disponible para bloques de párrafos y encabezados, lo que proporciona más flexibilidad para la creación de sitios.</li>\n\n\n\n<li><strong>Experiencia de arrastrar y soltar bloques</strong>: en lugar de arrastrar una copia, los usuarios ahora mueven el bloque dentro del editor mientras reorganizan el contenido. El resultado es una experiencia de edición visualmente mejorada y accesible para todos los usuarios.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Paleta de comandos</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li>La paleta de comandos (<em>pulsa Ctrl+K o Comando+K en cualquier parte del escritorio para usarla</em>) está disponible tanto en el editor como en el escritorio, lo que facilita y agiliza la navegación y las acciones. Simplemente escribe en la paleta de comandos para buscar, acceder a pantallas específicas o activar acciones directamente. Esto también sienta las bases para futuras integraciones con la nueva API de habilidades .</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Actualizaciones de API y desarrolladores</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/ai/2025/07/17/abilities-api/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\"><strong>API de habilitades</strong></a>: un registro unificado de habilidades de WordPress invocables con entradas y salidas definidas, diseñado para integraciones de IA y automatización de desarrolladores.</li>\n\n\n\n<li><strong>Mejoras en la API de interactividad</strong>: un nuevo algoritmo potencia la navegación del lado del cliente, lo que permite a los desarrolladores crear nuevas experiencias de usuario que antes no eran posibles y que se incluirán en futuras versiones de WordPress, como la búsqueda instantánea o el envío de comentarios del lado del cliente.</li>\n\n\n\n<li><strong>Componentes DataViews y DataForm</strong>: esta versión incorpora compatibilidad con más tipos de campos y nuevos diseños. DataViews ahora ofrece desplazamiento infinito para conjuntos de datos grandes, además de permitir filtros bloqueados y una selección múltiple mejorada mediante el nuevo DataViewsPicker.</li>\n\n\n\n<li><strong>API HTML</strong>: esta actualización hacen que el análisis, la transformación y la validación de HTML sean más seguros y eficientes en bloques, editores de sitios y plugins personalizados, lo que aumenta la precisión de la manipulación programática de HTML.</li>\n\n\n\n<li><strong>API de enlace de bloques</strong>: el bloque de fecha admite enlaces de bloques, el bloque de imagen permite enlazar al título, una interfaz de usuario mejorada y extensible que permite fuentes personalizadas en el editor de enlaces.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"performance\">Rendimiento</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Se introduce el «búfer de salida de mejora de plantillas» para desbloquear nuevas oportunidades de optimización.</li>\n\n\n\n<li>Los estilos de bloques se cargan bajo demanda en los temas clásicos para reducir el uso general de CSS .</li>\n\n\n\n<li>Compatibilidad para <code>fetchpriority</code>scripts y módulos de script.</li>\n\n\n\n<li>Compatibilidad para imprimir módulos de script en el pie de página.</li>\n\n\n\n<li>Mejora en la incorporación de hojas de estilo en línea para reducir el bloqueo de renderizado.</li>\n\n\n\n<li>Minimizado de hojas de estilo en temas de bloques nativos.</li>\n\n\n\n<li>Los scripts y estilos para bloques ocultos se omiten por defecto.</li>\n\n\n\n<li>El script de detección de emojis se ha convertido en un módulo de script y se mueve al pie de página.</li>\n\n\n\n<li>Optimizaciones de consultas de bases de datos y almacenamiento en caché.</li>\n\n\n\n<li>El cron se genera al apagar en lugar de al iniciar para reducir el impacto en el TTFB.</li>\n\n\n\n<li>Mejoras en el almacenamiento en caché de fuentes RSS .</li>\n\n\n\n<li>Optimizaciones de procesamiento UTF-8.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Notas adicionales</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>No hay un ningún nuevo tema por defecto en WordPress 6.9</strong>: no hay un paquete de temas incluido con la versión 6.9; el foco está en mejorar la experiencia del editor, la compatibilidad de APIs y el rendimiento.</li>\n\n\n\n<li><strong>Plugins de vista previa anticipada</strong>: Se lanzan MCP Adapter y el cliente PHP AI como paquetes y plugins canónicos junto con la versión 6.9, pero <em>no</em> son parte del núcleo.\n<ul class=\"wp-block-list\">\n<li>El <a href=\"https://make.wordpress.org/ai/2025/07/17/mcp-adapter/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">adaptador MCP</a> convierte las capacidades de WordPress en herramientas MCP que pueden ser utilizadas por agentes de IA.</li>\n\n\n\n<li>El <a href=\"https://make.wordpress.org/ai/2025/07/17/php-ai-api/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">cliente PHP AI</a> permite que WordPress se conecte a LLMS para la creación de contenido impulsado por IA.</li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Sólo para ti: un haiku de la beta 1</h2>\n\n\n\n<pre class=\"wp-block-verse\">Sale la luna beta,<br>En su resplandor, depuramos sueños—<br>A la vista, estrellas estables.</pre>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"https://es.wordpress.org/2025/10/22/wordpress-6-9-beta-1/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"726287\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:62:\"WordPress en Femenino: Cuando las buenas ideas lo cambian todo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"https://es.wordpress.org/2025/10/21/wordpress-en-femenino-cuando-las-buenas-ideas-lo-cambian-todo/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:106:\"https://es.wordpress.org/2025/10/21/wordpress-en-femenino-cuando-las-buenas-ideas-lo-cambian-todo/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 21 Oct 2025 08:26:08 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=726283\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:137:\"WordPress en Femenino llega a Málaga. Inspírate, aprende y conecta con una comunidad increíble. Hagamos entre todos un Internet mejor.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6323:\"\n<p>Supongo que en algún momento de tu vida te habrá pasado algo parecido a esto: Alguien se te acerca y te dice “¿sabes qué? ¡deberías venir!” y tú le miras con una sonrisa de oreja a oreja y piensas “ya veré…” (aunque, en realidad, estás dudando si quedarte en casa a ver una peli).</p>\n\n\n\n<p>Bueno, pues con este evento, este pensamiento no tiene validez porque, unas mujeres de lo más top del sector han preparado <strong>el eventazo del mes: WordPress en Femenino, que se celebrará en La Noria, en la ciudad de Málaga, el sábado 25 de octubre.</strong></p>\n\n\n\n<p>Te lo estás imaginando, ¿verdad?&#8230; Un sábado en Málaga: Sol y buen tiempo, una ciudad maravillosa por descubrir (si aún no lo has hecho) y unas charlas de WordPress de las que recordarás toda la vida.</p>\n\n\n\n<p>¿Y por qué las vas a recordar?</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/malaga/2025/wordpress-en-femenino/tickets/\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">WordPress con acento femenino</h2>\n\n\n\n<p>Porque esta primera jornada de <strong>WordPress en Femenino</strong> (sí, es la primera, otro motivo más para no perdérsela) nace con unos objetivos muy claros: <strong>visibilizar, apoyar y potenciar la participación de las mujeres en el ecosistema WordPress.</strong></p>\n\n\n\n<p>Además, ¿no te has dado cuenta de que el mundo tecnológico sigue teniendo un problemilla de equilibrio?: Muchas más líneas de código escritas por hombres que por mujeres.&nbsp;</p>\n\n\n\n<p>Pero, por suerte, eso está cambiando.</p>\n\n\n\n<p>Y es que gracias a eventos como este, que <strong>tendrá lugar en La Noria, en Málaga, el 25 de octubre</strong>, estas ideas tan necesarias son las que lo van a cambiar todo, pues con ellas se pretende <strong>animar a más mujeres a formar parte activa de la comunidad, no sólo como asistentes, sino también como ponentes, organizadoras y líderes</strong>.&nbsp;</p>\n\n\n\n<p><strong>Pero no te confundas, que esto no es solo para mujeres</strong>, que si eres de los que se levanta por las mañanas y te tienes que afeitar la cara porque su tacto parece el de un papel de lija, esto también es para ti… Y es que, aunque el foco del evento esté en visibilizar a las mujeres, <strong>este evento es para toda la comunidad.</strong></p>\n\n\n\n<p>Me reitero: TODA la comunidad.</p>\n\n\n\n<p>Y aquí va mi frase épica (de esas que a veces se me ocurren y que nunca deberías olvidar): <em>“Sólo si hacemos las cosas juntos y entre todos, podremos construir un entorno más equitativo, inclusivo y representativo.”</em></p>\n\n\n\n<p><a href=\"https://events.wordpress.org/malaga/2025/wordpress-en-femenino/tickets/\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cuatro ponencias, cuatro historias y cuatro mujeres que inspiran.</h2>\n\n\n\n<p>Esa es la cifra mágica del día: Cuatro.</p>\n\n\n\n<p>Cuatro mujeres que, con sus ponencias, van a <strong>dar voz, visibilidad y foco a todas esas mujeres que hacen magia detrás de las pantallas</strong>: Mujeres que crean, que programan, que diseñan, que enseñan y que demuestran que la tecnología también tiene rostro, corazón y mirada femenina.</p>\n\n\n\n<p>Cuatro referentes indiscutibles del sector que, <strong>el 25 de octubre en La Noria, en Málaga</strong>, te van a dejar sin excusas y de las que vas a aprender muchísimo.</p>\n\n\n\n<p>Y como ya sé que llevas tiempo leyéndome y sabes que soy una persona razonable…</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Por qué deberías ir (sin pensar en el “ya veré”)?</h2>\n\n\n\n<p>Primero, porque será<strong> una oportunidad increíble para conectar con la comunidad WordPress</strong>, compartiendo tu pasión por la tecnología, el diseño, el emprendimiento…</p>\n\n\n\n<p>Segundo, porque <strong>vas a aprender muchísimo con estas ponencias y no sólo sobre WordPress, sino también sobre liderazgo, comunicación y desarrollo personal y profesional.</strong></p>\n\n\n\n<p>Tercero, porque <strong>los eventos de la comunidad WordPress tienen algo que no vas a encontrar en otros eventos</strong>: ese ambiente cálido, colaborativo y sin postureo en el que puedes charlar de tú a tú con ese ponente al que admiras o intercambiar ideas y opiniones con la persona que se sentará a tu lado, a la cual no conoces de nada pero que acabas de descubrir que tiene ideas muy similares (o diferentes) a las tuyas.</p>\n\n\n\n<p>Y es que en un evento WordPress nadie va de resabidillo de la tecnología a quien debes hacer una genuflexión a su paso. Aquí toda la gente construye, comparte y aprende junta.</p>\n\n\n\n<p>Y cuarto (ya te dije que el cuatro en la cifra mágica del día), porque va a ser en Málaga y ya sabes lo que eso significa: buen clima, buena gente, buena comida…&nbsp;</p>\n\n\n\n<p>¿De verdad sigues pensando en lo que vas a hacer ese fin de semana?</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/malaga/2025/wordpress-en-femenino/tickets/\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Venga… ¡Apúntate que ya estás tardando!</h2>\n\n\n\n<p>Ya te lo he dicho muchas veces, pero te lo repito (que soy muy “pesao”): <strong>El sábado 25 de octubre tienes una cita ineludible, en La Noria (Málaga), para acudir al primer WordPress en Femenino</strong> que promete ser la bomba.</p>\n\n\n\n<p>Y no me importa si desarrollas, diseñas, creas contenido, emprendes o simplemente eres alguien con curiosidad por el mundo digital… Este es un evento hecho para ti, así que ven, escucha, pregunta, participa, y pásatelo genial aprendiendo y conectando con una gran comunidad de mujeres (y hombres) que te van a hacer crecer como persona y como profesional.</p>\n\n\n\n<p>Además, ¿sabes qué?&#8230; Seguro que sales de allí sabiendo que siempre tendrás buena compañía junto a esa <strong>comunidad enorme de mujeres que están empujando juntas para que la tecnología sea más igualitaria y más creativa.</strong></p>\n\n\n\n<p>Así que, hazme caso:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Haz clic.</li>\n\n\n\n<li><a href=\"https://events.wordpress.org/malaga/2025/wordpress-en-femenino/tickets/\">Compra tu entrada</a> (que están a un precio irrisorio).</li>\n\n\n\n<li>Y prepárate para vivir la primera edición (de muchas) de <strong>WordPress en Femenino, el 25 de octubre en La Noria, Málaga.</strong></li>\n</ul>\n\n\n\n<p>¡Nos vemos allí!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://es.wordpress.org/2025/10/21/wordpress-en-femenino-cuando-las-buenas-ideas-lo-cambian-todo/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"726283\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:52:\"WordPress Diversity Day 2025: ¡Volvemos a la carga!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"https://es.wordpress.org/2025/10/10/wordpress-diversity-day-2025-volvemos-a-la-carga/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"https://es.wordpress.org/2025/10/10/wordpress-diversity-day-2025-volvemos-a-la-carga/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Oct 2025 15:28:42 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=719701\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:138:\"Sábado 18 octubre en Valencia: WordPress, diversidad y buen rollo. Si faltas otra vez, no te lo perdonarás, así que compra tu entrada..\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5633:\"\n<p>Si ya estuviste el año pasado, sabes perfectamente de qué va esto y, si te la perdiste, pues aquí vuelve <strong>una nueva edición de este evento WordPress tan especial</strong> al que esta vez, sí o sí, tienes que acudir (que no me entere yo de que fallas).</p>\n\n\n\n<p>Este año, también se celebrará <strong>en Valencia</strong> <strong>en la Sala Ateneo Marítimo de WAYCO, el sábado 18 de octubre</strong>, para pasarlo en grande. </p>\n\n\n\n<p>Además, un pajarito me ha dicho que el lugar es espectacular, moderno y accesible, así que prepara tu mejor cara, muestra tu sonrisa más arrebatadora y deja que el fotógrafo te tome unas instantáneas de lujo mientras posas delante de tu ordenador, tecleando como un auténtico “PRO” de WordPress.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2025/diversityday/entradas/\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿El Diversity “qué”…? (para los despistados)</h2>\n\n\n\n<p>Te lo explico por si aún no lo sabes…<strong> El WordPress Diversity Day es ese evento que te recuerda que la tecnología no vive en una burbuja de uniformidad</strong> donde todos pensamos igual, hablamos igual y vestimos igual (como si estuviéramos dentro del libro 1984, la distópica novela de George Orwell).</p>\n\n\n\n<p><em>“Este evento quiere reflejar todas las voces y crear una comunidad donde cada persona, con su historia, identidad y vivencia, tenga un lugar y una voz.”</em>&nbsp;</p>\n\n\n\n<p>Esta frase que acabas de leer no es mía y está sacada de la propia web del evento… Créeme si te digo que es muy buena y expresa perfectamente lo que significa WordPress Diversity Day 2025.&nbsp;</p>\n\n\n\n<p><strong>Diversidad cultural y lingüística, diversidad funcional y accesibilidad, de trayectoria profesional, socioeconómica, generacional, neurodivergente, y sexual y de género…</strong> Aquí vas a encontrar todo esto y mucho más. Va a ser esa gran fiesta de WordPress en la que (permíteme el chiste encorsetado mientras me coloco bien el nudo de la corbata): “Nadie se va a quedar fuera por no ir vestido acorde al código”.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2025/diversityday/entradas/\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Por qué debería importarte este evento?&nbsp;</h2>\n\n\n\n<p>¿Qué evento?&#8230; <strong>¿El WordPress Diversity Day 2025 de Valencia? ¿El que se celebrará el 18 de octubre en la Sala Ateneo Marítimo de WAYCO?</strong>&nbsp;</p>\n\n\n\n<p>Pues debería importarte por muchas cosas. Un primer motivo te lo voy a dar en datos fríos, porque <strong>más del 43% de Internet está construido con WordPress</strong>… Y eso son muchísimos millones de sitios web… Flipante, ¿verdad?</p>\n\n\n\n<p>El segundo motivo es que <strong>los organizadores detrás del evento se han pegado un currazo de la leche para traer a siete ponentes alucinantes</strong> que tratarán temas como:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Neurodivergencia</li>\n\n\n\n<li>Accesibilidad instantánea</li>\n\n\n\n<li>WordPress sin fronteras</li>\n\n\n\n<li>Audiencia diversa</li>\n\n\n\n<li>Etc…</li>\n</ul>\n\n\n\n<p>¿Y sabes lo mejor de todo? (y este es el tercer motivo)… Que el evento ocurrirá durante la mañana del sábado 18 de octubre. Eso quiere decir que te quedará libre toda la tarde para irte a comer con <strong>la gente del Diversity Day y fortalecer la comunidad WordPress</strong>… Y si eres de los que va por su cuenta, podrás hacer turismo y disfrutar de esa fantástica ciudad que es Valencia.</p>\n\n\n\n<p>El cuarto motivo es el más sencillo de todos… Estoy seguro de que este no es el primero de mis artículos que lees, así que ya tendrás muy claro que soy un tipo encantador, que soy de los que sabe de lo que habla y que, sólo por eso, si digo que debes ir, irás sin siquiera dudarlo… ¿Verdad?</p>\n\n\n\n<p>No… Ahora en serio… <strong>Realmente el WordPress Diversity Day 2025 va a ser un evento muy especial</strong>, igual que lo fue la edición del año pasado. Además, su formato corto, de sólo una mañana de duración, lo hace perfecto para planear esa escapada de fin de semana en la que disfrutar a tope tanto de WordPress como de las maravillas que te ofrece la ciudad de Valencia.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2025/diversityday/entradas/\">Comprar entrada</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Y un día llegará en el que…</h2>\n\n\n\n<p>Cojas tu móvil, tu Tablet, tu ordenador (o unas gafas de realidad aumentada) y visites la página que te ha recomendado un amigo o entres a un sitio web gubernamental en el que debes hacer un papeleo burocrático y…</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Será accesible por defecto.</li>\n\n\n\n<li>Será intuitivo y sencillo de manejar.</li>\n\n\n\n<li>Estará en tu propio idioma.</li>\n\n\n\n<li>Tendrá interfaces claras.</li>\n\n\n\n<li>Etc…</li>\n</ul>\n\n\n\n<p>¿Suena utópico?&#8230; Puede ser. Pero <strong>eventos como el WordPress Diversity Day 2025 son el combustible que hará que todo eso se convierta en realidad</strong> en un futuro cercano.</p>\n\n\n\n<p>Así que ya lo sabes (y si no, te lo vuelvo a recordar)… Reserva en tu calendario la mañana del <strong>sábado 18 de octubre</strong> y hazte un viajecito hasta <strong>Valencia</strong> porque, <strong>en la Sala Ateneo Marítimo de WAYCO</strong>, te esperan unos auténticos figuras de WordPress con los que vas a aprender mucho, vas a hacer Comunidad y, sobre todo, vas a pasártelo genial.</p>\n\n\n\n<p>¡Nos vemos!</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/valencia/2025/diversityday/entradas/\">Comprar entrada</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:90:\"https://es.wordpress.org/2025/10/10/wordpress-diversity-day-2025-volvemos-a-la-carga/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"719701\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:82:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress 6.8.3 – Actualización de seguridad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://es.wordpress.org/2025/09/30/wordpress-6-8-3-actualizacion-de-seguridad/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"https://es.wordpress.org/2025/09/30/wordpress-6-8-3-actualizacion-de-seguridad/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Sep 2025 21:10:11 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:4:{i:0;a:5:{s:4:\"data\";s:15:\"Actualizaciones\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:9:\"Seguridad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:3:\"6.8\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:5:\"6.8.3\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=718372\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:413:\"¡Ya está disponible WordPress 6.8.3! Esta es una actualización de seguridad que incluye dos correcciones. Debido a que se trata de una actualización de seguridad se recomienda que actualices tus sitios de inmediato . Puedes descargar WordPress 6.8.3 desde WordPress.org o visitar tu escritorio de WordPress, hacer clic en «Actualizaciones» y luego en «Actualizar ahora». Si tienes sitios con [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Fernando Tellado\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5083:\"\n<p><strong>¡Ya está disponible WordPress 6.8.3!</strong></p>\n\n\n\n<p>Esta es una actualización de seguridad que incluye dos correcciones.</p>\n\n\n\n<p>Debido a que se trata de una actualización de seguridad <strong>se recomienda que actualices tus sitios de inmediato</strong> .</p>\n\n\n\n<p>Puedes <a href=\"https://es.wordpress.org/latest-es_ES.zip\" rel=\"nofollow\">descargar WordPress 6.8.3 desde WordPress.org</a> o visitar tu escritorio de WordPress, hacer clic en «Actualizaciones» y luego en «Actualizar ahora». Si tienes sitios con las actualizaciones automáticas en segundo plano activas el proceso de actualización comenzará automáticamente.</p>\n\n\n\n<p>La próxima versión mayor será <a href=\"https://make.wordpress.org/core/6-9/\">la 6.9</a> , que está prevista para el 2 de diciembre de 2025.<br>Para obtener más información sobre WordPress 6.8.3, visita la <a href=\"https://wordpress.org/documentation/wordpress-version/version-6-8-3/\">página de versiones en el sitio de HelpHub</a> .</p>\n\n\n\n<h2 class=\"wp-block-heading\">Actualizaciones de seguridad incluidas en esta versión</h2>\n\n\n\n<p>El equipo de seguridad desea agradecer a las siguientes personas por&nbsp;<a href=\"https://hackerone.com/wordpress?type=team\">informar de manera responsable las vulnerabilidades</a>&nbsp;y permitir que se solucionen en esta versión:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Un problema de exposición de datos que permitía a usuarios identificados acceder a contenido restringido. Informado de manera independiente por <a href=\"https://hackerone.com/mnelson4\">Mike Nelson</a> , <a href=\"https://hackerone.com/hurayraiit\">Abu Hurayra</a> , <a href=\"https://profiles.wordpress.org/timothyblynjacobs/\">Timothy Jacobs</a> y <a href=\"https://profiles.wordpress.org/peterwilsoncc/\">Peter Wilson</a> .</li>\n\n\n\n<li>Una vulnerabilidad de secuencias de comandos entre sitios (XSS) que requería un perfil de usuario identificado y que afectaba a los menús de navegación. Informó <a href=\"https://x.com/Savphill\">Phill Savage</a> .</li>\n</ul>\n\n\n\n<p>También se han puesto estas correcciones a disposición de todas las ramas que pueden recibir correcciones de seguridad (ahora mismo hasta la versión 4.7). Recuerda que <strong>solo se da soporte activo a la versión más reciente de WordPress</strong>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Gracias a estos contribuidores a WordPress</h2>\n\n\n\n<p>Este lanzamiento lo dirigió <a href=\"https://profiles.wordpress.org/johnbillion/\">John Blackbourn</a> .</p>\n\n\n\n<p>Además de los investigadores de seguridad y los miembros del equipo de la versión mencionados anteriormente, WordPress 6.8.3 no habría sido posible sin las contribuciones de las siguientes personas:</p>\n\n\n\n<p><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/hurayraiit\">Abu Hurayra</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/zieladam\">Adam Zieliński</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/xknown\">Alex Concha</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/andraganescu%20\">Andrei Draganescu</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/davidbaumwald/\">David Baumwald</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/ehtis\">Ehtisham Siddiqui</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/iandunn\">Ian Dunn</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/whyisjake\">Jake Spurlock</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/joehoyle\">Joe Hoyle</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/johnbillion\">John Blackbourn</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/mnelson4\">Michael Nelson</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/phillsav\">Phill</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/noisysocks\">Robert Anderson</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/rmccue\">Ryan McCue</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/coffee2code/\">Scott Reilly</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/timothyblynjacobs\">Timothy Jacobs</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/vortfu\">vortfu</a>&nbsp;,&nbsp;<a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cómo contribuir</h2>\n\n\n\n<p>Para participar en el desarrollo del núcleo de WordPress, visita el Trac, <a href=\"https://core.trac.wordpress.org/report/6\">crea una solicitud</a> y únete a la conversación en el canal <a href=\"https://app.slack.com/client/T024MFP4J/C02RQBWTW\">#core</a> de Slack. ¿Necesitas ayuda? Consulta el <a href=\"https://make.wordpress.org/core/handbook/tutorials/faq-for-new-contributors/\">manual del colaborador del núcleo</a> .</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"https://es.wordpress.org/2025/09/30/wordpress-6-8-3-actualizacion-de-seguridad/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"718372\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:58:\"Código Costa Noja 2025, la belleza de las cosas sencillas\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:93:\"https://es.wordpress.org/2025/09/30/codigo-costa-noja-2025-la-belleza-de-las-cosas-sencillas/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:101:\"https://es.wordpress.org/2025/09/30/codigo-costa-noja-2025-la-belleza-de-las-cosas-sencillas/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Sep 2025 06:17:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=718231\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:143:\"Código Costa Noja 2025 es WordPress, playa y magia. Un evento sencillo para disfrutar el 11 de octubre en Noja. ¡Compártelo y ven a vivirlo!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8900:\"\n<p>Lo primero es lo primero…</p>\n\n\n\n<p>¿Qué es <strong>Código Costa Noja 2025</strong>?&#8230; Pues es <strong>un evento de WordPress</strong> que tendrá lugar la mañana del <strong>sábado 11 de octubre en el Centro de Ocio Playa Dorada de Noja, en Cantabria</strong>.</p>\n\n\n\n<p>Y ya sé que una semana antes es la WordCamp Galicia 2025, pero este… ¡No te lo puedes perder!</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/noja/2025/codigocosta/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<p>Y ahora que lo he dicho, no sé si te ha pasado esto alguna vez: Entras en un importantísimo museo lleno de obras de arte, como el Prado o el Louvre y sales de allí alucinando y flipando, pero con la sensación de que te has perdido muchísimas cosas buenas porque no había tiempo para verlo todo…</p>\n\n\n\n<p>Unos días después entras en un museo más pequeño, como el Museo de Bellas Artes de Bilbao o el Artium, y te pasa exactamente lo mismo: Aunque su superficie de exposición sea menor, también te quedas con obras que no puedes disfrutar del todo por falta de tiempo… Y por último…</p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Guau!… Lo último…</h2>\n\n\n\n<p>Un buen día entras en una pequeña galería de arte. Un espacio que abarcas con la mirada y en el que sólo hay expuestas cinco o seis obras. Un lugar en el que el aire se respira de un modo diferente y en el que te sientes con todo el tiempo del mundo para disfrutar de cada milímetro de las piezas artísticas.</p>\n\n\n\n<p>Y cuando sales de allí,<strong> te invade esa sensación de plenitud, como que lo has abarcado todo y no te has dejado nada en el tintero</strong> porque, por una vez, el tiempo no ha jugado en tu contra.</p>\n\n\n\n<p>Pues exactamente <strong>esto es Código Costa Noja 2025</strong>: un evento pequeño e íntimo, de sólo una mañana de duración, del que saldrás pensando que es lo mejor que podías haber hecho durante el fin de semana, <strong>porque has conseguido exprimir cada segundo de tu vida, aprendiendo y disfrutando por completo de tres ponencias</strong> (perfectamente escogidas) y, además, pudiendo hablar de tú a tú con los artistas que las exponen.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/noja/2025/codigocosta/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">La belleza de las cosas sencillas</h2>\n\n\n\n<p>Con estas mismas palabras abro este artículo. Este evento de WordPress, <strong>Código Costa Noja 2025, tiene un encanto particular que no vas a encontrar en otros eventos</strong> como una WordCamp de nivel internacional o nacional… Pero esto no quiere decir nada malo de esos otros eventos, porque son geniales, alucinantes y únicos… Pero yo, al menos, siempre me quedo con la sensación de que podría haberlos exprimido más, pero no tuve tiempo suficiente para hacerlo.</p>\n\n\n\n<p>De ahí que insista en la belleza de las cosas sencillas y en el encanto de esas cosas pequeñas que nacen para convertirse en algo más grande.</p>\n\n\n\n<p>Porque sí, <strong>Código Costa Noja 2025</strong>, que <strong>se celebrará el sábado 11 de octubre en el Centro de Ocio Playa Dorada de Noja, en Cantabria</strong>, nace este año como algo pequeño, pero con la ambición de convertirse en el referente WordPress de la zona.&nbsp;</p>\n\n\n\n<p>Es un evento pionero que reunirá a los mejores profesionales, a empresas del sector digital y, lo mejor de todo, a estudiantes, esa futura generación de genios creativos que nos seguirá para mantener nuestro CMS favorito como líder del sector.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/noja/2025/codigocosta/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Cuando unos pocos hacen mucho</h2>\n\n\n\n<p>Este evento <strong>está dirigido por dos enamorados de la tecnología, luchando por establecer de forma definitiva una comunidad WordPress en la zona</strong> ya que, con anterioridad, se organizaron MeetUp en Santander y Torrelavega, pero estas no terminaron de cuajar del todo.</p>\n\n\n\n<p>Solo por esto… ¿No crees que, como esa gran comunidad que somos, no deberíamos dar ese gran apoyo a este nuevo proyecto Código Costa Noja 2025?</p>\n\n\n\n<p>Además, <strong>en su gran inauguración han invitado a tres ponentes cracks del sector</strong> que, con que sólo hayas rascado un poco en la superficie de WordPress, seguro que los conocerás, pues su reputación es de sobra conocida y, como no podía ser de otro modo, haciendo gala de dicha reputación, nos van a regalar unas ponencias de lo más memorables.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/noja/2025/codigocosta/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Guau!… Las ponencias…</h2>\n\n\n\n<p>El dúo de organizadores de <strong>Código Costa Noja 2025</strong> han seleccionado tres ponencias espectaculares para la mañana del <strong>sábado 11 de octubre en el Centro de Ocio Playa Dorada de Noja, Cantabria</strong>.</p>\n\n\n\n<p>En una charla personal que pude mantener con este dúo (sí… lo que ya he dicho antes: el encanto y la intimidad de las cosas pequeñas te permiten hacer este tipo de cosas y entablar este tipo de relaciones), me confesaron que:</p>\n\n\n\n<p>“<em>La intención es dar en todo momento unas ponencias de calidad que puedan atraer tanto a profesionales como a estudiantes y, como pretensión última, crear una comunidad estable en la zona para reunirnos con cierta periodicidad. Por eso queremos presentar contenidos que sean prácticos, para las personas que asistan. Por una parte, tenemos interés en que vengan estudiantes y que conozcan tanto el funcionamiento de la comunidad WordPress como el mundo real del trabajo en la empresa. Al mismo tiempo, también nos gustaría que se acercaran personas que trabajen en el sector, que se beneficien de las propias ponencias y que se establezca una red de contactos.</em>”</p>\n\n\n\n<p>¡Y vaya si lo van a conseguir!&#8230; Para que veas que este dúo de genios tiene los objetivos muy claros, aquí te dejo sólo el título de las ponencias para que valores si merece la pena acudir al evento (yo lo tengo muy claro, son muy buenas).</p>\n\n\n\n<p>&nbsp;&nbsp;&nbsp;&nbsp;• <strong>CSS: todo lo que no sabías que necesitabas</strong>.</p>\n\n\n\n<p>&nbsp;&nbsp;&nbsp;&nbsp;• <strong>Cómo colaborar con un desarrollador</strong> para llevar tu diseño a medida a WordPress.</p>\n\n\n\n<p>&nbsp;&nbsp;&nbsp;&nbsp;• <strong>Cómo colaborar con una diseñadora</strong> para transformar un diseño a medida en un sitio WordPress.</p>\n\n\n\n<p>¿Lo ves?&#8230; Unas <strong>ponencias necesarias y prácticas para tu día a día</strong> si eres desarrollador/a o diseñador/a WordPress… Unas ponencias <strong>realmente interesantes</strong> si eres una empresa interesada en tener un sitio web y necesitas del servicio de estos profesionales… Unas ponencias <strong>indispensables e irrepetibles</strong> si eres un estudiante o una persona que se quiere iniciar en el mundo de las tecnologías web.</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/noja/2025/codigocosta/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">¡Un triple acierto!</h2>\n\n\n\n<p>¿Se lo ha trabajado o no este dúo de cracks?&#8230; ¿Acaso <strong>no crees que se merecen todo nuestro apoyo</strong> por este currazo que se han pegado para poder levantar una nueva comunidad WordPress en Cantabria?</p>\n\n\n\n<p>Yo lo tengo muy claro… ¿Y tú?&#8230;</p>\n\n\n\n<p>Pues venga… ¿A qué estás esperando para <strong>compartirlo en tus redes para dar la mayor visibilidad y ayudar a establecer una nueva comunidad WordPress en Cantabria</strong>?</p>\n\n\n\n<p>Y lo más importante, no te pierdas <strong>Código Costa Noja 2025</strong>, compra tu entrada y alucina con la profesionalidad de los organizadores, el conocimiento de los ponentes y disfruta de la intimidad de <strong>un evento pequeño que nace con la intención de convertirse en uno de los grandes de la zona</strong>.</p>\n\n\n\n<p>Y por cierto, te lo recuerdo por última vez (que ya sé que a veces no tienes la cabeza en su sitio): Haz un hueco en tu agenda y ocupa<strong> la mañana del sábado 11 de octubre para acudir al Centro de Ocio Playa Dorada de Noja, en Cantabria</strong>.</p>\n\n\n\n<p>¡No te arrepentirás!&#8230; Además, aún te sobrará un día y medio del fin de semana para disfrutar de la gastronomía, la cultura y el paisaje de la zona y saber, de una vez por todas, por qué a esa Comunidad Autónoma se la conoce como “Cantabria Infinita”.</p>\n\n\n\n<p>¡Nos vemos allí!</p>\n\n\n\n<p><a href=\"https://events.wordpress.org/noja/2025/codigocosta/entradas/\" target=\"_blank\" rel=\"noreferrer noopener\">Comprar entradas</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:98:\"https://es.wordpress.org/2025/09/30/codigo-costa-noja-2025-la-belleza-de-las-cosas-sencillas/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"718231\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordCamp Galicia 2025: La unión hace la fuerza\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://es.wordpress.org/2025/09/22/wordcamp-galicia-2025-la-union-hace-la-fuerza/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:90:\"https://es.wordpress.org/2025/09/22/wordcamp-galicia-2025-la-union-hace-la-fuerza/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 Sep 2025 07:43:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=718227\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:164:\"Cuando las MeetUp gallegas se unen no sale una empanada… Sale el eventazo WordPress que estabas esperando… ¡Ven a #WCGalicia2025 porque este año será brutal!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"lualvarimp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:9889:\"\n<p>Tras el veranito y las vacaciones, <strong>volvemos de nuevo a la carga con las WordCamp</strong>, el lugar favorito donde los fans de WordPress se arrejuntan para hablar de sus cositas&#8230;</p>\n\n\n\n<p>Y como no podía ser de otro modo, inaugurando otro año más esta serie de eventos tan arraigados en nuestro país, abre la tanda: ¡WordCamp Pontev…!!!</p>\n\n\n\n<p>No, espera… ¿No es la de siempre?&#8230; ¿Qué pasa aquí?&#8230;&nbsp;</p>\n\n\n\n<p>Pues resulta que este año, <strong>dos de las WordCamp más exitosas de la pasada edición han decidido sumar fuerzas</strong> y conocimientos porque, ¿para qué andar por lados distintos del camino, si juntarse en el centro es más divertido y te permite entablar mejores conversaciones?</p>\n\n\n\n<p>Así que dicho y hecho, las “antiguas” WordCamp Pontevedra y WordCamp Vigo ahora se unen en <strong>WordCamp Galicia 2025</strong> y en esta edición, que se celebrará <strong>los días 3 al 5 de octubre en la Facultad de Comunicación, en el Campus de Pontevedra de la Universidad de Vigo</strong>, prometen venir con algo muy grande.</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<p>¡Y vaya si va a ser grande!&#8230; Porque algo tan grande sólo puede pasar cuando l<strong>os profesionales de los siete grupos de MeetUp de la comunidad autónoma se ponen de acuerdo</strong> (A Coruña, Ferrolterra, Lugo, Ourense, Pontevedra, Vigo y Santiago) y unen fuerzas&#8230; ¿Cómo no va a ser un evento irrepetible y alucinante?</p>\n\n\n\n<p>Es como si juntasen en una misma película a tus superhéroes favoritos, creando el blockbuster perfecto, aunque aquí, en vez de gente hipermusculada dentro de trajes chillones, van a acudir los mejores ponentes con sus superpoderosas mentes, dispuestos a hacerte explotar el cerebro con todo lo que te van a enseñar (y si además viniesen montados a lomos de pulpos gigantes mutantes, ya sería la repanocha, pero eso sólo ocurre en lo cómics).</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<p>¿Y qué vamos a encontrar en esta WordCamp Galicia?&#8230; Imagínate <strong>tres días llenos de charlas y de talleres imprescindibles</strong> para estar al tanto de lo más importante que se cuece en el panorama WordPressero y<strong> todo girando alrededor de las páginas web, la enseñanza y el emprendimiento</strong>. Además, las actividades programadas estarán relacionadas con <strong>WordPress y el aprendizaje</strong>… ¿Te lo piensas perder?</p>\n\n\n\n<h2 class=\"wp-block-heading\">Lo mejor de lo mejor</h2>\n\n\n\n<p>El <strong>viernes, 3 de octubre</strong>, habrá dos actividades muy importantes que, aunque independientes de la WordCamp Galicia 2025, son unos clásicos dentro de este evento (y además, sólo este día, ¡son gratis!):&nbsp;</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>El taller teórico/práctico de iniciación de WordPress</strong>: Una genial actividad que, de la mano de un gran profesional, sirve para acercar este CMS a toda esa gente que quiere tener una web y no se atreve, o que piensa que es complicado, o lo que sea… </li>\n\n\n\n<li><strong>El do_action hackaton</strong>: Una actividad en la que, en unas pocas horas, tanto los recién llegados como los más curtidos, planifican y crean el sitio web de una organización sin ánimo de lucro de ámbito local.</li>\n</ul>\n\n\n\n<p>¿Y qué se consigue con estas dos actividades? (que me repito, sólo son gratuitas el día 3 de octubre): <strong>Dar visibilidad a WordPress</strong>, ampliar la familia de usuarios del CMS y, lo más importante, que los nuevos usuarios vean que existe <strong>una gran comunidad de gente</strong> que está ahí para ayudarles y respaldarles.</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">El día del salseo</h2>\n\n\n\n<p>El <strong>sábado, 4 de octubre</strong> comienza realmente lo bueno … ¿Y qué es lo bueno?</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Las ponencias (en diferentes formatos de duración)</li>\n\n\n\n<li>Los talleres</li>\n\n\n\n<li>Las auditorías</li>\n\n\n\n<li>Las consultorías</li>\n\n\n\n<li>Los debates abiertos</li>\n</ul>\n\n\n\n<p>Y t<strong>odo será muy dinámico, con ideas innovadoras e historias que te inspirarán</strong> pero, sobre todo, será <strong>una WordCamp muy práctica</strong> para que al final, cuando llegues a tu casa tras un impresionante fin de semana, puedas usar todo lo aprendido en tus proyectos.</p>\n\n\n\n<p>Se te está haciendo la boca agua, ¿verdad?&#8230; Pues <a href=\"https://galicia.wordcamp.org/2025/es/conferencias/\">pásate por este enlace de la WordCamp</a> en el que te explican mejor por qué no te debes perder este comienzo de temporada.</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<p>Y ya de paso, aprovecho para recordarte que la <strong>WordCamp Galicia 2025</strong> se celebrará los días <strong>3 al 5 de octubre en la Facultad de Comunicación, en el Campus de Pontevedra de la Universidad de Vigo</strong> (por si te habías olvidado).</p>\n\n\n\n<p>La verdad es que las ponencias van a ser increíbles. Te vas a encontrar con charlas como estas:&nbsp;</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Mejorar el rendimiento de WordPress</strong> sin depender de plugins.</li>\n\n\n\n<li><strong>Crear tu propio GPT</strong> sin ser desarrollador y usarlo como herramienta práctica.</li>\n\n\n\n<li><strong>Autenticación</strong> y acceso a datos.</li>\n\n\n\n<li><strong>UX</strong> para impulsar las ventas.</li>\n\n\n\n<li><strong>Mejorar las ventas</strong> de tus cursos o academia online.</li>\n\n\n\n<li><strong>WordPress Campus Connect</strong>.</li>\n\n\n\n<li>Y muchas más que te van a dejar flipado…</li>\n</ul>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Es que yo no soy de ponencias</h2>\n\n\n\n<p>¡Pues no pasa nada!&#8230; ¡Si a este evento van a acudir 250 personas!…&nbsp;</p>\n\n\n\n<p>¿Sabes qué quiero decir con eso?&#8230; Que las ponencias son algo alucinante pero, ¿y poder <strong>hablar con los 250 asistentes al evento</strong>?&#8230; ¡Eso sí que mola!</p>\n\n\n\n<p>Es una de tantas cosas buenas que tienen las WordCamp: Encontrarte con colegas de profesión a los que hace meses que no ves; o conocerlos en persona tras haber estado hablando con ellos durante mucho tiempo a través de videoconferencia; o ver a ese crack que tiene un canal en la web que llevas siguiendo años y al que te diriges con vergüenza y al final resulta que es un tipo de lo más simpático y cercano.</p>\n\n\n\n<p>Todas esas cosas ocurren en una WordCamp, así que ya sabes que <strong>debes guardar un espacio en tu agenda los días 3 al 5 de octubre para ir a WordCamp Galicia 2025, en la Facultad de Comunicación del Campus de Pontevedra de la Universidad de Vigo</strong> (sé que ya lo sabías, pero por si acaso).</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Y la traca final</h2>\n\n\n\n<p>¡Fiesta, fiesta!&#8230; Porque sí… Porque <strong>las WordCamp no son sólo un evento en el que aprender</strong>. También es un lugar en el que <strong>compartir, conocer y disfrutar</strong> en compañía de amigos y desconocidos del mejor CMS del planeta.</p>\n\n\n\n<p>Y, además, si eso no te convence, ¿qué te parece disfrutar durante los descansos de unas delicias de la típica gastronomía gallega? … Ahí te he pillado, ¿verdad? (¡que haya pulpo, que haya pulpo!)</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<p>Porque en esta WordCamp Galicia 2025 lo tienen muy claro: <strong>La comida, el networking y el After Party: ¡A la gallega!</strong></p>\n\n\n\n<p>Prepárate para sumergirte en un pedazo de la auténtica Galicia, con los organizadores y los voluntarios vestidos con las típicas batas de las abuelas gallegas, con un hilo musical en el que se escuchan los acordes típicos de Milladoiro, Luar Na Lubre, Carlos Núñez…</p>\n\n\n\n<p>Y ahora que los acabo de nombrar (y no me refiero a los músicos)… ¡Muchísimas gracias!&#8230; Sin vosotros: patrocinadores, organizadores y voluntarios, este evento no tendría lugar y sé que este año lo haréis mejor todavía, porque sois unos cracks (que eso nunca se os olvide).</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">No te vayas todavía</h2>\n\n\n\n<p>Sí, porque la WordCamp no se acaba con el After Party… <strong>El 5 de octubre, tendrá lugar el Día de la Comunidad</strong>, ese pedacito de tesoro mañanero en el que la gente aporta, con su tiempo y conocimiento, el granito de arena que hace que WordPress siga creciendo año tras año.&nbsp;</p>\n\n\n\n<p>Además, <strong>en esta ocasión viene acompañado de tres charlas cortas</strong> (las cuales no os desvelo, pero os juro que merecerá la pena escucharlas), para terminar convirtiendo el evento global en una experiencia perfecta.</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\n\n\n<p>Y tras finalizar, a las 14:00 horas, será el momento de volver a casa o quedarse para disfrutar de la ciudad y trabajar en remoto (sí, <a href=\"https://galicia.wordcamp.org/2025/donde-alojarse-en-pontevedra/\">en la web te informan de ello</a>).</p>\n\n\n\n<p>Recuerda, son tres días inolvidables que disfrutarás en este comienzo de temporada que inaugura WordCamp Galicia 2025, los días 3 al 5 de octubre en la Facultad de Comunicación del Campus de Pontevedra de la Universidad de Vigo.</p>\n\n\n\n<p>¡No te los pierdas! (porque si lo haces, te arrepentirás)</p>\n\n\n\n<p><a href=\"https://galicia.wordcamp.org/2025/es/entradas/\">Comprar entradas</a></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:87:\"https://es.wordpress.org/2025/09/22/wordcamp-galicia-2025-la-union-hace-la-fuerza/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"718227\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"¡Participa en el Summer Photo Contest y deja que tus fotos hablen del verano!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:112:\"https://es.wordpress.org/2025/07/21/participa-en-el-summer-photo-contest-y-deja-que-tus-fotos-hablen-del-verano/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"https://es.wordpress.org/2025/07/21/participa-en-el-summer-photo-contest-y-deja-que-tus-fotos-hablen-del-verano/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 21 Jul 2025 10:45:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:9:\"Comunidad\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://es.wordpress.org/?p=693933\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:89:\"El verano es para vivirlo… ¡y para fotografiarlo!\n\nEn WordPress sabemos que así es...\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:10:\"Nilo Velez\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:4439:\"\n<p>El verano es para vivirlo… ¡y para fotografiarlo! Desde <strong><a href=\"https://www.meetup.com/es-ES/quedadas-wordpress-en-espanol/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">Quedadas WordPress</a></strong>, el grupo de meetups online de la comunidad de WordPress española, te invitamos a formar parte del <strong>Summer Photo Contest</strong>, un concurso pensado para celebrar el verano y, al mismo tiempo, ayudar a que crezca uno de los proyectos más bonitos del ecosistema WordPress: el <a href=\"https://wordpress.org/photos/\" target=\"_blank\" rel=\"noreferrer noopener nofollow\">WordPress Photo Directory</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es el WordPress Photo Directory?</h2>\n\n\n\n<p>Si aún no lo conoces, el <strong>WordPress Photo Directory</strong> es una colección de fotos libres, gratuitas y colaborativas, 100% hecha por personas como tú. Todas las imágenes están bajo licencia <a href=\"https://creativecommons.org/public-domain/cc0/\" target=\"_blank\" rel=\"noreferrer noopener\">CC0</a>, lo que significa que cualquiera puede usarlas, modificarlas o compartirlas sin pedir permiso, incluso con fines comerciales.</p>\n\n\n\n<p>A diferencia de otras plataformas, aquí no hay algoritmos que te oculten, ni pagos ocultos, ni fórmulas mágicas: si subes una buena foto y cumple las <a href=\"https://wordpress.org/photos/guidelines/\" target=\"_blank\" rel=\"noreferrer noopener\">normas</a>, se publica y queda a disposición del mundo. Así de sencillo. Es una forma de contribuir al proyecto WordPress, aprendiendo fotografía, mostrando tu mirada y regalando tus imágenes a la comunidad.</p>\n\n\n\n<h2 class=\"wp-block-heading\">¿Qué es el Summer Photo Contest?</h2>\n\n\n\n<p>El <strong>Summer Photo Contest</strong> es una iniciativa abierta a todo el mundo que quiera participar. El objetivo es animarte a subir tus mejores fotos veraniegas al WordPress Photo Directory: momentos de descanso, viajes, naturaleza, detalles cotidianos, vida en la ciudad, en la playa o en el campo… ¡todo lo que tenga ese sabor a verano vale!</p>\n\n\n\n<p>Para participar, sólo tienes que subir tus fotos al directorio entre el <strong>1 y el 31 de agosto</strong>, incluyendo la etiqueta <code>#SummerPhotoContest</code> en el formulario. Así de fácil.</p>\n\n\n\n<p>Un jurado formado por fotógrafos y moderadores del propio directorio elegirá las imágenes más destacadas en distintas categorías. Y sí, habrá premios, pensados especialmente para gente a la que le gusta hacer fotos.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Calendario de actividades</h2>\n\n\n\n<p>Además del propio concurso, hemos preparado algunas sesiones en directo para abrir y cerrar el evento, compartir dudas y experiencias, y animarte a participar estés donde estés:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>28 de julio – 12:00 GMT</strong> (14:00 en España): Sesión de apertura (Africa y Asia, en inglés)</li>\n\n\n\n<li><strong>28 de julio – 18:00 GMT</strong> (20:00 en España): Sesión de apertura (España y LATAM, en español)</li>\n\n\n\n<li><strong>28 de julio – 20:00 GMT</strong> (22:00 en España): Sesión de apertura (Estados Unidos y Canadá, en inglés)</li>\n\n\n\n<li><strong>1 de agosto – 00:00 GMT</strong>: ¡Empieza el concurso!</li>\n\n\n\n<li><strong>31 de agosto – 23:59 GMT</strong>: Fin del plazo para subir fotos</li>\n\n\n\n<li><strong>6 de septiembre – 18:00 GMT</strong> (20:00 en España): Sesión de cierre (bilingüe, inglés/español)</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Consigue tu entrada gratuita</h2>\n\n\n\n<p>Todas las actividades se celebran online, y puedes seguirlas desde cualquier lugar del mundo. Para recibir recordatorios, enlaces y novedades del concurso, sólo tienes que <strong>conseguir tu entrada gratuita</strong> en el sitio oficial del evento:</p>\n\n\n\n<p><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f449.png\" alt=\"👉\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> <a href=\"https://events.wordpress.org/quedadas/2025/summerphoto\" target=\"_blank\" rel=\"noreferrer noopener\">https://events.wordpress.org/quedadas/2025/summerphoto</a></p>\n\n\n\n<p>No importa si eres fotógrafo profesional o si sólo haces fotos con el móvil cuando te acuerdas. Lo importante es compartir tu mirada y formar parte de esta gran galería colaborativa que es el WordPress Photo Directory.</p>\n\n\n\n<p>Este verano, súmate al reto y deja que tus fotos hablen por ti. ¡Te esperamos!</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:117:\"https://es.wordpress.org/2025/07/21/participa-en-el-summer-photo-contest-y-deja-que-tus-fotos-hablen-del-verano/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:6:\"693933\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1