\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2025/11/dean-talk/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:402:\"<figure class=\"wp-block-embed alignwide is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n\n\n\n<p>There&#8217;s a new video with Jeff Dean talking at the Stanford AI Club, only 2k views so far, he&#8217;s half of the pair I <a href=\"https://ma.tt/2025/11/friday-links/\">blogged the other day</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 25 Nov 2025 05:05:29 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"Matt: Vogelstein on AI\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150650\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"https://ma.tt/2025/11/vogelstein-on-ai/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:580:\"<p>Fred Vogelstein writes on Crazy Stupid Tech: <a href=\"https://crazystupidtech.com/2025/11/21/boom-bubble-bust-boom-why-should-ai-be-different/\">Boom, bubble, bust, boom. Why should AI be different?</a> &#8220;To us what’s happening is obvious. We both covered the internet bubble 25 years ago. We’ve been writing about – and in Om’s case investing in – technology since then. We can both say unequivocally that the conversations we are having now about the future of AI feel exactly like the conversations we had about the future of the internet in 1999. &#8220;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 23 Nov 2025 07:55:22 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Matt: Friday Links\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150639\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2025/11/friday-links/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1237:\"<ul class=\"wp-block-list\"><div class=\"__iawmlf-post-loop-links\" style=\"display: none;\"></div>\n<li><a href=\"https://sfstandard.com/2025/11/08/stewart-brand-whole-earth-catalog-tugboat/\">Stewart Brand is selling his tugboat houseboat in Sausalito</a>.</li>\n\n\n\n<li><a href=\"https://www.youtube.com/watch?v=niJpDnNtNp4\">Benedict Evans gave a nice presentation on the adoption of AI</a>.</li>\n\n\n\n<li><a href=\"https://www.youtube.com/watch?v=LdORIBH3R88\">Chris Young reviews a $4,200 silver frying pan, comparing it to other metals with some really cool science and infographics</a>.</li>\n\n\n\n<li>From 2018 in the New Yorker, <a href=\"https://www.newyorker.com/magazine/2018/12/10/the-friendship-that-made-google-huge\">The Friendship That Made Google Huge</a>. Great profile of <a href=\"https://research.google/people/jeff/\">Jeff Dean</a> and <a href=\"https://research.google/people/sanjayghemawat/\">Sanjay Ghemawat</a>, makes me wish we did more pair programming at <a href=\"https://automattic.com/\">Automattic</a>. Note the early mentions of machine learning, TPUs, Google Brain, etc.</li>\n\n\n\n<li><a href=\"https://www.youtube.com/watch?v=nDanzN1EUeE\">Trump did a press conference with Zohran Mamdani</a>, the new mayor of New York.</li>\n</ul>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 22 Nov 2025 07:58:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:99:\"Gutenberg Times: State of the Word, WordPress 6.9, Carousel Block and more — Weekend Edition #350\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=42877\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:103:\"https://gutenbergtimes.com/state-of-the-word-wordpress-6-9-carousel-block-and-more-weekend-edition-350/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:23227:\"<p>Hi there,</p>\n\n\n\n<p>Munich got hit with the first snow for this Winter. It started slowly on Friday morning, and by the afternoon the flakes got larger and the white started to cover tree branches, roofs and cars. It might all be gone by tomorrow, though, as the weather forecast shows -7 °C (19.4 °F) with sunshine.<img alt=\"❄\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/2744.png\" style=\"height: 1em;\" /> I am still a Floridian Weather whimp, but I like the snow covering the overcast gray of an Autumn day. I just won&#8217;t go outside if I can help it.</p>\n\n\n\n<p>WordPress 6.9 is almost there. If you need a full run down of the changes in the block editor, I&#8217;ve got you covered with the <a href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/\"><strong>WordPress 6.9 Source of Truth</strong></a>, with screenshot and videos. It clocks in at 5,200+ words. The table of contents as well as the in-post tags will help you navigate it. And I am always here to answer your questions.</p>\n\n\n\n<p>But wait there is more below, </p>\n\n\n\n<p>Have a fabulous weekend, and if you are in the Northern Hemisphere, stay warm. </p>\n\n\n\n<p>Yours, <img alt=\"💕\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f495.png\" style=\"height: 1em;\" /><br /><em>Birgit</em></p>\n\n\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-word-press-release-information\">Developing Gutenberg and WordPress</h2>\n\n\n\n<p>First-time release lead <strong>Jonathan Bossenger</strong> worked on the Gutenberg 22.1. version. In his release post <a href=\"https://make.wordpress.org/core/2025/11/20/whats-new-in-gutenberg-22-1-18-november-2025/\"><strong>What’s new in Gutenberg 22.1? (18 November, 2025)</strong></a> he highlighted two major block updates and a performance improvement for the image block.</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2025/11/20/whats-new-in-gutenberg-22-1-18-november-2025/#new-tabs-block\">New Tabs block</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/20/whats-new-in-gutenberg-22-1-18-november-2025/#html-block-updates\">HTML block updates</a></li>\n\n\n\n<li><a href=\"https://github.com/WordPress/gutenberg/pull/61107\">Image prefetching when expanding images in the editor</a></li>\n</ol>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://wordpress.org/news/2025/11/wordpress-6-9-release-candidate-2/\"><img alt=\"Highlight grid WordPress 6.9\" class=\"wp-image-43066\" height=\"375\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/WordPress-6.9-2025-11-20.png?resize=652%2C375&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<p><strong><a href=\"https://wordpress.org/news/2025/11/wordpress-6-9-release-candidate-2/\">WordPress 6.9 Release Candidate 2</a> </strong>was released this week. December 2 will be here soon enough for the final release. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Joe Dolson</strong> published a list of all the <a href=\"https://make.wordpress.org/core/2025/11/19/accessibility-improvements-in-wordpress-6-9/\"><strong>Accessibility Improvements in WordPress 6.9</strong></a>. More Dev Notes can be <a href=\"https://make.wordpress.org/core/tag/dev-notes-6-9/\">perused on the Make Blog </a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><a href=\"https://x.com/javaid_sarim\"><strong>Sarim Javaid</strong></a>, Digital Ocean posted <a href=\"https://www.cloudways.com/blog/wordpress-6-9/\"><strong>WordPress 6.9: What’s new, release date, features, and why it is important for your site</strong></a> on the Cloudways blog. &#8220;You’ll get faster load times, more streamlined site management, and new developer tools like APIs and automation features. Also, teams will benefit from block-level commenting for better collaboration&#8221; he wrote. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In this week&#8217;s stream, <strong>Jonathan Bossenger</strong> dives into testing WordPress 6.9, specifically <a href=\"https://www.youtube.com/watch?v=Ky3R5ZScwhI\"><strong>focusing on the DataViews functionality</strong></a>. He starts by setting up his live stream, organizing processes, and installing necessary updates. Then, he explores the JavaScript packages involved, particularly the React components that power admin pages. Join him as he fumbles around, copy-pastes examples, and strives to get a basic implementation of DataViews working. If you enjoy watching someone learn through trial and error, give this video a like and subscribe.</p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>JuanMa Garrido</strong> livestreamed about <a href=\"https://www.youtube.com/\"></a><a href=\"https://www.youtube.com/watch?v=8X8ztWQFx9E\"><strong>What&#8217;s new for Devs in Wp 6.9: Interactivity API</strong></a></p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n\n<h3 class=\"wp-block-heading\" id=\"upcoming-wordpress-6-9-events\">Upcoming WordPress 6.9 events </h3>\n\n\n\n<p><strong>Maruti Mohanty</strong> plans a Workshop for <strong>November 27 at 10am UTC</strong> on <a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/312092781/\"><strong>How to Prepare Your WordPress Site for WordPress 6.9?</strong></a> via Learn WordPress meetup.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>Also on <strong>November 27 at 12:00 UTC</strong>, <strong>JuanMa Garrido</strong> and <strong>Jonathan Bossenger</strong> invite you to the <a href=\"https://www.meetup.com/learn-wordpress-online-workshops/events/312110895/\"><strong>Developer Hours: WordPress 6.9 Developer Updates</strong></a>. A second edition, covering updates to Block Bindings and Interactivity API. </p>\n\n\n\n<p>If you missed the first edition, it&#8217;s now available on WordPressTV: <a href=\"https://wordpress.tv/2025/11/18/developer-hours-wordpress-6-9-dataviews-dataform-abilities-api/\"><strong>Developer Hours: WordPress 6.9 DataViews/DataForm &amp; Abilities API</strong></a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>The <strong><a href=\"https://wordpress.org/state-of-the-word/\">State of the Word</a></strong>, <strong>Matt Mullenweg</strong>&#8216;s annual keynote will be live streamed from San Francisco on <strong>December 2 at 8pm UTC.</strong> For the first time, we are celebrating SOTW alongside the official release of WordPress 6.9 on the same day. Expect demos, and even get an early preview of the future beyond for WordPress. All followed by a Q &amp; A with Matt Mullenweg. </p>\n\n\n\n<figure class=\"wp-block-image size-large is-style-no-vertical-margin\"><a href=\"https://wordpress.org/state-of-the-word/\"><img alt=\"\" class=\"wp-image-43111\" height=\"367\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/SotW-banner-_-date-and-time-horizontal.png?resize=652%2C367&#038;ssl=1\" width=\"652\" /></a></figure>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<div class=\"wp-block-group has-light-background-background-color has-background\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<p><img alt=\"🎙\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f399.png\" style=\"height: 1em;\" /> The latest episode is <a href=\"https://gutenbergtimes.com/podcast/gutenberg-changelog-124-gutenberg-22-wordpress-6-9/\">Gutenberg Changelog #124 – Gutenberg 22.0 and WordPress 6.9</a> with <strong>Ellen Bauer</strong>, project lead at Automattic. </p>\n\n\n\n<figure class=\"wp-block-image size-full is-style-no-vertical-margin\"><img alt=\"Gutenberg Changelog 124 with Ellen Bauer and Birgit Pauli-Haack\" class=\"wp-image-42695\" height=\"185\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Screenshot-2025-11-07-at-18.56.39.png?resize=652%2C185&#038;ssl=1\" width=\"652\" /></figure>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-rich is-provider-pocket-casts wp-block-embed-pocket-casts\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div></div></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<h2 class=\"wp-block-heading\" id=\"0-p\">Plugins, Themes, and Tools for #nocode site builders and owners</h2>\n\n\n\n<p> <strong>Justin Tadlock</strong> just dropped his awesome new <a href=\"https://justintadlock.com/archives/2025/11/18/media-data-wordpress-plugin\"><strong>Media Data WordPress Plugin</strong></a>, which is all about pulling in embedded metadata from your uploaded media files—think EXIF data, ID3 tags, camera settings, dimensions, and a lot more. The plugin comes with two blocks: one to hold everything together and others to showcase specific bits of metadata. Plus, it works seamlessly with WordPress 6.9&#8217;s block bindings, so you can easily make custom connections between blocks. It&#8217;s <a href=\"https://github.com/x3p0-dev/x3p0-media-data/releases\">up on GitHub</a> while waiting for approval in the directory.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>Core contributors are getting ready to move the Post Editor into an iframe in WordPress 7.0. This change is all about giving the editing experience a fresh, modern vibe and cutting down on distractions from admin styles and those third-party scripts. <strong>Aki Hamano</strong>, a core committer, laid out the plans last week in a developer note: <a href=\"https://make.wordpress.org/core/2025/11/12/preparing-the-post-editor-for-full-iframe-integration/\"><strong>Preparing the Post Editor for Full iframe Integration</strong></a></p>\n\n\n\n<p><strong>Rae Morey</strong>, The Repository, reports on the various concerns from other contributors in <strong><a href=\"https://www.therepository.email/core-contributors-prepare-to-iframe-the-post-editor-in-7-0-prompting-backward-compatibility-concerns\">Core Contributors Prepare to iframe the Post Editor in 7.0, Prompting Backward-Compatibility Concerns</a>.</strong></p>\n\n\n\n<p>As a follow-up, <strong>Aki Hamano</strong> started a discussion on GitHub on <strong><a href=\"https://github.com/WordPress/gutenberg/issues/73138\">Documentation to help with the migration to Block API version 3 #73138</a>,</strong> with comments from <strong>Ella van Durpe</strong> and <strong>Riad Benguella</strong> with ideas on how to navigate the migration. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p>In her post <a href=\"https://humanmade.com/wordpress-for-enterprise/introducing-accelerate-redefining-experimentation-in-wordpress/\"><strong>Introducing Accelerate: Redefining Experimentation in WordPress</strong></a>, <strong>Gianna Legate</strong>, Head of Content at Human Made, explores how the new Accelerate platform bridges WordPress and modern marketing. The <a href=\"https://humanmade.com/wordpress-for-enterprise/introducing-accelerate-redefining-experimentation-in-wordpress/\">plugin enables</a> marketers to run A/B tests, personalize content by geography, and promote high-performing blocks directly within the editor, shifting WordPress from content-centric publishing toward data-driven customer engagement without requiring external tools or custom development work. The premium plugin is <a href=\"https://www.accelerateplugin.com/pricing/\">free for up to one million</a> monthly page views. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Hans-Gerd Gerhards</strong> announced an update to his plugin <a href=\"https://wordpress.org/plugins/shrinking-logo-sticky-header/\"><strong>Dynamic Header &amp; Navigation for Block Themes</strong></a>, a lightweight WordPress plugin developed specifically as a navigation solution for most Block Themes. &#8220;I am very pleased that my plugin now has more than 100 active installations.&#8221; he <a href=\"https://www.linkedin.com/posts/hans-gerd-gerhards-2b0814170_dynamic-header-navigation-for-block-themes-activity-7397624000190820353-vMzq?utm_source=share&amp;utm_medium=member_desktop&amp;rcm=ACoAAAAkKaoBHI9qqM4OcmXfJb1QeGFMlLI6W4o\">wrote on LinkedIn.</a></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p id=\"johanne-courtright-published-here-the-complete-guide-to-groundworx-carousel-block\"><strong>Johanne Courtright </strong>published her <a href=\"https://groundworx.dev/resources/the-complete-guide-to-groundworx-carousel-block/\"><strong>The Complete Guide to Groundworx Carousel Block</strong></a>. She walks through setting up responsive carousels using Splide.js and Gutenberg, exploring nine professional templates and eight responsive breakpoints for precise control. The guide covers styling via theme.json, creating custom templates using CSS Grid, and building reusable block variations for your team&#8217;s consistent configurations across WordPress projects. The plugin is available in the WordPress repository: <a href=\"https://wordpress.org/plugins/groundworx-carousel/\">Groundworx Carousel</a> v 2.0 was released last week after a complete redesign. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"Goundwork Carousel Block \" class=\"wp-image-43130\" height=\"410\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Screenshot-2025-11-22-at-11.47.24.png?resize=652%2C410&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"2-word-press-6-0-1-and-6-1-scheduled\">Theme Development for Full Site Editing and Blocks</h2>\n\n\n\n<p><strong>Ellen Bauer</strong>&#8216;s talk at WordCamp Kansai is now available on WordPressTV: <a href=\"https://wordpress.tv/2025/11/20/building-a-woocommerce-store-using-block-themes-and-ai-site-building/\" rel=\"noreferrer noopener\" target=\"_blank\"><strong>Building a WooCommerce Store Using Block Themes and AI Site Building</strong></a>. In this hands-on session, you&#8217;ll learn how to use a lightweight starter block theme and AI site-building tools to create a fully editable WooCommerce store design that you can refine directly in the WordPress editor.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p><strong>Rich Tabor</strong> continues his explorations. The second post is all about the <strong><a href=\"https://rich.blog/application-menu/\">Application Menu</a></strong>. &#8220;An application menu would act as a consistent anchor—an always-present spot where you can see the full range of available actions. Not a replacement for other controls, and not a move to strip the interface down.&#8221; he wrote. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n<div class=\"ng-block-b3c1b79fc8119b72 wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #fdfcea; border-radius: 12px;\"><div class=\"ng-block-22619fe37e3f6d1b wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong> <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/\" rel=\"noreferrer noopener\" target=\"_blank\">&#8220;Keeping up with Gutenberg &#8211; Index 2025&#8221;</a> </strong><br />A chronological list of the WordPress Make Blog posts from various teams involved in Gutenberg development: Design, Theme Review Team, Core Editor, Core JS, Core CSS, Test, and Meta team from Jan. 2024 on. Updated by yours truly. </p></div></div></div></div>\n\n<div class=\"ng-block-0d7593c6e2262fd7 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>The previous years are also available: <br /><strong><strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2020/\">2020</a> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2021/\">2021</a></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/keeping-up-with-gutenberg-index-2022/\">2022</a></strong></strong> | <strong><a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2023\">2023</a></strong> | <a href=\"https://make.wordpress.org/core/handbook/references/keeping-up-with-gutenberg-index/gutenberg-index-2024/\"><strong>2024</strong></a></p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<p><strong>Ryan Welcher</strong> livestreamed part 3 of his quest to <a href=\"https://www.youtube.com/watch?v=5-VY_9_DX0E\" rel=\"noreferrer noopener\" target=\"_blank\"><strong>use every Interactivity API feature in one site</strong></a></p>\n\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\n</div>\n\n<div class=\"ng-block-1cab8ce4e70f6749 wp-block-newsletterglue-container ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div class=\"ng-block-vs ng-block-vs-1\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div><div><div class=\"ng-block-hs ng-block-hs-1\" height=\"0\" style=\"width: 0px;\"></div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 20px; padding-bottom: 20px; padding-left: 0px; padding-right: 0px; text-align: none; color: #666666; background-color: #f8f8f8; border-radius: 8px;\"><div class=\"ng-block-78d56a7bf7f308c2 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong><a href=\"https://gutenbergtimes.com/need-a-zip-from-master/\">Need a plugin .zip from Gutenberg&#8217;s master branch?</a></strong><br />Gutenberg Times provides daily build for testing and review.</p></div></div></div></div>\n\n<div class=\"ng-block-3d52df5e5879f60c wp-block-newsletterglue-image ng-block size-full is-resized\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px;\"><a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\"><img alt=\"\" class=\"wp-image-42874 ng-image\" height=\"45\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2024/02/Screenshot-2025-11-15-at-12.06.44.png?resize=196%2C45&#038;ssl=1\" style=\"border-style: none; border-color: transparent;\" width=\"196\" /></a></div></div></div></div>\n\n<div class=\"ng-block-752cc80fb4d5b5db wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 16px; font-family: Helvetica; line-height: 1.6; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p>Now also available via <a href=\"https://playground.wordpress.net/?blueprint-url=https://gutenbergtimes.com/wp-content/uploads/2020/11/playnightly.json\">WordPress Playground</a>. There is no need for a test site locally or on a server. Have you been using it? <a href=\"mailto:pauli@gutenbergtimes.com\">Email me </a>with your experience.</p></div></div></div></div></div><div class=\"ng-block-hs ng-block-hs-2\" height=\"0\" style=\"width: 0px;\"></div></div><div><div class=\"ng-block-vs ng-block-vs-2\" colspan=\"3\" height=\"0\" style=\"height: 0px;\"></div></div></div></div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\"><em>Questions? Suggestions? Ideas? </em><br /><em>Don&#8217;t hesitate to send <a href=\"mailto:pauli@gutenbergtimes.com\">them via email</a> or</em><br /><em> send me a message on WordPress Slack or Twitter @bph</em>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-center has-small-font-size\">For questions to be answered on the <a href=\"http://gutenbergtimes.com/podcast\">Gutenberg Changelog</a>, <br />send them to <a href=\"mailto:changelog@gutenbergtimes.com\">changelog@gutenbergtimes.com</a></p>\n\n\n<div class=\"ng-block-07ee7dd184493e8a wp-block-newsletterglue-separator ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"center\" class=\"ng-block-td\" style=\"padding-top: 20px; padding-bottom: 20px; padding-left: 20px; padding-right: 20px; color: #666666;\"><hr style=\"background-color: transparent; color: transparent; margin: 0; border: 0; border-top: 1px solid #666666; width: 560px; height: 0;\" /></div></div></div></div>\n\n<div class=\"wp-block-newsletterglue-showhide ng-block\" width=\"100%\"><div class=\"ng-block-96a970d7cc97f234 wp-block-newsletterglue-text ng-block\" style=\"color: #666666;\" width=\"100%\"><div><div><div align=\"none\" class=\"ng-block-td\" style=\"font-size: 14px; font-family: Helvetica; line-height: 0.2; font-weight: normal; padding-top: 8px; padding-bottom: 10px; padding-left: 20px; padding-right: 20px; text-align: none; color: #666666;\"><p><strong>Featured Image: </strong></p></div></div></div></div></div>\n\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-wide\" />\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 21 Nov 2025 23:27:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"WordPress Foundation: Recognizing the 2025 WordCamp Asia Kim Parsell Memorial Scholarship Recipients\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"https://wordpressfoundation.org/?p=1206507\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:121:\"https://wordpressfoundation.org/news/2025/recognizing-the-2025-wordcamp-asia-kim-parsell-memorial-scholarship-recipients/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4896:\"<p>In 2015, the WordPress Foundation <a href=\"https://make.wordpress.org/community/2015/01/15/remembering-kim-parsell/\" rel=\"noreferrer noopener\" target=\"_blank\">established an annual memorial scholarship</a> to honor the memory of <a href=\"https://wordpress.org/news/2019/11/people-of-wordpress-kim-parsell/\" rel=\"noreferrer noopener\" target=\"_blank\">Kim Parsell</a>, a beloved and influential contributor to the WordPress community. Kim’s legacy continues to inspire connection, mentorship, and inclusivity across WordPress.</p>\n\n\n\n<p>In 2024, the Kim Parsell Memorial Scholarship <a href=\"https://wordpressfoundation.org/news/2024/kim-parsell-memorial-scholarship-expands-to-wordcamp-asia-and-wordcamp-europe/\" rel=\"noreferrer noopener\" target=\"_blank\">was expanded</a> to include WordCamp Asia and WordCamp Europe, reflecting Kim’s dedication to inclusivity and empowering more contributors to engage in global collaboration.</p>\n\n\n\n<p>This year, the scholarship for WordCamp Asia was awarded to Zeel Thakkar and Pooja Derashri. Two recipients were selected this year because Pooja could not attend WordCamp US in the year she was selected for the scholarship.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Remembering Zeel Thakkar</h2>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://i0.wp.com/wordpressfoundation.org/content/uploads/2025/11/zeel.webp?ssl=1\"><img alt=\"\" class=\"wp-image-1206508\" height=\"512\" src=\"https://i0.wp.com/wordpressfoundation.org/content/uploads/2025/11/zeel.webp?resize=512%2C512&#038;ssl=1\" width=\"512\" /></a></figure>\n\n\n\n<p>Zeel Thakkar (<a href=\"https://profiles.wordpress.org/zeelthakkar/\" rel=\"noreferrer noopener\" target=\"_blank\">@zeelthakkar</a>) of Ahmedabad, India, brought energy, leadership, and kindness to everything she did. A talented freelance WordPress developer at <a href=\"https://www.linkedin.com/company/jpadweb\" rel=\"noreferrer noopener\" target=\"_blank\">Jpadweb</a>, Zeel’s journey began with a simple internship that evolved into a lifelong passion for development and community building.</p>\n\n\n\n<p>Within the <a href=\"https://www.meetup.com/ahmedabad-wp-meetup/\" rel=\"noreferrer noopener\" target=\"_blank\">WordPress Ahmedabad community</a>, Zeel was a tireless organiser, helping lead events including WordCamp Ahmedabad 2023 and Do_Action 2024. Her work united contributors, fostered collaboration through regular meetups, and upheld her belief in empowering women in technology.</p>\n\n\n\n<p>Zeel’s technical contributions were equally significant. She played a key role on the WordPress 6.7 Testing Team, helping ensure the platform’s ongoing stability, and contributed to the Training Team to create educational resources for learners across the world. Her dedication to professional growth and commitment to inclusivity continue to inspire those who had the honor of working alongside her. Zeel’s passing is a tremendous loss, and she will be remembered with deep respect and gratitude.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Celebrating Pooja Derashri</h2>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://i0.wp.com/wordpressfoundation.org/content/uploads/2025/11/pooja.webp?ssl=1\"><img alt=\"\" class=\"wp-image-1206509\" height=\"512\" src=\"https://i0.wp.com/wordpressfoundation.org/content/uploads/2025/11/pooja.webp?resize=512%2C512&#038;ssl=1\" width=\"512\" /></a></figure>\n\n\n\n<p>Pooja Derashri (<a href=\"https://profiles.wordpress.org/webtechpooja/\" rel=\"noreferrer noopener\" target=\"_blank\">@webtechpooja</a>), from Ajmer, India, first started using WordPress in 2013 and went on to co-found WPVibes, a WordPress plugin development agency, with her husband Anand. While she began her career as a developer, she has since expanded her expertise into SEO and Content Marketing, helping shape WordPress projects holistically.</p>\n\n\n\n<p>Pooja’s contribution journey began in 2017 with the <a href=\"https://make.wordpress.org/tv/\" rel=\"noreferrer noopener\" target=\"_blank\">WPTV</a> and <a href=\"https://make.wordpress.org/polyglots/\" rel=\"noreferrer noopener\" target=\"_blank\">Polyglots</a> teams, where she helped localize content and make WordPress more accessible to Hindi speakers. Since 2021, she has served as a Global Translation Editor for Hindi, and in 2019 joined the <a href=\"https://make.wordpress.org/training/\" rel=\"noreferrer noopener\" target=\"_blank\">WordPress Training Team</a>. As a Co-Team Rep, Pooja now helps lead efforts behind <a href=\"http://learn.wordpress.org/\" rel=\"noreferrer noopener\" target=\"_blank\">LearnWP</a>, creating educational materials that support trainers and learners worldwide.</p>\n\n\n\n<p>Both Zeel and Pooja embody the spirit of dedication, generosity, and empowerment that the Kim Parsell Memorial Scholarship was created to celebrate. Their contributions continue to enrich the WordPress community and inspire others to share knowledge and support one another.</p>\n\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 21 Nov 2025 21:07:42 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Harmony Romo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"Gutenberg Times: WordPress 6.9 Source of Truth\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=42536\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:57:\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:104811:\"<p id=\"welcome-to-the-source-of-truth-for-wordpress-6-9\">Welcome to the Source of Truth for WordPress 6.9! </p>\n\n\n\n<p>Before you dive headfirst into all the big and small changes and pick your favorites, make sure to read these preliminary thoughts about this post and how to use it. If you have questions, leave a comment or email me at <a href=\"mailto:pauli@gutenbergtimes.com\">pauli@gutenbergtimes.com</a>. </p>\n\n\n\n<p>Huge Thank You to all collaborators on this post: Anne McCarthy, Sarah Norris, Ella van Durpe, Ben Dwyer, Jonathan Bossenger, Justin Tadlock, Dave Smith and a lot more. It&#8217;s takes a village&#8230; </p>\n\n\n\n<div class=\"wp-block-group has-primary-color has-text-color has-link-color has-small-font-size wp-elements-a8bb9ec1783f5f0c5623981a664fedce is-content-justification-left is-nowrap is-layout-flex wp-container-core-group-is-layout-558b13e7 wp-block-group-is-layout-flex\" style=\"text-decoration: none;\">\n<p>Estimated reading time</p>\n\n\n<div class=\"wp-block-post-time-to-read\">22–32 minutes</div>\n\n\n<p>at </p>\n\n\n<div class=\"wp-block-post-time-to-read\">5,107 words</div></div>\n\n\n\n<p><strong>Table of Contents</strong></p>\n\n\n\n<nav class=\"wp-block-table-of-contents\"><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#changelog\">Changelog</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#important-note-guidelines\">Important note/guidelines</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#overview\">Overview </a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#important-links\">Important links:</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#assets\">Assets </a></li></ul></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#tags\">Tags</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#command-palette-everywhere-all\">Command Palette everywhere [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#block-editor-updates\">Block editor updates</a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#notes-all\">Notes     [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#visual-drag-drop-end-user\">Visual Drag &amp; Drop <img alt=\"🐉\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f409.png\" style=\"height: 1em;\" /> <img alt=\"💧\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f4a7.png\" style=\"height: 1em;\" />  [end user]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#ui-for-managing-allowed-blocks-in-templates-and-patterns-end-user-site-admin\">UI for managing allowed Blocks in Templates and Patterns.     [end user][site admin]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#hide-and-show-blocks-end-user-site-admin\">Hide and Show Blocks  [end user][site admin]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#additional-css-control-moved-end-user-site-admin-theme-author\">Additional CSS control moved   [end user][site admin] [theme author]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#copy-styles-keyboard-shortcut-end-user-site-admin\">Copy Styles keyboard shortcut     [end user][site admin]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#block-style-variations-in-style-book-end-user-site-admin-theme-author\">Block Style Variations in Style Book  [end user][site admin] [theme author]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#the-starter-patterns-modal-for-all-post-types-theme-author-plugin-author-enterprise\">The Starter Patterns modal for all post types. [theme author] [plugin author][enterprise]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#why-iframe-the-post-editor-plugin-author-enterprise\">Why iframe the Post Editor?  [plugin author][enterprise]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#relevant-bug-fixes-for-backward-compatibility-checks-theme-author-plugin-author-site-admin\">Relevant bug fixes for backward compatibility checks [theme author] [plugin author][site admin]</a></li></ul></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#new-blocks-all\">New Blocks [all]</a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#accordion-block\">Accordion Block</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#term-query-block\">Term Query Block</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#time-to-read-block\">Time to Read Block</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#math-block\">Math Block</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#comment-count-and-comment-link-blocks\">Comment Count and Comment Link Blocks</a></li></ul></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#updates-to-existing-blocks\">Updates to existing blocks </a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#stretchy-text-for-heading-and-paragraph-blocks-all\">Stretchy Text for Heading and Paragraph blocks. [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#button-block-end-user-siteadmin\">Button Block [end user] [siteadmin]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#cover-block-improved-video-handling-all\">Cover Block improved video handling [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#details-block-end-user-site-admin-plugin-author\">Details Block [end user][site admin][plugin author]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#gallery-block-all\">Gallery Block [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#heading-block-css-specificity-fix-all\">Heading Block CSS specificity fix [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#navigation-block-all\">Navigation Block [all]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#query-loop-blocks-all\">Query Loop Blocks [all]</a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#content-block\">Content Block</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#date-block-supports-custom-dates\">Date Block supports custom dates.</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#query-title-get-post-type-label\">Query Title get Post Type label</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#query-total\">Query Total</a></li></ul></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#rss-block-end-user\">RSS Block [end user]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#separator-block-theme-author-site-admin-plugin-author\">Separator Block  [theme author][site admin][plugin author]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#social-icons-block-developers-enterprise\">Social Icons Block [developers][enterprise]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#table-block-end-users-site-admin\">Table Block   [end users][site admin]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#video-block-all\">Video Block [all] </a></li></ul></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#theme-json-and-global-styles-developers-enterprise-site-admin\">Theme.json and Global Styles  [developers][enterprise][site admin]</a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#form-elements-in-theme-json\">Form elements in theme.json</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#border-radius-presets-supported\">Border Radius presets supported </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#button-element-inherits-typography\">Button element inherits typography</a></li></ul></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#a-closer-look-at-performance-optimizations-developers-enterprise\">A closer look at performance optimizations  [developers][enterprise]</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#improved-accessibility-across-core-and-block-editor\">Improved accessibility across Core and Block editor</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#new-and-updated-apis-for-developers-developers-enterprise\">New and updated APIs for Developers [developers][enterprise]</a><ul><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#abilities-api\">Abilities API</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#block-bindings-api\">Block Bindings API</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#dataviews-and-dataform\">DataViews and DataForm</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#interactivity-api\">Interactivity API</a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#output-buffering-for-the-rendered-template\">Output buffering for the rendered template </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#blocks-efficiently-find-and-traverse-blocks-in-a-document\">Blocks: Efficiently find and traverse blocks in a document. </a></li><li><a class=\"wp-block-table-of-contents__entry\" href=\"https://gutenbergtimes.com/wordpress-6-9-source-of-truth/#more-developer-notes-for-wordpress-6-9-release\">More Developer Notes for WordPress 6.9 release</a></li></ul></li></ul></nav>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"changelog\">Changelog</h2>\n\n\n\n<p>Any changes are cataloged here as the release goes on.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>11/24/2025</strong>\n<ul class=\"wp-block-list\">\n<li>Added <a href=\"https://gutenbergtimes.com/feed/#more-developer-notes-for-wordpress-6-9-release\">Dev Notes</a> on HTML API updates and pn PHP 8.5 Support</li>\n</ul>\n</li>\n\n\n\n<li><strong>11/21/2025 </strong>\n<ul class=\"wp-block-list\">\n<li>Updated screenshots and videos for <a href=\"https://gutenbergtimes.com/feed/#stretchy-text-for-heading-and-paragraph-blocks-all\">Stretchy Text section</a>, reflecting changes in RC2.  </li>\n</ul>\n</li>\n\n\n\n<li><strong>11/20/2025</strong>\n<ul class=\"wp-block-list\">\n<li>added <a href=\"https://gutenbergtimes.com/feed/#improved-accessibility-across-core-and-block-editor\">accessibility updates section</a>. </li>\n\n\n\n<li>Added <a href=\"https://gutenbergtimes.com/feed/#more-developer-notes-for-wordpress-6-9-release\">Dev Notes</a> on Admin Search query, IE-related updates and URL escaping functions. </li>\n\n\n\n<li>Updated the featured image to the <a href=\"https://github.com/WordPress/gutenberg/issues/71818#issuecomment-3556808505\">latest version of the highlight grid</a>.</li>\n</ul>\n</li>\n\n\n\n<li><strong>11/19/2025: </strong>\n<ul class=\"wp-block-list\">\n<li>Added credits</li>\n\n\n\n<li>Added tags to headings,</li>\n\n\n\n<li>Added <a href=\"https://gutenbergtimes.com/wp-admin/post.php?post=42536&amp;action=edit#more-developer-notes-for-wordpress-6-9-release\">Dev Notes</a> on WordPress email, UTF-8 support</li>\n\n\n\n<li>Added horizontal scroll bar feature to Math Block</li>\n\n\n\n<li>Fixed some typos.</li>\n</ul>\n</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"important-note-guidelines\">Important note/guidelines</h2>\n\n\n\n<p>Please do not copy and paste what is in this post since this will be shared with many people. This should be used to inspire your own content and to ensure that you have the best information about this release. If you do copy and paste, keep in mind that others might do the same, opening the door for some awkwardness around duplicated content out on the web. </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Each item has been tagged using best guesses with different high-level labels so that you can more readily see at a glance who is likely to be most impacted.</li>\n\n\n\n<li>Each item has a high-level description, visuals (if relevant), and key resources if you would like to learn more.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"overview\">Overview </h2>\n\n\n\n<p><em>Note: As always, what’s shared here is being actively pursued but doesn’t necessarily mean each will make it into the final release of WordPress 6.9.</em></p>\n\n\n\n<p>WordPress 6.9 introduces several new features and performance enhancements.</p>\n\n\n\n<p>Key new features include:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Collaborative Feedback and Content Control:</strong> Block-level Notes facilitate team feedback, allowed blocks UI, Abilities API, visual drag and drop, binding blocks to external controls.</li>\n\n\n\n<li><strong>New Blocks:</strong> Discover Accordion, Terms Query, Math, and Time to Read blocks.</li>\n\n\n\n<li><strong>Typography Enhancements:</strong> Benefit from new text-fitting typography.</li>\n\n\n\n<li><strong>Dashboard-wide Command Palette:</strong> The Command Palette will  help users streamline their workflow across WordPress Admin pages. </li>\n</ul>\n\n\n\n<p>Performance improvements include:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Optimized Loading:</strong> On-demand block-style loading and faster emoji detection.</li>\n\n\n\n<li><strong>Efficient Scheduling:</strong> Optimized cron execution.</li>\n</ul>\n\n\n\n<p>Furthermore, WordPress 6.9 lays the groundwork for future AI integration with the new Abilities API, which enables secure automation through machine-readable WordPress capabilities.</p>\n\n\n\n<p><a href=\"https://make.wordpress.org/core/6-9\">WordPress 6.9</a> is set to be released on December 2, 2025. </p>\n\n\n\n<p>Of note, this release includes Gutenberg plugin versions 20.5 &#8211; 21.9.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"important-links\">Important links:</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2025/07/28/roadmap-to-6-9/\">Roadmap to 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/6-9/\">WordPress 6.9 Development Cycle</a></li>\n\n\n\n<li>What’s new for developers: <a href=\"https://developer.wordpress.org/news/2025/06/whats-new-for-developers-june-2025/\">June</a>, <a href=\"https://developer.wordpress.org/news/2025/07/whats-new-for-developers-july-2025/\">July</a>, <a href=\"https://developer.wordpress.org/news/2025/08/whats-new-for-developers-august-2025/\">August,</a> <a href=\"https://developer.wordpress.org/news/2025/09/whats-new-for-developers-september-2025/\">September</a>, <a href=\"https://developer.wordpress.org/news/2025/10/whats-new-for-developers-october-2025/\">October</a>, <a href=\"https://developer.wordpress.org/news/2025/11/whats-new-for-developers-november-2025/\">November</a>)</li>\n\n\n\n<li>6.9 Field Guide </li>\n\n\n\n<li><a href=\"https://wordpress.org/state-of-the-word/\">State of the Word 2025</a> will include highlights and demos of the most important features of this release. The event will be <a href=\"https://www.youtube.com/wordpress\">livestreamed on YouTube </a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"assets\">Assets </h3>\n\n\n\n<p>In this <a href=\"https://drive.google.com/drive/u/0/folders/1z0ilv8vH2AVWVt-1tPI9qPUoTOSGahuB\">Google Drive folder</a> you can view all assets in this document.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"tags\">Tags</h2>\n\n\n\n<p>To make this document easier to navigate based on specific audiences, the following tags are used liberally: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>[end user]</strong>: end user focus. </li>\n\n\n\n<li><strong>[theme author]</strong>: block or classic theme author. </li>\n\n\n\n<li><strong>[plugin author]</strong>: plugin author, whether block or otherwise.</li>\n\n\n\n<li><strong>[developer]</strong>: catch-all term for more technical folks. </li>\n\n\n\n<li><strong>[site admin]</strong>: this includes a “builder” type. </li>\n\n\n\n<li><strong>[enterprise]</strong>: specific items that would be of interest to or particularly impact enterprise-level folks</li>\n\n\n\n<li><strong>[all]</strong>: broad impact to every kind of WordPress user. </li>\n</ul>\n\n\n\n<p>How can you use these? Use your browser&#8217;s <strong>Find</strong> capability and search for the string including the brackets. Then use the arrows to navigate through the post from one result to the next. </p>\n\n\n\n<details class=\"wp-block-details is-layout-flow wp-block-details-is-layout-flow\">Short video on how to use the tags to navigate the post. \n<p></p>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			<div class=\"jetpack-videopress-player__wrapper\"> </div>\n			\n			\n		</figure>\n		</details>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"command-palette-everywhere-all\">Command Palette everywhere <sup>[all]</sup></h2>\n\n\n\n<p>A couple of years ago the Command Palette was first released for the Site Editor. It provides content creators and administrators with a quick search and command execution tool. Invoked by Ctrl+K or Cmd+K. It is now available from any admin screen and helps streamline content creation as well as administering a WordPress site. It provides shortcuts to places otherwise only available by navigating multiple menu levels deep. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Command Palette now available from the dashboard\" class=\"wp-image-42912\" height=\"402\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Command-Palette-everywhere-1024x631.png?resize=652%2C402&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>Technically, this change extracts navigation commands from `@wordpress/edit-site` to `@wordpress/core-commands`, making them universally accessible. This architectural shift sets the foundation for admin-wide command integration in WordPress 6.9 and beyond, potentially reducing the need for repetitive clicking through admin menus.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>For developers the new useCommands hook was introduced. (<a href=\"https://github.com/WordPress/gutenberg/pull/71603\">71603</a>)</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"block-editor-updates\">Block editor updates</h2>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"notes-all\">Notes     <sup>[all]</sup></h3>\n\n\n\n<p>Asynchronous collaboration comes to WordPress via the new Notes feature and rings in the 3rd Phase of Gutenberg. Site owners, Editors and Authors can collaborate by leaving comment directly on the post or page, attached to the blocks in the editor. The notes are threaded, resolveable, and can be reopened as well. Add an access notes from the Block toolbar and via the sidebar. Post authors will receive email notification when notes are added to the content.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Collaborative Notes in WordPress 6.9\" class=\"wp-image-42914\" height=\"465\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Notes-in-WordPress-6-9.png?resize=652%2C465&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>Notes are by default enabled for Posts and Pages. They can be enabled also for other content post types via the `register_post_type` function. </p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>PHP</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">register_post_type( \'book\', array(\n	\'label\' => \'Books\',\n	\'public\' => true,\n	\'show_in_rest\' => true,\n	\'supports\' => array(\n		\'title\',\n		\'editor\' => array( \'notes\' => true ),\n		\'author\',\n	),\n) );\n</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #D7827E;\">register_post_type</span><span style=\"color: #797593;\">(</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">\'book\'</span><span style=\"color: #797593;\">,</span><span style=\"color: #575279;\"> </span><span style=\"color: #B4637A; font-style: italic;\">array</span><span style=\"color: #797593;\">(</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #EA9D34;\">\'label\'</span><span style=\"color: #575279;\"> </span><span style=\"color: #286983;\">=&gt;</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">\'Books\'</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #EA9D34;\">\'public\'</span><span style=\"color: #575279;\"> </span><span style=\"color: #286983;\">=&gt;</span><span style=\"color: #575279;\"> </span><span style=\"color: #D7827E;\">true</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #EA9D34;\">\'show_in_rest\'</span><span style=\"color: #575279;\"> </span><span style=\"color: #286983;\">=&gt;</span><span style=\"color: #575279;\"> </span><span style=\"color: #D7827E;\">true</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #EA9D34;\">\'supports\'</span><span style=\"color: #575279;\"> </span><span style=\"color: #286983;\">=&gt;</span><span style=\"color: #575279;\"> </span><span style=\"color: #B4637A; font-style: italic;\">array</span><span style=\"color: #797593;\">(</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #EA9D34;\">\'title\'</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #EA9D34;\">\'editor\'</span><span style=\"color: #575279;\"> </span><span style=\"color: #286983;\">=&gt;</span><span style=\"color: #575279;\"> </span><span style=\"color: #B4637A; font-style: italic;\">array</span><span style=\"color: #797593;\">(</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">\'notes\'</span><span style=\"color: #575279;\"> </span><span style=\"color: #286983;\">=&gt;</span><span style=\"color: #575279;\"> </span><span style=\"color: #D7827E;\">true</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">),</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #EA9D34;\">\'author\'</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">),</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">)</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">);</span></span>\n<span class=\"line\"></span></code></pre></div>\n\n\n\n<p>More details on handling Notes programmatically can be found in the Dev Note: <a href=\"https://make.wordpress.org/core/2025/11/15/notes-feature-in-wordpress-6-9/\"><strong>Notes feature in WordPress 6.9</strong></a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"visual-drag-drop-end-user\">Visual Drag &amp; Drop <img alt=\"🐉\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f409.png\" style=\"height: 1em;\" /> <img alt=\"💧\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/16.0.1/72x72/1f4a7.png\" style=\"height: 1em;\" />  <sup>[end user]</sup></h3>\n\n\n\n<p>Drag-and-drop just got smarter. Blocks now show live visual feedback as you reposition them, making layout building more intuitive and precise. You&#8217;ll see exactly where elements land before releasing, accelerating the creative process. (<a href=\"https://github.com/WordPress/gutenberg/pull/67470\">67470</a>). Currently, this only works for single blocks. Drag and Drop of multiple blocks is slated for WordPress 7.0.</p>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			<div class=\"jetpack-videopress-player__wrapper\"> </div>\n			\n			\n		</figure>\n		\n\n\n<h3 class=\"wp-block-heading\" id=\"ui-for-managing-allowed-blocks-in-templates-and-patterns-end-user-site-admin\">UI for managing allowed Blocks in Templates and Patterns.     <sup>[end user][site admin]</sup></h3>\n\n\n\n<p>WordPress now makes managing allowed blocks simpler with a new UI tucked in<strong> Advanced</strong> settings. Previously, developers had to edit block markup directly in code view—not user-friendly. This updates makes things easier for website admins, theme builders, and agencies enforcing specific block rules in patterns and templates. While agencies already handled this via code, the new interface offers a nicer interaction model. It&#8217;s part of WordPress&#8217;s broader mission: letting users build complex sites without touching code at all.  (<a href=\"https://github.com/WordPress/gutenberg/pull/72191\">72191</a>)</p>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			<div class=\"jetpack-videopress-player__wrapper\"> </div>\n			\n			\n		</figure>\n		\n\n\n<h3 class=\"wp-block-heading\" id=\"hide-and-show-blocks-end-user-site-admin\">Hide and Show Blocks  <sup>[end user][site admin]</sup></h3>\n\n\n\n<p>WordPress 6.9 introduces long-awaited control to hide blocks in the editor while preserving their structure within templates. This initial implementation provides content creators and designers with the ability to manage blocks that are not always displayed, such as seasonal content or conditional elements.</p>\n\n\n\n<p>Instead of deleting and recreating blocks, users can now simply toggle their visibility, retaining all settings. This foundational feature paves the way for more sophisticated conditional display options in future releases, potentially including role-based or time-based visibility controls. (<a href=\"https://github.com/WordPress/gutenberg/pull/71203\">71203</a>) </p>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			<div class=\"jetpack-videopress-player__wrapper\"> </div>\n			\n			\n		</figure>\n		\n\n<div class=\"wp-block-image\">\n<figure class=\"alignright size-large\"><img alt=\"\" class=\"wp-image-42922\" height=\"279\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Additional-CSS-Sidebar.png?resize=399%2C279&#038;ssl=1\" width=\"399\" /></figure>\n</div>\n\n\n<h3 class=\"wp-block-heading\" id=\"additional-css-control-moved-end-user-site-admin-theme-author\">Additional CSS control moved <br /> <sup>[end user][site admin] [theme author]</sup></h3>\n\n\n\n<p>Theme builders might go searching for the <strong>Additional CSS</strong> controls. They were moved into the ellipsis menu in the header of the Styles page on either side of the screen (<a href=\"https://github.com/WordPress/gutenberg/pull/71550\">71550</a>) </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42923\" height=\"238\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Additional-CSS-dark-side.png?resize=652%2C238&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"copy-styles-keyboard-shortcut-end-user-site-admin\">Copy Styles keyboard shortcut    <br /><sup>[end user][site admin]</sup></h3>\n\n\n\n<p>A new keyboard shortcut helps with pasting styles from one block to another and can speed up content creation workflows: cmd/ctrl + options/alt + v<strong> (</strong><a href=\"https://github.com/WordPress/gutenberg/pull/69196\"><strong>69196</strong></a><strong>) </strong></p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"block-style-variations-in-style-book-end-user-site-admin-theme-author\">Block Style Variations in Style Book<br /> <sup>[end user][site admin] [theme author]</sup></h3>\n\n\n\n<p>To make the Stylebook even more comprehensive, it now surfaces block styles for core blocks as well as custom blocks. This makes it possible to change block style variations site-wide in one screen (<a href=\"https://github.com/WordPress/gutenberg/pull/70448\">70448</a>).</p>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			<div class=\"jetpack-videopress-player__wrapper\"> </div>\n			\n			\n		</figure>\n		\n\n\n<h3 class=\"wp-block-heading\" id=\"the-starter-patterns-modal-for-all-post-types-theme-author-plugin-author-enterprise\">The Starter Patterns modal for all post types. <sup>[theme author] [plugin author][enterprise]</sup></h3>\n\n\n\n<p>With WordPress 6.9, contributors addressed a limitation in the starter pattern modal, which previously appeared exclusively when creating pages. This restriction is now removed from the `StartPageOptions` component, enabling the modal to display across all post types where patterns exist. The fix resolves a regression introduced in earlier pulls, expanding design flexibility for WordPress content creators working with diverse content structures.(<a href=\"https://github.com/WordPress/gutenberg/pull/69753\">69753</a>)</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"why-iframe-the-post-editor-plugin-author-enterprise\">Why iframe the Post Editor? <br /><sup>[plugin author][enterprise]</sup></h3>\n\n\n\n<p>The process to <a href=\"https://make.wordpress.org/core/2021/06/29/blocks-in-an-iframed-template-editor/\">restructure how the WordPress post editor works</a> started a few years ago.  WordPress 6.9 begins transitioning the editor into this isolated iframe, with full completion coming in WordPress 7.0.  Think of an iframe like a sandbox—a separate container within a webpage. Currently, the editor runs in the same space as WordPress&#8217;s admin interface, causing styling conflicts. This separation prevents admin styles from interfering with content editing, making the editor preview match what readers actually see. Plugin developers need to update older blocks to work with this new setup or they might stop functioning properly. </p>\n\n\n\n<p>The Dev note <a href=\"https://make.wordpress.org/core/2025/11/12/preparing-the-post-editor-for-full-iframe-integration/\">Preparing the Post Editor for Full iframe Integration</a> has more details. And in the comments many immediate questions have been answered. </p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"relevant-bug-fixes-for-backward-compatibility-checks-theme-author-plugin-author-site-admin\">Relevant bug fixes for backward compatibility checks <sup>[theme author] [plugin author][site admin]</sup></h3>\n\n\n\n<p>Certain bugs have been around for a while and developers often have found work arounds. Now that those bugs are fixed, it might be possible that the work around don’t work any more and it’s feasible to remove it. </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Comments Pagination: Remove unwanted bottom margin from links. (<a href=\"https://github.com/WordPress/gutenberg/pull/70360\">70360</a>)</li>\n\n\n\n<li>Remove screencast.com embed block variation. (<a href=\"https://github.com/WordPress/gutenberg/pull/70480\">70480</a>)</li>\n\n\n\n<li>Tag Cloud: Remove unnecessary full-width padding. (<a href=\"https://github.com/WordPress/gutenberg/pull/69725\">69725</a>)</li>\n\n\n\n<li>HTML Block: Remove space below textarea. (<a href=\"https://github.com/WordPress/gutenberg/pull/70055\">70055</a>)</li>\n\n\n\n<li>Fix : Calendar block: Colors do not change between global styles and theme.json. (<a href=\"https://github.com/WordPress/gutenberg/pull/70184\">70184</a>)</li>\n\n\n\n<li>Image Block: Preserve line breaks in media caption. (<a href=\"https://github.com/WordPress/gutenberg/pull/70476\">70476</a>)</li>\n\n\n\n<li>Search Block: Move search setting to inspector. (<a href=\"https://github.com/WordPress/gutenberg/pull/70144\">70144</a>)</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"new-blocks-all\">New Blocks <sup>[all]</sup></h2>\n\n\n\n<p>WordPress 6.9 brings six new blocks to WordPress editor: an Accordion block and its nested InnerBlocks, a Time-to-read block that also can show the word count of a post or page, the Term Query block, and the Math block to display mathematical formulas in science and essay posts. Comment handling also became easier with two more blocks, Comment Count and Comment Link. </p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"accordion-block\">Accordion Block</h3>\n\n\n\n<p>The Accordion Block has been long awaited and it is now available to all WordPress users. It’s a nested structure using Accordion Block, Accordion Item, Accordion Heading and Accordion Panel blocks. </p>\n\n\n\n<p>An Accordion block has multiple Accordion Items, each comprising of a Accordion Heading + Icon and an Accordion Panel with the content. </p>\n\n\n\n<p>The default styling is minimal and opens a lot of design possibilities for theme builders to cover all the use cases. On the Developer blog you’ll find a <a href=\"https://developer.wordpress.org/news/2025/10/styling-accordions-in-wordpress-6-9/\">tutorial of the various methods for styling an Accordion block</a>, using the example of an FAQ page (<a href=\"https://github.com/WordPress/gutenberg/pull/64119\">64119</a>)(<a href=\"https://github.com/WordPress/gutenberg/pull/71222\">71222</a>)(<a href=\"https://github.com/WordPress/gutenberg/pull/71388\">71388</a>).</p>\n\n\n\n<p>The Snippets section of the Developer Blog shows how to add <a href=\"https://developer.wordpress.org/news/snippets/schema-org-microdata-for-accordion-block-faqs/\">Schema.org microdata for Accordion block FAQs</a></p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42932\" height=\"495\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Accordion-block.png?resize=652%2C495&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"term-query-block\">Term Query Block</h3>\n\n\n\n<p>Traditionally, creating category and tag pages has been complex and required custom queries and workarounds. The new Terms Query block offers a built-in way to display and organize categories and tags, similar to how the Query block manages posts. (<a href=\"https://github.com/WordPress/gutenberg/pull/70720\">70720</a>)</p>\n\n\n\n<p>There are also supporting blocks: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Term Template block</li>\n\n\n\n<li>Term Name block</li>\n\n\n\n<li>Term Count block</li>\n</ul>\n\n\n\n<p>Together with the already existing Term Description block, this additional support for display of categories or tags is particularly useful for directory and magazine sites who provide content filters and subpages for their readers. The interface provides an `order` and `order-by` sorting in a single dropdown. All blocks have the necessary design tools for styling and the Term Count block also has a toggle to make it a link. For those working extensively with taxonomies, the ongoing <a href=\"https://github.com/WordPress/gutenberg/issues/49094\">hierarchy discussion</a> outlines future enhancements to taxonomy handling in WordPress.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42936\" height=\"381\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Term-Query-Block.png?resize=652%2C381&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"time-to-read-block\">Time to Read Block</h3>\n\n\n\n<p>The Time to Read block, available in the Gutenberg plugin for a long time went through an extended accessibility review before it was added to WordPress Core. </p>\n\n\n\n<p>It now has a toggle control to display a range of time rather than a fixed average reading time. It also comes with a variation to display a word count for the post or page it’s used on (<a href=\"https://github.com/WordPress/gutenberg/pull/71606\">71606</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/71841\">71841</a>). </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42941\" height=\"93\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Screenshot-2025-10-27-at-17.25.42.png?resize=435%2C93&#038;ssl=1\" width=\"435\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Time to Read / Word Count block WordPress 6.9\" class=\"wp-image-42940\" height=\"229\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Screenshot-2025-10-27-at-17.25.17.png?resize=652%2C229&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"math-block\">Math Block</h3>\n\n\n\n<p>With the Math Block content creators can now add mathematical formulas in LaTeX syntax to their post and pages. The LaTeX syntax can also be used together with the inline Math format.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42944\" height=\"287\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Math-Block-WordPress-6.9.png?resize=652%2C287&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42943\" height=\"457\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Math-block-inline-format.png?resize=652%2C457&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>Longer formulas are handled with a horizontal scrollbar.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-43026\" height=\"108\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Math-block-horizontal-scroll.png?resize=525%2C108&#038;ssl=1\" width=\"525\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"comment-count-and-comment-link-blocks\">Comment Count and Comment Link Blocks</h3>\n\n\n\n<p>Two new comment blocks help theme builders to handle comment count and comment links separately. Both blocks have been available in the Gutenberg plugin for a few years and only for the Site editor. Earlier this year, they came out of experimentation and were made available for all editor screens. So now a content creator can for instance include a links to the comment section on top of the post and be more deliberate in allowing access to comments only on certain posts. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Comment Link and Comment count in Template\" class=\"wp-image-42951\" height=\"194\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Comment-Link-Comment-Count.png?resize=652%2C194&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"updates-to-existing-blocks\">Updates to existing blocks </h2>\n\n\n\n<p>For WordPress 6.9, contributors standardized most blocks&#8217; Inspector settings to use the <a href=\"https://wordpress.github.io/gutenberg/?path=/docs/components-toolspanel--docs\">ToolsPanel component</a>, bringing visual consistency across the editor. The shift grants users granular control over displayed settings while simplifying how developers inject additional options into existing groups. The ToolsPanel aligns Inspector controls with the Styles sidebar, already leveraging the component extensively, creating a cohesive authoring experience. (<a href=\"https://github.com/WordPress/gutenberg/issues/67813\">67813</a>)</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"stretchy-text-for-heading-and-paragraph-blocks-all\">Stretchy Text for Heading and Paragraph blocks. <sup>[all]</sup></h3>\n\n\n\n<p>Both Heading and Paragraph blocks now support a new &#8220;Stretchy&#8221; variation that stretches text to the full width of its container. The transform tool from the button tools bar allowing users to convert text into this stretchy format. </p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-43081\" height=\"271\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Sstretchy-Heading-2025-11-21.png?resize=277%2C271&#038;ssl=1\" width=\"277\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-43082\" height=\"252\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Stretchy-Paragrapph-2025-11-21.png?resize=279%2C252&#038;ssl=1\" width=\"279\" /></figure>\n</figure>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"alignright size-large\"><img alt=\"\" class=\"wp-image-42955\" height=\"158\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Stretchy-slash-command.png?resize=289%2C158&#038;ssl=1\" width=\"289\" /></figure>\n</div>\n\n\n<p>Content creators can find these variations also in the Block inserter or via the Slash command. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42956\" height=\"307\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Stretchy-in-inserter.png?resize=354%2C307&#038;ssl=1\" width=\"354\" /></figure>\n\n\n\n<p>Stretchy Text offers designers and content creators an additional creative tool, opening up numerous possibilities for visually appealing text, especially when paired with suitable fonts. </p>\n\n\n\n<p>Developers can add support for this feature to any Custom text block via block.json. (<a href=\"https://github.com/WordPress/gutenberg/pull/73148\">73148</a>)(<a href=\"https://github.com/WordPress/gutenberg/pull/73056\">73056</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/73067\">73067</a>)(<a href=\"https://github.com/WordPress/gutenberg/pull/72923\">72923</a>)</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">{\n	\"supports\":{\n		\"typography\":{\n				\"fitText\": true,\n		}\n	}\n}\n</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">supports</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">typography</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fitText</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #D7827E;\">true</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"></span></code></pre></div>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			\n			\n			\n		</figure>\n		\n\n\n<h3 class=\"wp-block-heading\" id=\"button-block-end-user-siteadmin\">Button Block <sup>[end user] [siteadmin]</sup></h3>\n\n\n\n<p>Button Block now sports HTML element selection in <strong>Advanced</strong> settings, letting creators choose between semantic &lt;a&gt; links and true &lt;button&gt; elements. This tackles accessibility headaches where users mistakenly treat buttons as links, confusing screen readers. The dropdown educates users about proper usage, empowering developers and non-coders alike to build accessible interfaces without custom code (<a href=\"https://github.com/WordPress/gutenberg/pull/70139\">70139</a>).</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"cover-block-improved-video-handling-all\">Cover Block improved video handling <sup>[all]</sup></h3>\n\n\n\n<p>The Cover Block now supports poster images for videos, enhancing accessibility for users with slow internet or mobile devices. These images can be easily added by dragging and dropping the file onto the Poster Image control, streamlining the post creation process (<a href=\"https://github.com/WordPress/gutenberg/pull/70816\">70816</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/71039\">71039</a>)  (<a href=\"https://github.com/WordPress/gutenberg/pull/70939\">70939</a>).</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42961\" height=\"397\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Cover-Block-Updates.png?resize=652%2C397&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"details-block-end-user-site-admin-plugin-author\">Details Block <sup>[end user][site admin][plugin author]</sup></h3>\n\n\n\n<p>The Formatting features are now enabled for the Details Block, similar to the Paragraph block. Users can now use special formatting like Strikethrough, Sub or Superscript, and highlighting. This also opens up the list to be extended via plugins. </p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"gallery-block-all\">Gallery Block <sup>[all]</sup></h3>\n\n\n\n<p>This next WordPress version adds the support for gallery-wide aspect ratio setting to the Gallery Block. User can now set the same aspect ratio for all images in the gallery with one click from the sidebar. <strong>(</strong><a href=\"https://github.com/WordPress/gutenberg/pull/71116\"><strong>71116</strong></a><strong>) (</strong><a href=\"https://github.com/WordPress/gutenberg/pull/72104\"><strong>72104</strong></a><strong>).</strong></p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42962\" height=\"415\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Gallery-block-aspect-ratio.png?resize=652%2C415&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>Theme developers can control the availability via theme.json. The code snippet shows an example of removing the default choice <code>defaultAspectRatios</code> and only offering two choices in the editor.</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">\"settings\":{\n        \"blocks\" {\n            \"core/gallery\":{\n                \"dimensions\":{\n                    \"defaultAspectRatios\":false,\n                    \"aspectRatios\": &#91;\n                        {\n                             \"name\": \"Square - 1:1\",\n                             \"slug\": \"square\",\n                             \"ratio\": \"1\"\n                        },\n                        {\n                             \"name\": \"Wide - 16:9\",\n                             \"slug\": \"16-9\",\n                             \"ratio\": \"16/9\"\n                        }\n                  &#93;\n             }          \n         }\n    }\n</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #EA9D34;\">&quot;settings&quot;</span><span style=\"color: #575279;\">:</span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">        </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">blocks</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #575279;\"> </span><span style=\"color: #B4637A;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">            </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">core/gallery</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">dimensions</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                    </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">defaultAspectRatios</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #D7827E;\">false</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                    </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">aspectRatios</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">&#91;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                        </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                             </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">name</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;Square - 1:1&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                             </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">slug</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;square&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                             </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">ratio</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;1&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                        </span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                        </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                             </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">name</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;Wide - 16:9&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                             </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">slug</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;16-9&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                             </span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">ratio</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;16/9&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                        </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">                  </span><span style=\"color: #797593;\">&#93;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">             </span><span style=\"color: #797593;\">}</span><span style=\"color: #575279;\">          </span></span>\n<span class=\"line\"><span style=\"color: #575279;\">         </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">    </span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"></span></code></pre></div>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"heading-block-css-specificity-fix-all\">Heading Block CSS specificity fix <sup>[all]</sup></h3>\n\n\n\n<p>WordPress 6.9 fixes a <a href=\"https://github.com/WordPress/gutenberg/pull/72837\">specificity issue with the Heading block&#8217;s</a> background padding. Previously, padding styles applied to headings with backgrounds were affecting other blocks that use heading elements, such as the Accordion Heading block. This fix ensures that background padding is only applied to actual Heading blocks.</p>\n\n\n\n<p>The CSS selector for applying padding to headings with backgrounds has been made more specific. The selector now targets <code>.wp-block-heading.has-background</code> instead of just heading element tags (h1, h2, etc) with the <code>.has-background</code> class. </p>\n\n\n\n<p>Dev note: <a href=\"https://make.wordpress.org/core/2025/11/12/heading-block-css-specificity-fix-in-wordpress-6-9/\">Heading Block CSS Specificity Fix in WordPress 6.9</a></p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"navigation-block-all\">Navigation Block <sup>[all]</sup></h3>\n\n\n\n<p>The Navigation block in this WordPress release has been significantly  improved. Builders can now find the create page functionality directly from the link UI dropdown and the process of creating a page is streamlined by an additional “publish immediately” checkbox. (<a href=\"https://github.com/WordPress/gutenberg/pull/71188\">71188</a>)(<a href=\"https://github.com/WordPress/gutenberg/pull/71487\">71487</a>)</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"alignleft size-full is-resized\"><img alt=\"navigation page link, add page feature. \" class=\"wp-image-42968\" height=\"368\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/navigation-create-new-page.png?resize=520%2C368&#038;ssl=1\" style=\"width: 326px; height: auto;\" width=\"520\" /></figure>\n</div>\n\n\n<figure class=\"wp-block-image size-full is-resized\"><img alt=\"Navigation create page and immediately publish.\" class=\"wp-image-42969\" height=\"291\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/navigation-create-new-page-publish.png?resize=527%2C291&#038;ssl=1\" style=\"width: 372px; height: auto;\" width=\"527\" /></figure>\n\n\n\n<p>Similarly the button block inside the navigation block also has the option to create a new page. It’s a slightly different approach, but it helps with streamlining site building work. (<a href=\"https://github.com/WordPress/gutenberg/pull/69368\">69368</a>)<br /></p>\n\n\n\n<figure class=\"wp-block-image size-full is-resized\"><img alt=\"Navigation button with create page feature. \" class=\"wp-image-42971\" height=\"343\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/navigation-button-create-page.png?resize=398%2C343&#038;ssl=1\" style=\"width: 399px; height: auto;\" width=\"398\" /></figure>\n\n\n\n<p>Site builders can now customize aria-labels independently of menu titles, which is great for accessibility. The text box is located under <strong>Advanced &gt; Menu Name</strong> (<a href=\"https://github.com/WordPress/gutenberg/issues/66935\">66935</a>)</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"Customize the name of the navigation menu\" class=\"wp-image-42972\" height=\"570\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/navigation-menu-name.png?resize=283%2C570&#038;ssl=1\" width=\"283\" /></figure>\n\n\n\n<p>The hamburger icon now consists of individual SVG lines, opening up more styling and animation possibilities. Plus, the automatic panel expansion for Navigation options in site editing makes the workflow smoother. (<a href=\"https://github.com/WordPress/gutenberg/issues/71791\">71791</a>)(<a href=\"https://github.com/WordPress/gutenberg/issues/56346\">56346</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/69343\">69343</a></p>\n\n\n\n<p>To improve the robustness of the Navigation, the Navigation Link Block is now creating the URL dynamically and even if the slug of the page changes the link will be automatically updated.(<a href=\"https://github.com/WordPress/gutenberg/issues/72422\">72422</a>) A similar mechanism also was applied to the Navigation Submenu block. </p>\n\n\n\n<p>The submenu control of the background is now much easier. A new slider control for the overlay helps with the design. (<a href=\"https://github.com/WordPress/gutenberg/pull/69379\">69379</a>)</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"Navigation submenu overlay slider \" class=\"wp-image-42973\" height=\"278\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Navigation-submenu-background-overlay.png?resize=652%2C278&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<p>In template part view, a new button <strong>Edit Navigation</strong> helps users to update Navigation block settings and menu items directly from this view.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42976\" height=\"126\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/navigation-edit-button-template-part-edited.png?resize=552%2C126&#038;ssl=1\" width=\"552\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"query-loop-blocks-all\">Query Loop Blocks <sup>[all]</sup></h3>\n\n\n\n<p>Blocks primarily used in a Query Loop context received a few quality-of-life enhancements and accessibility controls. </p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"alignright size-full\"><img alt=\"content block HTML element selection. \" class=\"wp-image-42977\" height=\"297\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/content-html-element.png?resize=284%2C297&#038;ssl=1\" width=\"284\" /></figure>\n</div>\n\n\n<h4 class=\"wp-block-heading\" id=\"content-block\">Content Block</h4>\n\n\n\n<p>The Content block in WordPress 6.9 now features a `tagName` selector in its Advanced Settings. This allows theme builders to replace the default div wrapper with semantic HTML elements (like main, section, or article), improving accessibility, SEO, and content structure. This powerful tool enhances how blocks align with web standards.<strong> </strong><strong>(</strong><a href=\"https://github.com/WordPress/gutenberg/pull/70698\"><strong>70698</strong></a><strong>)</strong></p>\n\n\n\n<h4 class=\"wp-block-heading\" id=\"date-block-supports-custom-dates\">Date Block supports custom dates.</h4>\n\n\n\n<p>The Date block has undergone significant enhancements. It now supports custom dates, and its existing Post Date and Last Modified Date variations have been updated to utilize Block Bindings. This change involved creating a new binding source, core/post-data, which exposes the publish date as date and the last modified date as modified for any given post (<a href=\"https://github.com/WordPress/gutenberg/pull/70585\">70585</a>).</p>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-2 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42980\" height=\"378\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/date-publish-modified.png?resize=278%2C378&#038;ssl=1\" width=\"278\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42979\" height=\"338\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/date-select-format.png?resize=283%2C338&#038;ssl=1\" width=\"283\" /></figure>\n</figure>\n\n\n\n<h4 class=\"wp-block-heading\" id=\"query-title-get-post-type-label\">Query Title get Post Type label</h4>\n\n\n\n<p>The Query Loop block now supports a new <a href=\"https://github.com/WordPress/gutenberg/pull/71167\">Post Type Label variation</a>. This feature enables users to display the post type of the current item within the block, which is especially helpful for showcasing the post type name when creating custom post type archive templates. (<a href=\"https://github.com/WordPress/gutenberg/pull/71167\">71167</a>)</p>\n\n\n\n<figure class=\"wp-block-image size-large is-resized\"><img alt=\"Query block post type labels\" class=\"wp-image-42984\" height=\"570\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/query-post-type-labels-edited.png?resize=652%2C570&#038;ssl=1\" style=\"width: 498px; height: auto;\" width=\"652\" /></figure>\n\n\n\n<h4 class=\"wp-block-heading\" id=\"query-total\">Query Total</h4>\n\n\n\n<p>The total number of query results return are displayed via the Query Total block. In WordPress 6.9, this block received color controls for styling. (<a href=\"https://github.com/WordPress/gutenberg/pull/69500\">69500</a>)</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"rss-block-end-user\">RSS Block <sup>[end user]</sup></h3>\n\n\n\n<p>The RSS Block is a block to display another website&#8217;s RSS feed in a post or template. This version holds two small updates: An added option to display the links in a new tab or window and to control the `rel` attributes. RSS feeds from third-party sources sometimes include HTML entities in their titles. In a bug fix, the RSS Block now displays titles correctly. </p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"separator-block-theme-author-site-admin-plugin-author\">Separator Block <br /><sup>[theme author][site admin][plugin author]</sup></h3>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"alignright size-full is-resized\"><img alt=\"\" class=\"wp-image-42982\" height=\"590\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/separator-html-element.png?resize=431%2C590&#038;ssl=1\" style=\"width: 218px; height: auto;\" width=\"431\" /></figure>\n</div>\n\n\n<p>A small update to the Separator block opens the styling options for designers: The HTML element can now be changed from a `&lt;hr&gt;` to a `&lt;div/&gt;` tag in not only increasing the range of design option but also accessibility. (<a href=\"https://github.com/WordPress/gutenberg/pull/70185\">70185</a>)</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"social-icons-block-developers-enterprise\">Social Icons Block <sup>[developers][enterprise]</sup></h3>\n\n\n\n<p>The update to the Social Icons Block enables now extenders to register custom Social Icons variations. This way, any group of Social Icons that are relevant to the site owner can be created and used in the content, for instance icons of various Podcast directories, or to add icons for payment systems not available in core. </p>\n\n\n\n<p>On the WordPress Developer Block developers will find a tutorial on <a href=\"https://developer.wordpress.org/news/2025/08/registering-custom-social-icons-in-wordpress-6-9/\">how to register their own social media icons</a><strong>. </strong>Plugin developers can now remove existing icons and register their own. (<a href=\"https://github.com/WordPress/gutenberg/pull/70261\">70261</a>)</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42985\" height=\"111\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/social-icons-more.png?resize=513%2C111&#038;ssl=1\" width=\"513\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42986\" height=\"136\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/social-icon-podcasts.png?resize=380%2C136&#038;ssl=1\" width=\"380\" /></figure>\n\n\n\n<p>A bug fix now makes sure the social icons honor theme.json styles for typography. (<a href=\"https://github.com/WordPress/gutenberg/pull/70380\">70380</a>)</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">\"core/social-links\": {\n		\"typography\": {\n			\"fontSize\": \"var(--wp--preset--font-size--x-large)\"\n		}\n},</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #EA9D34;\">&quot;core/social-links&quot;</span><span style=\"color: #575279;\">: </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">typography</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fontSize</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;var(--wp--preset--font-size--x-large)&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">}</span><span style=\"color: #575279;\">,</span></span></code></pre></div>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"table-block-end-users-site-admin\">Table Block   <sup>[end users][site admin]</sup></h3>\n\n\n\n<p>The Table block received more robust handling of Markdown table parsing, specifically retaining alignment from a Markdown table. </p>\n\n\n\n<p style=\"font-size: 12px;\">| A &#8211; Left | B &#8211; Centered | C &#8211; Right | D &#8211; None |</p>\n\n\n\n<p style=\"font-size: 12px;\">| :&#8212;&#8212;- | :&#8212;&#8212;&#8212;-: | &#8212;&#8212;&#8211;: | &#8212;&#8212;&#8211; |</p>\n\n\n\n<p style=\"font-size: 12px;\">| 100      |     150      |       200 | 250      |</p>\n\n\n\n<p style=\"font-size: 12px;\">| 200      |     250      |       300 | 350      |</p>\n\n\n\n<p style=\"font-size: 12px;\">| 300      |     350      |       400 | 450      |</p>\n\n\n\n<p style=\"font-size: 12px;\">| 400      |     450      |       500 | 550      |</p>\n\n\n\n<p style=\"font-size: 12px;\">| 500      |     550      |       600 | 650      |</p>\n\n\n\n<p>The above Markdown example parsed into the block editor canvas is automatically converted to the Table block.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-42987\" height=\"232\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/table-block-markdown.png?resize=652%2C232&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"video-block-all\">Video Block <sup>[all]</sup> </h3>\n\n\n\n<p>The Video Block can now handle multiple language tracks with the option to set one as the default track. It’s also possible to add a poster image to the video block to improve accessibility for visitors with slow internet connections (<a href=\"https://github.com/WordPress/gutenberg/pull/71039\">71039</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/70939\">70939</a>)(<a href=\"https://github.com/WordPress/gutenberg/pull/70227\">70227</a>).</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42989\" height=\"370\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/video-tracks-handling.png?resize=652%2C370&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42988\" height=\"368\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/video-with-language-tracks.png?resize=652%2C368&#038;ssl=1\" width=\"652\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"theme-json-and-global-styles-developers-enterprise-site-admin\">Theme.json and Global Styles <br /><sup>[developers][enterprise][site admin]</sup></h2>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"form-elements-in-theme-json\">Form elements in theme.json</h3>\n\n\n\n<p>WordPress theme development reaches new enrichment with theme.json support for form element styling. Developers can now target text-based controls and select/dropdown elements through the styles.elements property, defining colors, borders, and typography directly in Global Styles. </p>\n\n\n\n<p>This eliminates custom CSS dependencies, allowing search forms, comment forms, and plugin-generated forms to automatically inherit the site&#8217;s design system. (<a href=\"https://github.com/WordPress/gutenberg/issues/34198\">34198</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/70378\">70378</a>) (<a href=\"https://github.com/WordPress/gutenberg/pull/70379\">70379</a>) Below snippet shows an example for the textInput element. </p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">\"elements\": {\n	\"textInput\": {\n			\"border\": {\n				\"radius\": \"0\",\n				\"style\": \"solid\",\n				\"width\": \"1px\",\n				\"color\": \"red\"\n			},\n			\"color\": {\n				\"text\": \"var(--wp--preset--color--theme-2)\"\n			},\n			\"typography\": {\n				\"fontFamily\": \"var(--wp--preset--font-family--inter)\"\n			}\n		}\n}\n</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #EA9D34;\">&quot;elements&quot;</span><span style=\"color: #575279;\">: </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">textInput</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">border</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">radius</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;0&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">style</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;solid&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">width</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;1px&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">color</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;red&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">color</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">text</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;var(--wp--preset--color--theme-2)&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">typography</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fontFamily</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;var(--wp--preset--font-family--inter)&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"></span></code></pre></div>\n\n\n\n<p>An additional resource is the tutorial on the WordPress Developer blog: <a href=\"https://developer.wordpress.org/news/2025/11/how-wordpress-6-9-gives-forms-a-theme-json-makeover/\">How WordPress 6.9 gives forms a theme.json makeover</a></p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"border-radius-presets-supported\">Border Radius presets supported </h3>\n\n\n\n<p>It’s now possible to define border radius presets in the `theme.json` for your theme. The user experience changes slightly with the numbers of presets: up until eight, a user can enable the border radius along a slider. For nine and more present the user uses a drop-down select menu. Users can always access custom value input through the custom button to the right of the control.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42991\" height=\"261\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/border-radius-presets.png?resize=560%2C261&#038;ssl=1\" width=\"560\" /></figure>\n\n\n\n<p>As an example you can add the following to the `settings` property of your `theme.json` file. (<a href=\"https://github.com/WordPress/gutenberg/pull/67544\">67544</a>). \\</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">{ \n\"settings\"{\n	\"border\": {\n		\"radiusSizes\": &#91;\n				{\n					\"name\": \"Small\",\n					\"slug\": \"small\",\n					\"size\": \"2px\"\n				},\n				{\n					\"name\": \"Medium\",\n					\"slug\": \"medium\",\n					\"size\": \"4px\"\n				},\n				{\n					\"name\": \"Large\",\n					\"slug\": \"large\",\n					\"size\": \"6px\"\n				}\n			&#93;\n	}\n}</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #797593;\">{</span><span style=\"color: #575279;\"> </span></span>\n<span class=\"line\"><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">settings</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #B4637A;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">border</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">radiusSizes</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">&#91;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">name</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;Small&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">slug</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;small&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">size</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;2px&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">name</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;Medium&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">slug</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;medium&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">size</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;4px&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">},</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">name</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;Large&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">slug</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;large&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">size</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;6px&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">&#93;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">}</span></span></code></pre></div>\n\n\n\n<ul class=\"wp-block-list\">\n<li>The Dev note has been published: <a href=\"https://make.wordpress.org/core/2025/11/12/theme-json-border-radius-presets-support-in-wordpress-6-9/\">Theme.json Border Radius Presets Support in WordPress 6.9</a></li>\n\n\n\n<li>A step-by-step guide can be found on the WordPress Developer blog: <a href=\"https://developer.wordpress.org/news/2025/09/border-radius-size-presets-in-wordpress-6-9/\">Border radius size presets in WordPress 6.9</a>. </li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"button-element-inherits-typography\">Button element inherits typography</h3>\n\n\n\n<p>With the release of WordPress 6.9, the button element defined in the default `theme.json` can inherit typographical styles from its parent. (<a href=\"https://github.com/WordPress/gutenberg/pull/70676\">70676</a>) </p>\n\n\n\n<p>The full styles for the element now look like this:</p>\n\n\n\n<div class=\"wp-block-kevinbatdorf-code-block-pro cbp-has-line-numbers\"><span>JSON</span><span class=\"code-block-pro-copy-button\" style=\"color: #575279; display: none;\" tabindex=\"0\"><pre class=\"code-block-pro-copy-button-pre\"><textarea class=\"code-block-pro-copy-button-textarea\" readonly=\"readonly\" tabindex=\"-1\">{\n	\"styles\": {\n		\"elements\": {\n			\"button\": {\n				\"typography\": {\n					\"fontSize\": \"inherit\",\n					\"fontFamily\": \"inherit\",\n					\"fontStyle\": \"inherit\",\n					\"fontWeight\": \"inherit\",\n					\"letterSpacing\": \"inherit\",\n					\"textTransform\": \"inherit\",\n					\"lineHeight\": \"inherit\",\n					\"textDecoration\": \"none\"\n				}\n			}\n	}\n}</textarea></pre><svg fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" viewBox=\"0 0 24 24\" xmlns=\"http://www.w3.org/2000/svg\"><path class=\"with-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path><path class=\"without-check\" d=\"M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"></path></svg></span><pre class=\"shiki rose-pine-dawn\" style=\"background-color: #faf4ed;\" tabindex=\"0\"><code><span class=\"line\"><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">styles</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">		</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">elements</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">button</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">typography</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #797593;\">{</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fontSize</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fontFamily</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fontStyle</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">fontWeight</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">letterSpacing</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">textTransform</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">lineHeight</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;inherit&quot;</span><span style=\"color: #797593;\">,</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">					</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #56949F;\">textDecoration</span><span style=\"color: #797593;\">&quot;</span><span style=\"color: #797593;\">:</span><span style=\"color: #575279;\"> </span><span style=\"color: #EA9D34;\">&quot;none&quot;</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">				</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">			</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #575279;\">	</span><span style=\"color: #797593;\">}</span></span>\n<span class=\"line\"><span style=\"color: #797593;\">}</span></span></code></pre></div>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"a-closer-look-at-performance-optimizations-developers-enterprise\">A closer look at performance optimizations <br /><sup>[developers][enterprise]</sup></h2>\n\n\n\n<p>WordPress 6.9 speeds up your site through several technical improvements. Scripts load more efficiently with priority ordering and move to footers when appropriate. Stylesheets load only when needed, particularly in classic themes, while styles for hidden blocks are omitted. The inline style limit increased to 40K. A new optimization system enables previously impossible efficiency gains. Database queries, UTF-8 processing, and cron tasks all improved. The Video block also eliminates layout shifts. Overall: more efficient performance across the board.</p>\n\n\n\n<p>Details are in this Dev Note: <a href=\"https://make.wordpress.org/core/2025/11/18/wordpress-6-9-frontend-performance-field-guide/\">WordPress 6.9 Frontend Performance Field Guide</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"improved-accessibility-across-core-and-block-editor\">Improved accessibility across Core and Block editor</h2>\n\n\n\n<p>WordPress 6.9 delivers substantial accessibility enhancements across Core and Gutenberg, implementing 33 Core improvements and 44 Gutenberg refinements. Core updates address administration interfaces, customizer tools, login and registration workflows, media library functionality, and bundled themes. </p>\n\n\n\n<p>Key changes include enhanced screen reader notifications, improved CSS-generated content handling, refined focus management, and superior color contrast adjustments. Gutenberg advances feature new accessible blocks, component redesigns, and data views improvements ensuring consistent editor interfaces. </p>\n\n\n\n<p>Updates span Cover blocks, Site Title, Navigation elements, Button blocks, and Columns, alongside Component refinements addressing modal dialogs, font size pickers, and link controls. </p>\n\n\n\n<p>Data Views enhancements prioritize checkbox visibility and text-based actions. Editor modifications involve iframe CSS classes, pattern modal behavior, and focus management within Global Styles panels. </p>\n\n\n\n<p>These comprehensive improvements reinforce WordPress&#8217;s commitment to Web Content Accessibility Guidelines standards, enabling creators to develop inclusive content while providing developers cleaner, more accessible code foundations for theme and plugin development.</p>\n\n\n\n<p>Details on the developer note <a href=\"https://make.wordpress.org/core/2025/11/19/accessibility-improvements-in-wordpress-6-9/\">Accessibility Improvements in WordPress 6.9</a></p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"new-and-updated-apis-for-developers-developers-enterprise\">New and updated APIs for Developers<br /><sup>[developers][enterprise]</sup></h2>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"abilities-api\">Abilities API</h3>\n\n\n\n<p>WordPress 6.9 features the Abilities API, a new foundational system designed to standardize how plugins, themes, and the WordPress core register and expose their capabilities. This API provides a unified, machine-readable registry of functionalities, ensuring consistent discovery, validation, and execution across various contexts, including PHP, REST API endpoints, and upcoming AI integrations.</p>\n\n\n\n<p>More resources: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Dev Note:<a href=\"https://make.wordpress.org/core/2025/11/10/abilities-api-in-wordpress-6-9/\">Abilities API in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/ai/2025/07/17/ai-building-blocks/\">AI Building Blocks for WordPress</a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"block-bindings-api\">Block Bindings API</h3>\n\n\n\n<p>Updates to the <a href=\"https://developer.wordpress.org/block-editor/reference-guides/block-api/block-bindings/\">Block Bindings API</a> include enabling it for a few more core blocks. The refactor of the Date block is one of those examples. (<a href=\"https://github.com/WordPress/gutenberg/pull/70585\">70585</a>)</p>\n\n\n\n<p>Another is enabling Image block’s caption data to be available for Synced Pattern Overrides. (<a href=\"https://github.com/WordPress/gutenberg/pull/72476\">72476</a>).  </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-42996\" height=\"203\" src=\"https://i0.wp.com/gutenbergtimes.com/wp-content/uploads/2025/11/Block-bindings-list-of-supported-blocks.png?resize=652%2C203&#038;ssl=1\" width=\"652\" /><figcaption class=\"wp-element-caption\">The list of supported block attributes by Block Bindings API.</figcaption></figure>\n\n\n\n<p>The function `getFieldsList` was available via the Gutenberg plugin and has been merged into WordPress Core now. Also, the attributes UI in the Block editor is now more flexible and handles any attributes from plugin developers. [Details will be available on the DevNote.]<br />More details can be found in the Dev Note: <a href=\"https://make.wordpress.org/core/2025/11/12/block-bindings-improvements-in-wordpress-6-9/\">Block Bindings improvements in WordPress 6.9</a></p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"dataviews-and-dataform\">DataViews and DataForm</h3>\n\n\n\n<p>WordPress 6.9 marks substantial progress for DataViews and DataForm components. There are no user-facing updates. Plugin developers can use the components for their products and on admin pages. </p>\n\n\n\n<p>The <strong>Field API</strong> now handles array, boolean, email, media, date, datetime, telephone, password, URL, and color types with comprehensive validation support. </p>\n\n\n\n<p><strong>DataViews</strong> gained sophisticated filtering with type-specific operators, infinite scroll capabilities, and improved table layouts featuring alignment and action column pinning. </p>\n\n\n\n<p><strong>DataForm</strong> received new layout options including modal panels and card designs, alongside controls matching the expanded field types. </p>\n\n\n\n<p>The new <strong>DataViewsPicker</strong> component is a selection-focused variant of DataViews designed for building item picker interfaces. It extends the familiar DataViews API with selection management and action buttons, making it ideal for workflows where users need to browse and pick items from a dataset. </p>\n\n\n\n<p>These enhancements collectively strengthen the block editor&#8217;s data management infrastructure, enabling developers to build more capable interfaces while maintaining consistency across WordPress&#8217;s content administration.</p>\n\n\n\n<p>Dev Note: <a href=\"https://make.wordpress.org/core/2025/11/11/dataviews-dataform-et-al-in-wordpress-6-9/\">DataViews, DataForm, et al. in WordPress 6.9</a></p>\n\n\n\n		<figure class=\"wp-block-jetpack-videopress jetpack-videopress-player\">\n			<div class=\"jetpack-videopress-player__wrapper\"> </div>\n			\n			\n		</figure>\n		\n\n\n<h3 class=\"wp-block-heading\" id=\"interactivity-api\">Interactivity API</h3>\n\n\n\n<p>Updates in WordPress 6.9 the Interactivity API with standardized directive IDs using triple-dash syntax, enabling multiple directives on single elements. The deprecated data-wp-ignore directive is removed. New TypeScript helpers AsyncAction and TypeYield improve asynchronous action typing. Client-side navigation improvements include dynamic stylesheet and script module loading, support for nested router regions, new attachTo options for overlays, and enhanced getServerState and getServerContext functions for proper state management across page transitions.</p>\n\n\n\n<p>The Dev Notes provide more details and code examples. </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/interactivity-apis-client-navigation-improvements-in-wordpress-6-9/\">Interactivity API’s client navigation improvements in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/changes-to-the-interactivity-api-in-wordpress-6-9/\">Changes to the Interactivity API in WordPress 6.9</a></li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"output-buffering-for-the-rendered-template\">Output buffering for the rendered template </h3>\n\n\n\n<p>WordPress 6.9 introduces a new way for plugin developers to handle HTML output, called the &#8220;template enhancement output buffer.&#8221; It standardizes output, meaning instead of plugins creating their own temporary storage for HTML, WordPress now provides a built-in system. If a plugin developer wants to use this feature, they just need to add a special wp_template_enhancement_output_buffer filter <em>before</em> the template is loaded. This system is designed for making small improvements or additions to a page, not for essential parts of the website&#8217;s functionality. If a website doesn&#8217;t want to use this buffer, it can disable it by filtering wp_should_output_buffer_template_for_enhancement to be false. </p>\n\n\n\n<p>For older (classic) WordPress themes, this buffer is now enabled by default. This allows them to load block styles only when needed and move them to the &lt;head&gt; section of the HTML, which can significantly reduce the amount of CSS on a page. Even if the page has already started loading, you can still send HTTP headers (like Server-Timing) while the output is being buffered. #<a href=\"https://core.trac.wordpress.org/ticket/64126\">64126</a>). <a href=\"https://core.trac.wordpress.org/ticket/43258\">#43258</a> (<a href=\"https://github.com/WordPress/wordpress-develop/pull/8412#issuecomment-3344496798\">PR#8412</a>) More details are available in the Dev Note. </p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"blocks-efficiently-find-and-traverse-blocks-in-a-document\">Blocks: Efficiently find and traverse blocks in a document. </h3>\n\n\n\n<p>The Block Processor class is now available in WordPress 6.9 to efficiently scan through and manipulate block structure in a lazy and streaming manner. For certain workloads this should dramatically improve the performance of processing code, and even more importantly, prevent out-of-memory crashes in the worst cases. [<a href=\"https://github.com/WordPress/wordpress-develop/pull/9105\">Core#9105</a>] <a href=\"https://core.trac.wordpress.org/ticket/61401\">(61401)</a>. </p>\n\n\n\n<p>It’s an more </p>\n\n\n\n<p>Do you need to do any of the following kinds of things? Check out <a href=\"https://github.com/WordPress/wordpress-develop/blob/trunk/src/wp-includes/class-wp-block-processor.php\">WP_Block_Processor</a>!</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Checking if a post contains a block of a given type.</li>\n\n\n\n<li>Counting or detecting all of the kinds of blocks present in a post.</li>\n\n\n\n<li>Modifying a block of a given kind within a post, not touching any of the other blocks.</li>\n\n\n\n<li>Finding the “wrapper element” surrounding the inner blocks and adding a class name to it.</li>\n\n\n\n<li>Extract sections of a document as blocks, modify it, serialize it back, and replace the original blocks with the new HTML.</li>\n</ul>\n\n\n\n<p>Dev Note: <a href=\"https://make.wordpress.org/core/?p=119384&amp;preview=1&amp;_ppp=7c4f90d12d\">Introducing the streaming block parser in WordPress 6.9</a></p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"more-developer-notes-for-wordpress-6-9-release\">More Developer Notes for WordPress 6.9 release</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2025/11/18/modernizing-utf-8-support-in-wordpress-6-9/\">Modernizing UTF-8 support in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/17/consistent-cache-keys-for-query-groups-in-wordpress-6-9/\">Consistent Cache Keys for Query Groups in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/17/miscellaneous-developer-focused-changes-in-6-9/\">Miscellaneous Developer-focused Changes in 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/18/more-reliable-email-in-wordpress-6-9/\">More-reliable email in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/19/admin-menu-search-query-changed/\">Admin menu search query changed</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/19/legacy-internet-explorer-code-removed/\">Legacy Internet Explorer Code Removed</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/19/url-escaping-functions-can-support-https-as-the-default-protocol-in-wordpress-6-9/\">URL-escaping functions can support HTTPS as the default protocol in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/21/updates-to-the-html-api-in-6-9/\">Updates to the HTML API in 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/21/php-8-5-support-in-wordpress-6-9/\">PHP 8.5 support in WordPress 6.9</a></li>\n</ul>\n\n\n\n<p>There are a few dev notes in the publishing queue, including a list of accessibility updates. This post will be updated once available. </p>\n\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 21 Nov 2025 09:42:19 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"Open Channels FM: New Host Nathan Wrigley Brings Chaos to Open Channels FM\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=112374\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"https://openchannels.fm/new-host-nathan-wrigley-brings-chaos-to-open-channels-fm/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:176:\"At WordCamp Europe, BobWP and Nathan cooked up \"The Shit Show\" podcast, discussing everything from penguins to soap. Tune in for quirky insights and Nathan’s endless droning.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 21 Nov 2025 09:15:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Matt: In Memoriam\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150624\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://ma.tt/2025/11/in-memoriam/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:779:\"<p>While there is much to celebrate in WordPress sometimes we must also mourn.</p>\n\n\n\n<p>In a <a href=\"https://timesofindia.indiatimes.com/city/surat/24-year-old-dies-after-collapsing-on-stage-at-it-event/articleshow/125394242.cms\">horribly tragic incident</a>, <a href=\"https://zeelthakkar.in/\">Zeel Thakkar</a>, a <a href=\"https://profiles.wordpress.org/zeelthakkar/\">WordPress contributor</a> and Kim Parsell Memorial Scholarship 2025 recipient, passed away <a href=\"https://x.com/wcsurat/status/1990766081754226923\">on stage at WordCamp Surat</a>. <a href=\"https://asia.wordcamp.org/2026/in-loving-memory-of-zeel-thakkar/\">WordCamp Asia has written a beautiful memorial to her</a>. She will be forever on our <a href=\"https://wordpress.org/remembers/\">Remembers page</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 21 Nov 2025 07:59:59 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: Gemini &amp;amp; FSD\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=150613\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2025/11/gemini-fsd/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1644:\"<p>Two interesting AI updates this week: It&#8217;s nice to read <a href=\"https://x.com/karpathy/status/1988705360723763242\">Andrej Karpathy&#8217;s review of Tesla&#8217;s FSD v13</a>, as someone who was involved with creating their first self-driving efforts. I&#8217;ve only experienced v12, so very excited to try out the latest generations soon. Ubiquitous self-driving will reshape cities and save countless lives.</p>\n\n\n\n<p>On the heels of announcing a <a href=\"https://x.com/sundarpichai/status/1989468970400055487\">$40B investment in Texas</a>, Google <a href=\"https://x.com/sundarpichai/status/1990812770762215649\">has launched Gemini 3</a>. It&#8217;s still funny how every organization ships its org chart with the naming and accessibility of the various models it releases, but, more broadly, it is so exciting to see so much intellectual capital focused on this area, with the frontier labs leapfrogging each other every few months. Every model has a feel, and with <a href=\"https://blog.google/products/gemini/gemini-3/\">Gemini 3</a> you start to feel the breadth of Google&#8217;s long investment in the space show up in interesting ways. Yet it can still be beaten in coding by an upstart like Anthropic with a fraction of Alphabet&#8217;s resources. </p>\n\n\n\n<p>What a time to be alive. Witnessing multiple excellent organizations ship the best work of their career rapidly is invigorating and inspiring; the competition drives better results, and the diffusion of new approaches is rapid. The consumer surplus that we all benefit from is just beginning to be felt; we&#8217;re maybe 1 or 2% impacted in the economy so far.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 20 Nov 2025 01:22:48 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:86:\"WPTavern: #194 – Devin Walker on Leading Jetpack: Challenges, Vision, and the Future\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=200819\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"https://wptavern.com/podcast/194-devin-walker-on-leading-jetpack-challenges-vision-and-the-future\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:46775:\"<details>Transcript<div>\n<p>[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p>Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case, leading Jetpack, the past, the challenges, the vision, and the future.</p>\n\n\n\n<p>If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p>If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox and use the form there.</p>\n\n\n\n<p>So on the podcast today we have Devin Walker. Devin&#8217;s journey in the WordPress ecosystem spans many years, with experience in development, design, marketing, and customer support. He is best known as the co-founder of GiveWP, which he built and scaled before it was acquired. During his time there, he touched a variety of prominent WordPress brands, including iThemes, Kadence, LearnDash, and The Events Calendar.</p>\n\n\n\n<p>Today Devon is starting a new role leading the Jetpack suite of services at Automattic. It&#8217;s a position with hefty responsibilities as Jetpack powers millions of WordPress sites, and integrates deeply across</p>\n\n\n\n<p>I talk with Devon about why he took on this challenge. The divisiveness and complexity surrounding Jetpack, and his vision for refocusing the plugin and simplifying its user experience.</p>\n\n\n\n<p>We start by hearing about Devon&#8217;s extensive WordPress background, and the choices he weighed up when deciding to join Automattic.</p>\n\n\n\n<p>The conversation quickly moves to the scope of Jetpack, its evolution, the struggle to be a jack of all trades master of none, and the recent efforts to bring greater focus and polish to key features like forms and SEO</p>\n\n\n\n<p>Devin gets into the organizational changes at Automattic. How Jetpack&#8217;s development teams now collaborate more fluidly with other product teams, such as WooCommerce, and the balancing act of shipping improvements to a 4 million strong user base without breaking things.</p>\n\n\n\n<p>AI emerges as a massive new frontier, and Devin shares behind the scenes insights into Jetpack&#8217;s current, and future, aI capabilities, giving us a glimpse at content creation, block building, and how AI might reshape user and developer expectations in WordPress.</p>\n\n\n\n<p>Throughout we hear about Devin&#8217;s approach to product marketing, and the need for more of it, the importance of listening to user feedback, and his plans for a more coherent and compelling Jetpack experience.</p>\n\n\n\n<p>If you&#8217;re a WordPress user wondering where Jetpack is headed, what&#8217;s working, or how AI fits into the future of site building, this episode is for you.</p>\n\n\n\n<p>If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you can find all the other episodes as well.</p>\n\n\n\n<p>And so without further delay, I bring you Devin Walker.</p>\n\n\n\n<p>I am joined on the podcast by Devin Walker. Hello, Devin.</p>\n\n\n\n<p>[00:03:34] <strong>Devin Walker:</strong> Hello.</p>\n\n\n\n<p>[00:03:35] <strong>Nathan Wrigley:</strong> Very nice to have you with us. Devin has a shiny new job. Up until a few weeks ago, Devin was not an Automattician, or at least I don&#8217;t think you were maybe at any point in your past. But you are now an Automattition, and you are doing what?</p>\n\n\n\n<p>[00:03:47] <strong>Devin Walker:</strong> My official title is Artistic Director of Jetpack, but basically product owner, or head of Jetpack. Whatever you want to call it.</p>\n\n\n\n<p>[00:03:55] <strong>Nathan Wrigley:</strong> So when it comes to Jetpack, the buck stops with you. I guess that&#8217;s a pretty important role in the WordPress space over at Automattic. And if anybody hasn&#8217;t heard of you, I suppose it would be important to just lay the groundwork, who you are, what you&#8217;ve done in the past.</p>\n\n\n\n<p>I know you&#8217;ve got a long and storied history, but just maybe a one minute little short bio telling us who you are and what you&#8217;ve done.</p>\n\n\n\n<p>[00:04:14] <strong>Devin Walker:</strong> Yeah, sure. I&#8217;ve been using WordPress for all sorts of things, development, design, blogging for 16 years now. Really made my name known, I guess you would say, with Matt Cromwell. We co-founded GiveWP together, and we grew it for seven years, from late 2014, all the way through 2021, which then we were acquired by Liquid Web and was there for a little more than four years, and touched a lot of brands from there, from the iThemes rebrand to SolidWP, to Kadence, to LearnDash, Events Calendar, and of course GiveWP as well.</p>\n\n\n\n<p>And left there in early August of this year, 2025. I also built WP Rollback throughout the years, that has quite a few active installs. So yeah, that&#8217;s a bit about me. Developer, design background, definitely well-rounded with marketing and supporting customer success.</p>\n\n\n\n<p>[00:05:05] <strong>Nathan Wrigley:</strong> So you&#8217;ve had a lot of experience working with WordPress products, which I guess is what you are doing over at Automattic, because let&#8217;s just call it head of Jetpack, just to make it easy. It&#8217;s a curious title, by the way. Artistic Director is kind of a really.</p>\n\n\n\n<p>[00:05:17] <strong>Devin Walker:</strong> You know Automattic loves that title.</p>\n\n\n\n<p>[00:05:18] <strong>Nathan Wrigley:</strong> Yeah, they love that, don&#8217;t they? But head of Jetpack, and obviously you&#8217;ve got a long and storied history kind of growing products and making sure that they succeed and customer support and all of that kind of thing.</p>\n\n\n\n<p>And I feel like Jetpack, no matter what time you dropped in on Jetpack in the last, let&#8217;s say decade, I feel that half of the community felt like it needed a lot of love.</p>\n\n\n\n<p>And I&#8217;m just wondering when you were interviewing for this position or when this position was offered to you, I don&#8217;t know how that process went, but what the kind of broad brush strokes are in what you&#8217;re hoping to do over there?</p>\n\n\n\n<p>We&#8217;ll get into the weeds very much, but roughly speaking, what&#8217;s the scope of the new job? What is it that you are hoping to do in the next three, six months, years, something like that?</p>\n\n\n\n<p>[00:05:57] <strong>Devin Walker:</strong> Yeah, so when I left Liquid Web, I wrote a long, well, not long, but wrote a blog post about closing that chapter of my career and really being open to what&#8217;s coming next for me. I knew that I wanted to stay in WordPress and I was having fun building on just my own products at the time, and having full control of everything, the whole lifecycle of a product.</p>\n\n\n\n<p>And I did some work with Matt in the past on some of his nonprofit sites with Give and the VIP team and the concierge at Automattic. And so Matt called me up one day, you know, we stayed loosely in contact over the years, and said, we have some interesting opportunities here at Automattic, and one of them that I think you&#8217;d be great at is Jetpack. And in my mind I&#8217;m like, Jetpack, this is a doozy.</p>\n\n\n\n<p>But, you know, he said, give it some thought, work on your own pace and give me a call back whenever. And so I thought about it for a week and, maybe two weeks, talked to my wife about it. And really it comes down to, I was either going to start my own business again, and try to grind again and strike lightning twice, like GiveWP, and see if I could grow something and eventually sell it in five to seven years, which takes a lot of hard effort, sacrifice, money. A lot of your own money, and almost no guarantee. And the WordPress marketplace has changed so much that it&#8217;s not immediate impact right away, and you&#8217;re really out on your own.</p>\n\n\n\n<p>It worked well once, but I was in my early thirties, just turning 30, and now I&#8217;m 40. So life&#8217;s changed quite a bit for me. And Jetpack, it is a very divisive product, we can get more into that in the future, but really it came down to having that impact. Being at Automattic, a company that I&#8217;ve respected since I came into WordPress, and always wanted to go behind the scenes and work as an Automattician, so going full circle from where my career began to the opportunity and the challenge.</p>\n\n\n\n<p>If I succeed at this, it can really open some other doors at Automattic. I&#8217;m head of this product, which touches almost everything on Automattic as far as the WordPress business goes. I just thought about it long and hard, talked to Matt about it, and made sure I would have the levers for success also. And that&#8217;s what made me choose to say yes and come aboard.</p>\n\n\n\n<p>[00:08:08] <strong>Nathan Wrigley:</strong> It is kind of curious because if you just discount all of the stuff you just said about, you know, wanting to fight and build your own product up, I can well imagine how grinding that can be, and there&#8217;s no guarantee of success. It could be a real failure.</p>\n\n\n\n<p>But stepping into a huge product, I&#8217;m going to put my neck out on the line a little bit here and say, I actually can&#8217;t think of a product or a plugin, let&#8217;s go with that, in the WordPress space that tries to cover as many bases. Covered by any organisation, whether that&#8217;s a third party development team or what have you, I can&#8217;t think of one named product that tries to cover as many bases.</p>\n\n\n\n<p>And the fact that it&#8217;s divisive and I&#8217;m sure you&#8217;ll get into this, but there&#8217;s lots of room for improvement, I&#8217;m sure you&#8217;ll agree. You are walking into something exactly as you say, where there is a chance of great success here. If you pull this off, and you pull the right levers, and in six months time, a year&#8217;s time, two years time, the arc is going in the right direction, there&#8217;ll be measurable success. So really interesting.</p>\n\n\n\n<p>So what was the bit, when you had that, oh, moment, what was the bit about Jetpack which made you think long and hard about it over two weeks, as opposed to immediately saying, yeah, I&#8217;ll do it? There must have bits about the project, Jetpack as a plugin, whatever it may be. What were the bits that concerned you?</p>\n\n\n\n<p>[00:09:18] <strong>Devin Walker:</strong> Well, I&#8217;ve used it over the years on and off. I wouldn&#8217;t call myself a power user at all, but I come from the community, 15 years of being in the community. I&#8217;ve gone to, I don&#8217;t even know how many WordCamps and always kept tabs on it, especially when, I don&#8217;t know when it was. I think it was pre 2020, when they did like a bit of marketing push that Jetpack does donations now, accept donations with Jetpack. And it was through Jetpack forms. I didn&#8217;t know that at the time, so I installed Jetpack. I was like, where&#8217;s donations? You&#8217;ve got to find your way through this tangled web. Oh, it&#8217;s part of forms. Okay, let&#8217;s go into forms. Oh, it&#8217;s like a template now and you have to, the connect flow was terrible. The whole flow was not a great experience.</p>\n\n\n\n<p>And the donation form itself, I was like, oh, we have a pretty serious competitor now with Give, we&#8217;ve got to like step our game up. But then I left that, I was like, okay, don&#8217;t worry about it guys, we&#8217;ll be fine now, nobody&#8217;s going to use this. That&#8217;s where that, oh, moment comes from where like, jack of all trades, master of none type of thing.</p>\n\n\n\n<p>[00:10:15] <strong>Nathan Wrigley:</strong> Yeah, I think probably encapsulates it perfectly. It&#8217;s kind of jack of all trades and master of none. So I&#8217;m just going to rattle off some of the things that I know it does. I&#8217;m probably missing quite a lot here. So for example, you know, it does stats, think something like Google Analytics, it will offer that for you. Backups. It will do protection. It will do speed and optimisation things on your website. Social sharing. It will do forms. There&#8217;s VideoPress thrown in there as well. There&#8217;s a whole bunch of stuff that I&#8217;ve missed out there, but it really is encapsulating a lot.</p>\n\n\n\n<p>And the jack of all trades, master of none, bit kind of fits because when Jetpack came out, I&#8217;m imagining it was a really, it was probably at the forefront of many of those things. The things that it did, it probably did as well as everybody else. But now, 10, 15, whatever years later, there&#8217;s now been real amazing products delivered by third party developers that have become the standard of forms, of backups, of speed and optimisation services and what have you. And so Jetpack now has to kind of compare itself to the very, very best. And I think that&#8217;s hard. You know, for one plugin to try and be the best at everything. Nigh on impossible, I would imagine.</p>\n\n\n\n<p>[00:11:16] <strong>Devin Walker:</strong> You&#8217;re right. Like, we can&#8217;t compete. I&#8217;ve been preaching focus for the last, since 2016 when our mentors said, what the heck are you doing all these other plugins? Sell them off or sunset them and only focus on Give. And that&#8217;s when our business started taking off. Now, what I&#8217;m trying to do is bring focus back into Jetpack.</p>\n\n\n\n<p>We do some things very well, and we need to make sure that, I&#8217;m not going to say we&#8217;re going to compete on the level of a Gravity Forms for our form solution. It&#8217;s going to come very close. And for 98% of the users out there that need forms on their website, I think it&#8217;ll fulfill that need.</p>\n\n\n\n<p>For that special 2% that need like calculation fields, they need super customised form capabilities, then it might not get to that level. But we really want Jetpack to be your go-to solution so that you can have these products work well together as well.</p>\n\n\n\n<p>It&#8217;s very generous too, the free version. You get a free CDN, you get VideoPress for free, and bringing people in the door and showing them that. Some folks are seeing the light of that, of what it can actually do and do pretty well. But for instance, like SEO. Yeah, Jetpack does SEO, but it&#8217;s the most rudimentary, basic version. I want to make that a bit better there. But also things that it doesn&#8217;t do well. Either get rid of those, if they&#8217;re just going to sit on a shelf and grow with age, what&#8217;s the point of it?</p>\n\n\n\n<p>So yeah, a lot of realignment with that and understanding that teams that are fully focused on one specific part of what Jetpack does, it&#8217;s really hard for us to compete with that.</p>\n\n\n\n<p>[00:12:46] <strong>Nathan Wrigley:</strong> Do you envisage a future for Jetpack now that you are at the helm, if you like ? And I don&#8217;t know how the structure of the people that are working on Jetpack works. In other words, do you have a forms dedicated crew where you&#8217;ve got, I don&#8217;t know, a bunch of people who just work on forms? You&#8217;ve got a bunch of people working on VideoPress and VaultPress and all of these different bits and pieces. Or is it, you work with Jetpack and you kind of move from team to team? I&#8217;m just curious as to what it looks like inside of Automattic and the different bits that make up Jetpack.</p>\n\n\n\n<p>[00:13:14] <strong>Devin Walker:</strong> Yeah, so this is really an interesting time at Automattic, where they&#8217;re going from that functional organisation where it&#8217;s product focus. Where Jetpack did, a year ago, have a dedicated development team, designer team, and the person that was in my role before, it was just like a classic company structure in a way, within Automattic.</p>\n\n\n\n<p>Now it&#8217;s shifting to more of a matrix organisation where there&#8217;s one architecture team. They handle .com, they handle Jetpack, they handle a bunch of other products like WooCommerce within that. And the designers as a product are outside of that.</p>\n\n\n\n<p>And so what that means is we, as the product team, we have a shared roadmap where, if you ever use .com, a lot of what brings that special sauce to it, what makes it unique outside of the self installed WordPress is Jetpack. So for instance, forms is getting a massive upgrade. And the 15.2 that just came out, it has quite a big upgrade. 15.3, we&#8217;re going to have even more. So there&#8217;s a dedicated team right now that&#8217;s, some of the best engineers, I&#8217;ve been really blown away with the level of engineering at Automattic, are working on bringing forms up. And I&#8217;m leading that initiative, putting myself into that place where I can then shape forms in the future.</p>\n\n\n\n<p>But that does mean that some other elements of Jetpack aren&#8217;t getting taken care of right now. AI&#8217;s going to become a big thing. We have to pick and choose based on our resources, what are the most important things for our shared initiative? But what that means is they work better together. I think you&#8217;re going to see in the future a lot more benefit of running WooCommerce and Jetpack together.</p>\n\n\n\n<p>Now, we&#8217;re not going to force you to log into wordpress.com to use WooCommerce, but to get some of that benefit, you will need to OAuth in to using Jetpack. And that is a requirement, because a lot of the Jetpack, what you get for free and the secret sauce is based on our cloud servers. You basically are starting to use our infrastructure for free. And Automattic is huge on privacy. And so I don&#8217;t quite understand that whole conflict of folks that don&#8217;t like that. There&#8217;s just some people out there that will never really like Automattic and they will not OAuth in or double sign in to use Jetpack, you know what I mean?</p>\n\n\n\n<p>[00:15:29] <strong>Nathan Wrigley:</strong> Yeah, it&#8217;s kind of curious. So if I&#8217;m parsing it right, it sounds like what you were saying was that in a recent restructuring of Automattic and over the last 18 months or so, I think there&#8217;s been a lot of that. It sounds like Jetpack is more of an amorphous thing. It&#8217;s not like these particular people are dedicated to Jetpack Forms and these ones are for VaultPress or whatever it may be. It&#8217;s more liquid than that. We&#8217;re going to do a dedicated sprint on Forms, for example. It sounds like that&#8217;s getting an update. So probably has had people on the seats having a look at that.</p>\n\n\n\n<p>And then once that&#8217;s put away and tidied up, then move to something else. But also, I guess an interesting thing that you mentioned there is that because it&#8217;s in this wider organisation of which WooCommerce, it&#8217;s pretty big, that you can also communicate with those folks. So there may be some overlap between what Forms can do in Jetpack and something that you might wish to do with WooCommerce, those kind of things.</p>\n\n\n\n<p>So have I got that right? It&#8217;s not like dedicated people doing dedicated products within Jetpack, it&#8217;s much more liquid and amorphous than that.</p>\n\n\n\n<p>[00:16:23] <strong>Devin Walker:</strong> Absolutely. Rather than having silos we have one large organisation that works better together. And our vision is really that all the WordPress products should be very similar to Apple and how when you&#8217;re using iOS or MacOS, there&#8217;s a lot of similar fields and they work well together and they tag team off of each other.</p>\n\n\n\n<p>And prior to this reorg, that wasn&#8217;t happening so much. And we experienced this at Stellar as well. They purchased a bunch of plugins, brought them all in, the vision was for them to all work well together. We went from functional organisation to this matrix type of organisation. And so this isn&#8217;t my first rodeo doing it, I know it can work. But it does take a concerted effort, and it&#8217;s still ongoing right now. It hasn&#8217;t been 18 months, it&#8217;s been like six months. And we&#8217;re still trying to figure things out. So me stepping in at this time, I&#8217;m really trying to figure it out.</p>\n\n\n\n<p>I have a blog post called, or a P2 post called Connecting the Dots, where I&#8217;m just trying to find which experts and which products on Jetpack they know better. I&#8217;ve been having so many one-on-ones just to try to get to know these folks, understand their history with Jetpack and put it in this kind of glossary of what I have here, and keep that updated as my time progresses here.</p>\n\n\n\n<p>[00:17:35] <strong>Nathan Wrigley:</strong> It is kind of hard to get a grip on what Jetpack is. Because it&#8217;s trying to do all these different things, I think it is quite hard for people to understand what they&#8217;re installing. So they install Jetpack, okay, I&#8217;ve heard that Jetpack&#8217;s a thing, I&#8217;ll go and install it. There&#8217;s loads of free stuff available. And then all of a sudden there&#8217;s bits which do work, there are bits which you can extend and upgrade and, you know, you might have to log in with .com to make that bit combine with this bit.</p>\n\n\n\n<p>And then there are bits where, you know, it feels like the classic themes work well in some areas, and then if you&#8217;ve got a block-based theme, other things don&#8217;t work quite so well. I&#8217;m thinking like social sharing and things like that. And it&#8217;s bit of a, mess is the wrong word, but it&#8217;s incredibly confusing, I think, to a novice user. And so I&#8217;m, I&#8217;m going to put words into your mouth, I&#8217;m guessing this is one of the challenges that you are going to try and tackle to take that confusion away. Because, I don&#8217;t know, it doesn&#8217;t matter how many times I log into Jetpack, there&#8217;s always a bit of a surprise. Oh, okay, it works that way. That&#8217;s curious. I wasn&#8217;t expecting it to do that. And I&#8217;ve been doing this for absolutely ages, and I&#8217;m still surprised by the way things work.</p>\n\n\n\n<p>[00:18:33] <strong>Devin Walker:</strong> You&#8217;re not alone. So one of the things that Matt&#8217;s been saying since I&#8217;ve come on board is we don&#8217;t really need to build much more new things. We need to focus and improve what&#8217;s already there, especially in Jetpack and .com. And simplifying it and making it make more sense to the end users. And Jetpack is a prime candidate for a really fresh look at how that can happen.</p>\n\n\n\n<p>We&#8217;ve been doing exercises as the product team for a framework called Jobs to Be Done. You put yourself in the shoes of that customer and you experience it through fresh eyes, based on what they are looking to get out of it.</p>\n\n\n\n<p>For instance, the classic, I guess, analogy is, folks don&#8217;t, they don&#8217;t want a quarter inch drill bit, they want a quarter inch hole, and that&#8217;s just the tool they use to get that quarter inch.</p>\n\n\n\n<p>And it&#8217;s the same thing with Jetpack or any other software product, and it&#8217;s a reforming in thinking. It&#8217;s only my fifth week here, but it&#8217;s been really a refreshing way to think about how we build product, and how I can then work with the designers to then smooth out those wrinkles of which there are many.</p>\n\n\n\n<p>[00:19:40] <strong>Nathan Wrigley:</strong> Yeah, it&#8217;s kind of interesting that you say that, because pretty much everything that Jetpack has, well, there&#8217;s one notable exception, which is of course AI, which we&#8217;ll come to in a minute. But more or less everything that&#8217;s in Jetpack has been available in some form or other for a decade or more. You know, forms is, it&#8217;s not a new thing. There&#8217;s some interesting ideas that people have come up with that maybe we&#8217;d want to integrate, but backups, it&#8217;s not a new thing.</p>\n\n\n\n<p>So the idea of not having new, well, features is probably the wrong word, but not having a new product and just finessing what you&#8217;ve already got, I think that would be music to any subscriber to Jetpack. One of the paid plans that you got, I think they would absolutely love that. Just finesse what you&#8217;ve already got. We&#8217;ve already got this thing, we know what we&#8217;ve got, we know how it works, but finesse it, give us a few more features here and there in the bit, like for example, forms or what have you. That seems like music to my ears.</p>\n\n\n\n<p>But I&#8217;ve said it. The cat is out the bag in this episode now, AI. AI is smuggled into Jetpack in the most, it&#8217;s kind of hidden. It&#8217;s almost entirely hidden, and yet incredibly profound. I don&#8217;t know if, dear listener, you&#8217;ve experienced Jetpack and it&#8217;s AI features, but if you switch it on and you just go, I don&#8217;t know, make a blog post or something like that, when you go to publish, it will just helpfully write your excerpt and your featured image, it will create that for you on the fly. It all happens in the background. It&#8217;s really incredible. How did that get under the radar? And is that going to be a big feature?</p>\n\n\n\n<p>[00:21:02] <strong>Devin Walker:</strong> That is going to be a huge feature. I just came back from New York with our AI engineering team led by James LaPage, who&#8217;s one of the brightest, young stars, I want to say, in WordPress. And he&#8217;s one of the reasons that I&#8217;m so excited for what AI can become with Jetpack, and where it&#8217;s going to go from here. It&#8217;s really great that you are already like what&#8217;s there? But that&#8217;s just scratching the surface from what we&#8217;re going to be doing in the near future.</p>\n\n\n\n<p>We&#8217;ve got quite a large team working on this. This is a 50 plus engineering team. It&#8217;s a huge focus of Automattic. And Jetpack&#8217;s the way we&#8217;re going to bring a lot of what we&#8217;re bringing to .com to self-hosted users. And it&#8217;s not going to cost you really much at all and it&#8217;s gonna be done in the WordPress way.</p>\n\n\n\n<p>Right now it tries to be your content companion, is kind of how I call it, but it&#8217;s going to do that a lot better, and it&#8217;s going to reach outside of the post editor and do a lot more helpful items for you in the WP admin. And not only in the WP admin, also provide some tools for you in the future for your visitors and how you can convert them, how you can get them to sign up on your newsletter, or you can get them to ask presales questions, or fill out forms or what have you. It&#8217;ll be very moldable and shapeable.</p>\n\n\n\n<p>So I delightfully was at several demo presentations at this meetup where I was just blown away. Sat down with Matias, James, a lot of the key stakeholders and players here at .com on how and when we can start bringing this into Jetpack.</p>\n\n\n\n<p>And what&#8217;s there right now is good. It&#8217;s almost going to be entirely rewritten and thrown away for what the foundation now is going to become. And so that&#8217;s one of the more exciting, more immediate, roadmap items that I&#8217;ll be really working on the next 8 to 12 months. You&#8217;ll see a huge change.</p>\n\n\n\n<p>[00:22:54] <strong>Nathan Wrigley:</strong> I feel like at the moment the AI implementation in Jetpack is about content, the content that you&#8217;re creating right at this moment. We&#8217;re creating, I don&#8217;t know, SEO fields and we&#8217;re creating excerpts and things like that and featured images and what have you. But if you haven&#8217;t had a play, again, I&#8217;ll link this in the show notes, Automattic&#8217;s Telex, which is the capability to, you write a simple prompt and it will create a block for you. I feel that something like Jetpack with something like Telex, just hidden in the sidebar of a WordPress blog post would be really kind of interesting. You know, the idea that, I need a block for this.</p>\n\n\n\n<p>[00:23:26] <strong>Devin Walker:</strong> Are you reading my DMs? Because, exactly. You&#8217;ve already sort of got a crystal ball right there. And with Telex, that&#8217;s a huge opportunity for site building, for imagining anything that WordPress could be, and having it created there.</p>\n\n\n\n<p>Right now it&#8217;s great. It creates separate plugins, you can download and install them, you can&#8217;t sync them per site. It&#8217;s kind of annoying how there&#8217;s all these plugins there. There&#8217;s not much management updating over time. Jetpack can be that bridge for you, and that&#8217;s really an exciting future where it needs to go.</p>\n\n\n\n<p>[00:23:57] <strong>Nathan Wrigley:</strong> Yeah, because at the moment, if you are an inexperienced WordPress user, if you&#8217;re not technical, let&#8217;s put it that way, then you are constrained entirely by what&#8217;s there or what the developer has built for you or the range of plugins that you&#8217;ve installed. And I feel like in the near future, you reach that point of frustration and you suddenly realise that, oh, there is no block that does that thing. Well, why don&#8217;t I just make one?</p>\n\n\n\n<p>And you&#8217;ll write a small prompt, I don&#8217;t know, I need a real estate block, or I don&#8217;t know, I need a block because it&#8217;s coming up to Christmas. I need a block which is going to show snowflakes falling on this particular post. Please don&#8217;t do this by the way, but you get the point. I&#8217;m just going to go ahead and make it, and it&#8217;ll be this entirely disposable thing. And when I&#8217;m finished with it, I&#8217;ll probably just throw it in the trash or maybe keep it until next year.</p>\n\n\n\n<p>But the point is, your WordPress becomes like this, how to describe it, it&#8217;s almost like the scaffolding for an infinite arrangement of possibilities. Whereas before, WordPress felt a bit like a box. If it wasn&#8217;t in the box, it couldn&#8217;t be done. But now the box got opened and there&#8217;s all this scaffolding everywhere and it can do a million more things. And as Matt Mullenweg said, you know, it&#8217;s becoming like the OS for the web or something like that.</p>\n\n\n\n<p>And the fact that AI is binding to the abilities inside of WordPress, so with the Abilities API and things like that, it knows everything that your WordPress website can do. You know, create users, create posts, delete posts, all of these kind of things. And Jetpack seems really aligned to doing that. I don&#8217;t know how it would fit into the bigger Jetpack picture, but, yeah, interesting.</p>\n\n\n\n<p>[00:25:27] <strong>Devin Walker:</strong> Yeah, well, I think AI can be the glue that binds a lot of these individual products together and really paint the picture on how they work well together, and work within your WordPress Core to make it the Jetpack that is supercharged, right? I mean the WordPress that has a Jetpack strapped to it.</p>\n\n\n\n<p>There is a great number of, kind of mission statements and taglines over the years for Jetpack. None of which I think have been fully fulfilled. So I really want to revisit that, revise that, and you&#8217;ll see a lot of updates coming to the website soon, soon-ish. Telling and bringing people along this journey.</p>\n\n\n\n<p>If you look at the website and a lot of the marketing right now, it&#8217;s kind of on idle. So that&#8217;s another big part of what I&#8217;m being focused on, and that will help change the perception in the community and outside of it, of what Jetpack is and what it can do for you is, pulling up the curtain, if you will, on all the cool stuff we&#8217;re doing here.</p>\n\n\n\n<p>You could read P2s all day here and many of them are so impressive and I feel like a lot of them should be public. There&#8217;s so much good content here that is really impressive. For somebody like me who&#8217;s been in the community for 15 years, like, oh my gosh, we have the best engineers, the best designers, and it&#8217;s all in this P2. Like, let&#8217;s get some of this published.</p>\n\n\n\n<p>[00:26:42] <strong>Nathan Wrigley:</strong> Yeah, well, that&#8217;s curious. So I was reading your mind a minute ago, you&#8217;ve just read my mind, because the next little bit was going to be all about marketing. Because it doesn&#8217;t matter, with the best will in the world, the best product in the world will probably fail, if not marketed correctly.</p>\n\n\n\n<p>And it feels as if, when Jetpack began, because it was kind of the thing, a long, long time ago it was the thing, it had that success kind of built into it. You know, it was an Automattic thing, it was a WordPress thing, it became popular because it did so many things that nothing else could do.</p>\n\n\n\n<p>Fast forward till today, it feels like the wheels have come off the marketing a little bit, or the train has completely pulled into the station and not moving at all. You know, I can&#8217;t remember the last time I saw something engaging, like a YouTube video or somebody experimenting on their YouTube channel with a Jetpack thing.</p>\n\n\n\n<p>Whereas with third party plugins, it&#8217;s happening all the time, you know? And so it feels like that&#8217;s going to be a very big part of where you are, you know, you&#8217;ll build hopefully some amazing things, but then trying to turn the tide and get people to be engaged and interested and see the utility of it. I&#8217;m guessing that&#8217;s going to be a part of the job which is separate to the technological part.</p>\n\n\n\n<p>[00:27:46] <strong>Devin Walker:</strong> It will, absolutely. I think for quite some time it was almost build it and they will come here. And for many, many years they did come. And now it&#8217;s harder because the marketplace has expanded quite a bit. There&#8217;s a lot of other folks out there doing really cool things with WordPress and have a lot more focused marketing efforts behind them.</p>\n\n\n\n<p>I mean, point and case was GiveWP, we were just, people weren&#8217;t turning to Woo or Gravity Forms because we made it that it was the number one solution you had to go do it. We just hammered that point through WordCamps, through videos, through podcasts, whatever it was, that was our mission.</p>\n\n\n\n<p>And for Jetpack, we really need to refocus on that and do that a lot more. It&#8217;s very engineering led organisation. I think marketing to some point is built into their roles and they&#8217;re not doing that part as much as I would like.</p>\n\n\n\n<p>And on another aspect, I think we definitely just need more marketers. I&#8217;m not going to say the exact numbers, but it was a surprisingly low number of marketers to the size of the organisation when I came in. I&#8217;m used to a much better ratio.</p>\n\n\n\n<p>So I&#8217;m going to be hammering that point a little bit more home as I get through the door, but it&#8217;s something that I&#8217;ve mentioned a bit already in my 5 weeks here.</p>\n\n\n\n<p>[00:29:02] <strong>Nathan Wrigley:</strong> I don&#8217;t know what the install base is specifically. It&#8217;s a lot, right? Jetpack has a lot of installs and so presumably you&#8217;ve.</p>\n\n\n\n<p>[00:29:08] <strong>Devin Walker:</strong> The core is 4 million.</p>\n\n\n\n<p>[00:29:09] <strong>Nathan Wrigley:</strong> 4 million. Okay, so, wow, gosh. So presumably that means anything that you do do, you&#8217;ve really got to tread carefully. So for a start, you can&#8217;t break things. You can&#8217;t just ship a brand new UI in let&#8217;s say the forms aspect of it overnight. And I presume that&#8217;s kind of like a bit of a noose around your neck in that, you know, you want to move fast and break things in some respects, but with 4 million installs, which is really right at the very top in the WordPress ecosystem, that&#8217;s big, big numbers. You are going to constrained in what you can do and how fast you can move things and how quickly you can break things.</p>\n\n\n\n<p>[00:29:40] <strong>Devin Walker:</strong> Somewhat. Somewhat I agree with that. Right now we are on a monthly release cycle and there&#8217;s definitely a lot of caution around that. And Jetpack touches a lot of .com too, so there&#8217;s that extra added user base, which is humongous. So there is that bit of treading carefully.</p>\n\n\n\n<p>But I want to balance that with being aggressive. We just shipped, prior to me coming on board, a new onboarding for getting connected. It&#8217;s just through the connection segment, getting connected to .com, and that really had positive results and saw an uptick in connected successful sites. I think we can take that to the next level and explain what Jetpack is, what they need it for, and really optimise it for the best use case based on what that particular site wants or needs.</p>\n\n\n\n<p>Going beyond onboarding is then getting into the product UI itself, making the navigation much more clear and understandable.</p>\n\n\n\n<p>You know, there&#8217;s three different areas in Jetpack right now where you can toggle on and off different modules or products.</p>\n\n\n\n<p>[00:30:39] <strong>Nathan Wrigley:</strong> Oh, I&#8217;ve discovered many them.</p>\n\n\n\n<p>[00:30:41] <strong>Devin Walker:</strong> Yeah. So I think we need to consolidate that at least. And there&#8217;s more Easter eggs. I don&#8217;t even want to call them Easter, I don&#8217;t know what you&#8217;d call that, but interesting quirks that we can clean up.</p>\n\n\n\n<p>And for the most part I think we do have to be a bit careful because it&#8217;s such a massive user base. Breaking things, just look at some of the Jetpack reviews. Breaking them and lack of support. Those are the two main cause of one star reviews. And with that many, I really want to get that review base above 4.0 stars. But with 3000 or whatever reviews it is, it takes a long shift to get that. And we&#8217;re not going to do that by continually breaking things, so it&#8217;s a balance.</p>\n\n\n\n<p>[00:31:19] <strong>Nathan Wrigley:</strong> It&#8217;s kind of interesting that me, a relatively inexperienced user of Jetpack, I was able to discover many of the quirks that you&#8217;ve just mentioned almost immediately. You know, just being curious. And I&#8217;m the kind of person that when I download anything, I go and look at every single menu item and kind of think, well, what does that do? How would that work? It really didn&#8217;t take me long to discover, well, hang on, that is somewhere else. If I engage that, does that mean it conflicts with this thing over here?</p>\n\n\n\n<p>And I saw this over and over again. And so I think that, as you imagine, would be some of the very, very brilliant low hanging fruit. To just have a UI which does, you know, there&#8217;s one place for one thing, it works as expected that you don&#8217;t, I&#8217;m sure you know where I&#8217;m going with this, basically, just simplify things, make it elegant in the same way that we&#8217;ve seen with so many third party plugins.</p>\n\n\n\n<p>Because at the moment it kind of feels like a whole range of different things that have been slammed together and forcefully told to get along with each other, as opposed to like a happy family that, just everything works and everybody&#8217;s happy and there&#8217;s bliss and rainbows everywhere. It feels a little bit like that, if you know what I mean?</p>\n\n\n\n<p>[00:32:21] <strong>Devin Walker:</strong> Oh, I completely agree. I think we used in the pre-show and it&#8217;s a bit of a Frankenstein. We need to change it from that. If I had a nickel for every toggle in Jetpack, I don&#8217;t know if I&#8217;d need to work anymore. There are quite a few toggle on, toggle offs in just a row. You can imagine how this interface could be much more elegantly put together.</p>\n\n\n\n<p>And we&#8217;re going to use user feedback for a lot of this and ask, hey, what do you guys think of this? Because we can&#8217;t do it successfully in a bubble.</p>\n\n\n\n<p>[00:32:52] <strong>Nathan Wrigley:</strong> Well, and the other thing is, given the perfect UI, it does so much stuff. If you just had Jetpack, if you had a vanilla version of WordPress and you installed Jetpack and everything was easy to navigate and worked as expected first time and maybe there was no dependency on having a .com account or what have you. It does all the things. It would take you from like zero success to broadly speaking, okay, you&#8217;ve got a credible website. Maybe there&#8217;s going to be some interesting cases where you want a little bit more SEO finesse or something like that.</p>\n\n\n\n<p>It would get you to the races, you know, it would get you to put your horse in the race and have a good go. And there&#8217;s not much like that out there. There really is nothing that I can think of in the WordPress space. But it&#8217;s a leviathan and it&#8217;s got many heads. We need it just to have the one head, I think.</p>\n\n\n\n<p>[00:33:35] <strong>Devin Walker:</strong> Very much so, and that&#8217;s the challenge that I&#8217;m in here to work with this entire team and put a lot of thought behind it.</p>\n\n\n\n<p>[00:33:44] <strong>Nathan Wrigley:</strong> Okay, so it&#8217;s all on you. So if Jetpack is a success in two years time, we know who to thank for that. And it does genuinely seem, for somebody with your obvious interest and capabilities, it does seem really, really enjoyable. I&#8217;m sure it&#8217;ll keep you awake, but an enjoyable challenge. Something that you get your teeth into. Something where the success can be measured fairly quickly. You know, does the discontent diminish? Does the UI improve? Tick, tick, tick. We did a good job.</p>\n\n\n\n<p>And also, there&#8217;s loads of room for improvement. So you&#8217;ve entered on a, you&#8217;ve definitely got yourself into a position where you&#8217;ve taken on a project where the improvements are evident everywhere. I hope that you managed to grab hold of them and wrestle this to the ground.</p>\n\n\n\n<p>[00:34:21] <strong>Devin Walker:</strong> Well, I really appreciate that, Nathan, and why don&#8217;t we have a check in in 12 months and see where we&#8217;re at on this journey. I think that would be a good way to keep us honest, follow along in this journey along the way, we&#8217;ll see how far we&#8217;ve gotten.</p>\n\n\n\n<p>[00:34:35] <strong>Nathan Wrigley:</strong> Okay, well, for now then, go and install Jetpack. If you&#8217;re listening to this, we&#8217;ll be back in 12 months time, so go and have a play with Jetpack as it is now and see.</p>\n\n\n\n<p>It sounds to me that Devin is like all ears. If you&#8217;ve got some quirks and you found something that&#8217;s curious or unexpected or dissatisfying or just downright annoying, where do we get in touch with you? Oh, also, I suspect Devin&#8217;s more than happy to receive positive commentary as well.</p>\n\n\n\n<p>[00:35:01] <strong>Devin Walker:</strong> Yeah, I mean the positive stuff&#8217;s great too. Right now feedback@jetpack.com is a good place, but we&#8217;re going to make this a lot more public in the near future. You can also just tweet at me @innerwebs, I-N-N-E-R-W-E-B-S, or go to my website devin.org. But jetpack.com, jetpack.com/feedback is also a great place. So that&#8217;s a bit about me and where you can find the Jetpack information.</p>\n\n\n\n<p>[00:35:27] <strong>Nathan Wrigley:</strong> Okay, thank you. So definitely a challenge out in the public for Devin to get his teeth into WordPress&#8217; Jetpack, and see if he can figure it out and make it better. Let&#8217;s check back in 12 months time and see how we&#8217;re going. Devin Walker, thanks for chatting to me today.</p>\n\n\n\n<p>[00:35:38] <strong>Devin Walker:</strong> Thank you.</p>\n</div></details>\n\n\n\n<p>On the podcast today we have <a href=\"https://devin.org\">Devin Walker</a>.</p>\n\n\n\n<p>Devin’s journey in the WordPress ecosystem spans many years, with experience in development, design, marketing, and customer support. He’s best known as the co-founder of GiveWP, which he built and scaled before it was acquired. During his time there, he touched a variety of prominent WordPress brands including iThemes, Kadence, LearnDash, and The Events Calendar.</p>\n\n\n\n<p>Today, Devin is starting a new role leading the Jetpack suite of services at Automattic. It’s a position with hefty responsibilities as Jetpack powers millions of WordPress sites, and integrates deeply across Automattic’s product portfolio.</p>\n\n\n\n<p>I talk with Devin about why he took on this challenge, the divisiveness and complexity surrounding Jetpack, and his vision for refocusing the plugin and simplifying its user experience.</p>\n\n\n\n<p>We start by hearing about Devin’s extensive WordPress background and the choices he weighed up when deciding to join Automattic. The conversation quickly moves to the scope of Jetpack, its evolution, the struggle to be a “jack of all trades, master of none”, and the recent efforts to bring greater focus and polish to key features like forms and SEO.</p>\n\n\n\n<p>Devin gets into the organisational changes at Automattic, how Jetpack’s development teams now collaborate more fluidly with other product teams (such as WooCommerce), and the balancing act of shipping improvements to a 4 million strong user base without breaking things.</p>\n\n\n\n<p>AI emerges as a massive new frontier, and Devin shares behind-the-scenes insights into Jetpack’s current and future AI capabilities, giving us a glimpse at content creation, block-building, and how AI might reshape user and developer expectations in WordPress.</p>\n\n\n\n<p>Throughout, we hear about Devin’s approach to product marketing (and the need for more of it), the importance of listening to user feedback, and his plans for a more coherent and compelling Jetpack experience.</p>\n\n\n\n<p>If you’re a WordPress user wondering where Jetpack is headed, what’s working, or how AI fits into the future of site building, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p><a href=\"https://jetpack.com\">Jetpack</a></p>\n\n\n\n<p><a href=\"https://jetpack.com/submit-feedback/\">Jetpack feedback form</a></p>\n\n\n\n<p><a href=\"https://givewp.com\">GiveWP</a></p>\n\n\n\n<p><a href=\"https://en-gb.wordpress.org/plugins/wp-rollback/\"> WP Rollback</a></p>\n\n\n\n<p><a href=\"https://wordpress.org/news/2025/05/announcing-the-formation-of-the-wordpress-ai-team/\">Automattic AI team announcement post</a></p>\n\n\n\n<p><a href=\"https://telex.automattic.ai\">Telex</a></p>\n\n\n\n<p><a href=\"https://devin.org\">Devin&#8217;s website</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 19 Nov 2025 15:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:27:\"Open Channels FM: Open Tabs\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://openchannels.fm/?p=112264\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://openchannels.fm/the-everyday-chaos-of-open-tabs-and-browser-battles/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:180:\"Bob and Nathan explore the chaos of browser tabs. One hoards thousands, while the other balances life with two. Tune in for witty banter, tech quirks, and questionable life advice.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 19 Nov 2025 11:52:22 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"BobWP\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:226:\"HeroPress: From carpentry to digital marketing, this is the story of how WordPress helped me rebuild my life. – De la carpintería al marketing digital, esta es la historia de cómo WordPress me ayudó a reconstruir mi vida.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://heropress.com/?post_type=heropress-essays&p=8280\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:266:\"https://heropress.com/essays/from-carpentry-to-digital-marketing-this-is-the-story-of-how-wordpress-helped-me-rebuild-my-life/#utm_source=rss&utm_medium=rss&utm_campaign=from-carpentry-to-digital-marketing-this-is-the-story-of-how-wordpress-helped-me-rebuild-my-life\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:13418:\"<img alt=\"Pull quote: I have a new job, new friends, and I could almost say a new family, and it’s all thanks to WordPress.\" class=\"attachment-large size-large wp-post-image\" height=\"512\" src=\"https://heropress.com/wp-content/uploads/2025/11/111825.webp\" width=\"1024\" /><p><a href=\"https://heropress.com/feed/#espanol\">Este ensayo también está disponible en español.</a></p>\n\n\n\n\n\n\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px; margin-top: 0px; margin-bottom: 0px;\">\n<figure class=\"wp-block-audio\"><audio controls=\"controls\" src=\"https://heropress.com/wp-content/uploads/2025/11/HeroPress_English_Version_JosepMoran.mp3\"></audio><figcaption class=\"wp-element-caption\">Here is Josep reading his own story aloud.</figcaption></figure>\n</section>\n\n\n\n\n<h2 class=\"kt-adv-heading8280_0f0037-3f wp-block-kadence-advancedheading\"><strong>My origins</strong></h2>\n\n\n\n<p>I’m Josep, born and raised in <a href=\"https://en.wikipedia.org/wiki/Rocafonda\">Rocafonda</a>, a working-class and humble neighborhood in <a href=\"https://en.wikipedia.org/wiki/Matar%C3%B3\">Mataró</a>.</p>\n\n\n\n<p>I come from a family that has worked with wood lovingly for three generations. Carpentry was always our trade, our way of understanding life and making a living.</p>\n\n\n\n<p>For many years, I worked with wood, shaping it with the same hands and patience I learned at home.</p>\n\n\n\n<p>At the same time, my curiosity led me down other paths: interior design and technical drawing as a draftsman, where I discovered the joy of imagining spaces before building them.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-the-turning-point\"><strong>The turning point</strong></h2>\n\n\n\n<p>Everything changed during the COVID-19 pandemic when my heart decided to stop beating properly. A genetically inherited heart condition forced me to stop completely and look at life from a new perspective.</p>\n\n\n\n<p>Suddenly, everything I took for granted; health, routines, the simple act of making plans disappeared, just as my life almost did.</p>\n\n\n\n<p>But it didn’t.</p>\n\n\n\n<p>I pulled through. With after-effects, yes, but with an incredible desire to live.<br />Out of that will to live came the decision to reinvent myself and study while recovering.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-new-life-new-goals\"><strong>New life, new goals</strong></h2>\n\n\n\n<p>There were twenty-six months of rehabilitation, relapses, and searching for an effective treatment.<br /><br />Yet, amid all that chaos, I managed to step back and turn my skills into a new opportunity.<br /><br />I studied Content Marketing and discovered a well-known secret for many, but something completely new for a carpenter from a neighborhood in Mataró.</p>\n\n\n\n<p>WordPress.<br /><br />And with it, its community.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-metamorphosis\"><strong>Metamorphosis</strong></h2>\n\n\n\n<p>And then… everything changed.</p>\n\n\n\n<p>I discovered WordPress through my marketing studies, and thanks to our beloved CMS, I created my first blog. I keep the logo and some of my early posts, remnants of a time when I was learning to tell stories and give shape to ideas.</p>\n\n\n\n<p>In May 2023, I volunteered for my first WordCamp in Barcelona. The experience opened my eyes to a new universe full of generous, passionate people eager to share.</p>\n\n\n\n<p>I quickly connected with the community and joined the Mentorship Program, a global initiative from the Community Team. I was one of the first eleven mentees in the world. For me, it was a dream come true.</p>\n\n\n\n<p>Shortly afterward, I began combining my increasingly active contributions with the same program, but this time as a mentor. I had received so much from the community that my gratitude pushed me to give back that knowledge and share those values with anyone willing to listen.</p>\n\n\n\n<p>I continued collaborating as a volunteer, speaker, and documentation table participant at <a href=\"https://europe.wordcamp.org/2024/\">WordCamp Europe Torino</a> 2024. It was a step forward in every sense from learning to teaching, from receiving to contributing.</p>\n\n\n\n<p>I began managing the Spain Handbook documentation alongside my mentors <strong><a href=\"https://profiles.wordpress.org/javiercasares/\">Javier Casares</a></strong> and <strong><a href=\"https://profiles.wordpress.org/glycymeris/\">Jesús Yesares</a></strong>. Together, we laid the foundations for a project that, like everything in WordPress, is built with patience and community.</p>\n\n\n\n<p>I also joined the global documentation team for WordPress version 6.6, “Dorsey.”</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-rising-from-my-ashes\"><strong>Rising from my ashes</strong></h2>\n\n\n\n<p>Thanks to WordPress and its community, I grew as a person and as a professional in a new discipline as competitive as it is exciting and alive.</p>\n\n\n\n<p>They supported me through the hardest moments and helped me rise again, like a phoenix from the ashes.</p>\n\n\n\n<p>At the end of 2023, through the <strong><a href=\"https://wordpress.org/five-for-the-future/\">Five for the Future</a></strong> initiative, <strong><a href=\"https://wetopi.com/\">Wetopi</a></strong>, a high-performance managed hosting company that exclusively hosts WordPress sites, placed its trust in a newcomer to the industry and offered me a full-time position where I could unleash all the creativity I had inside.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-present-and-future\"><strong>Present and future</strong></h2>\n\n\n\n<p>If there’s one thing I learned during my illness, it’s to enjoy the moment and not worry so much about the future.</p>\n\n\n\n<p>That’s my focus now, the present, always grateful to all those who helped me become who I am today, in 2025.</p>\n\n\n\n<p>I have a new job, new friends, and I could almost say a new family, and it’s all thanks to WordPress.</p>\n\n\n\n<p>Many people tell me that if I weren’t so resilient, persistent, and determined, I wouldn’t have achieved any of this.</p>\n\n\n\n<p>I simply smile and think that all those qualities were brought to light one day by <strong><a href=\"https://heropress.com/contributors/hari-shanker/\">Hari Shanker</a></strong>, during the <strong><a href=\"https://make.wordpress.org/community/handbook/contributor-day/contributor-working-group/contributor-mentorship-program-for-wordpress/\">Mentorship Program</a></strong>, together with WordPress and its community.</p>\n\n\n\n<p><strong>Thank you to all of them.</strong></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h1 class=\"kt-adv-heading8280_df5daf-9a wp-block-kadence-advancedheading\" id=\"espanol\">De la carpintería al marketing digital, esta es la historia de cómo WordPress me ayudó a reconstruir mi vida.</h1>\n\n\n\n\n<section class=\"wp-block-newsletterglue-group\" style=\"padding-top: 0px; padding-bottom: 0px; padding-left: 0px; padding-right: 0px; margin-top: 0px; margin-bottom: 0px;\">\n<figure class=\"wp-block-audio\"><audio controls=\"controls\" src=\"https://heropress.com/wp-content/uploads/2025/11/HeroPress_Spanish_Version_JosepMoran.mp3\"></audio><figcaption class=\"wp-element-caption\">Escucha a Josep leer su propia historia en voz alta.</figcaption></figure>\n</section>\n\n\n<h2 class=\"wp-block-heading\" id=\"h-mis-origenes\"><strong>Mis orígenes</strong></h2>\n\n\n\n<p>Soy Josep, nacido y criado en <a href=\"https://en.wikipedia.org/wiki/Rocafonda\">Rocafonda</a>, un barrio trabajador y humilde de <a href=\"https://en.wikipedia.org/wiki/Matar%C3%B3\">Mataró</a>.</p>\n\n\n\n<p>Vengo de una familia que ha trabajado la madera con mimo durante tres generaciones. La carpintería siempre fue nuestro oficio, nuestra forma de entender la vida y de ganárnosla.</p>\n\n\n\n<p>Durante muchos años trabajé la madera, moldeándola con las manos y la paciencia que aprendí en casa.</p>\n\n\n\n<p>Al mismo tiempo, mi curiosidad me llevó por otros caminos: el diseño de interiores y el dibujo técnico como delineante, donde descubrí el placer de imaginar espacios antes de construirlos.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-el-punto-de-inflexion\"><strong>El punto de inflexión</strong></h2>\n\n\n\n<p>Todo cambió en plena pandemia de la COVID-19, cuando mi corazón decidió detener el ritmo.<br />Una enfermedad cardíaca de origen genético me obligó a parar por completo y mirar la vida desde otro lugar.</p>\n\n\n\n<p>De repente, aquello que daba por sentado —la salud, las rutinas, el simple hecho de poder hacer planes— se desvaneció, como casi se desvanece mi vida.</p>\n\n\n\n<p>Pero no.</p>\n\n\n\n<p>Salí adelante. Con secuelas, sí, pero con unas ganas de vivir increíbles.<br />Y fruto de esas ganas decidí reinventarme y estudiar mientras me recuperaba.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-nueva-vida-nuevas-metas\"><strong>Nueva vida, nuevas metas</strong></h2>\n\n\n\n<p>Fueron veintiséis meses entre rehabilitación, recaídas y la búsqueda de un tratamiento eficaz.<br />Pero, entremedio de todo ese caos, supe abstraerme y convertir mis habilidades en una nueva oportunidad.<br />Estudié Marketing de Contenidos y descubrí un secreto a voces para muchos, pero completamente nuevo para un carpintero de un barrio de Mataró.</p>\n\n\n\n<p>WordPress.<br />Y con él, su comunidad.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-metamorfosis\"><strong>Metamorfosis</strong></h2>\n\n\n\n<p>Y entonces… todo cambió.</p>\n\n\n\n<p>Conocí WordPress gracias a mis estudios de marketing y, gracias a nuestro querido CMS, pude crear mi primer blog.<br />Aún conservo el logo y algunos de mis primeros textos, vestigios de una etapa en la que aprendía a contar historias y a dar forma a ideas.</p>\n\n\n\n<p>En mayo de 2023 me ofrecí como voluntario en mi primera WordCamp, en Barcelona. La experiencia me abrió los ojos a un universo nuevo, lleno de personas generosas, apasionadas y con ganas de compartir.</p>\n\n\n\n<p>Rápidamente conecté con la comunidad y accedí al Mentorship Program, un proyecto global del equipo de Comunidad.<br />Fui uno de los primeros once mentees del mundo. Para mí, era un sueño.</p>\n\n\n\n<p>Poco después, pasé a compaginar mis contribuciones, cada vez más activas, con el mismo programa, pero esta vez como mentor.<br />Había recibido mucho de la comunidad, y mi gratitud me empujó a devolver ese conocimiento y a compartir esos valores con todo aquel que quisiera escucharme.</p>\n\n\n\n<p>Seguí colaborando como voluntario, ponente y participante en la mesa de documentación en la <a href=\"https://europe.wordcamp.org/2024/\">WordCamp Europe Torino</a> 2024.<br />Fue un salto de calidad, y también un salto personal: de aprender a enseñar, de recibir a aportar.</p>\n\n\n\n<p>Comencé a gestionar la documentación del Spain Handbook junto a mis mentores <a href=\"https://profiles.wordpress.org/javiercasares/\">Javier Casares</a> y <a href=\"https://profiles.wordpress.org/glycymeris/\">Jesús Yesares</a>.<br />Juntos pusimos las bases de un proyecto que, como todo en WordPress, se construye con paciencia y en comunidad.</p>\n\n\n\n<p>También formé parte del equipo de documentación global para la versión 6.6 de WordPress, “Dorsey”.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-renacer-de-mis-cenizas\"><strong>Renacer de mis cenizas</strong></h2>\n\n\n\n<p>Gracias a WordPress y a su comunidad crecí como persona y como profesional en una nueva disciplina: tan competitiva como apasionante y viva.</p>\n\n\n\n<p>Me sostuvieron durante mis malos momentos e hicieron que resurgiese como si de un ave fénix se tratase.</p>\n\n\n\n<p>A finales de 2023, gracias al proyecto <a href=\"https://wordpress.org/five-for-the-future/\">Five For The Future</a>, <a href=\"https://wetopi.com/\">Wetopi</a> —una empresa de hosting gestionado de altas prestaciones que aloja únicamente sitios web creados con WordPress— confió en un recién llegado al sector y me ofreció un proyecto a tiempo completo donde podía dar rienda suelta a toda la creatividad que llevaba dentro.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-presente-y-futuro\"><strong>Presente y futuro</strong></h2>\n\n\n\n<p>Si algo aprendí en mi época de enfermedad es a disfrutar más el momento y no pensar tanto en el futuro.</p>\n\n\n\n<p>Y en eso me centro: en el presente, agradeciendo siempre a todas aquellas personas que me ayudaron a ser quien soy hoy, en 2025.</p>\n\n\n\n<p>Tengo un nuevo empleo, nuevos amigos, casi puedo decir que una nueva familia, y es todo, todo, gracias a WordPress.</p>\n\n\n\n<p>Mucha gente me dice que, si yo no fuese tan resiliente, resistente y tenaz, no habría conseguido nada.</p>\n\n\n\n<p>Yo simplemente les sonrío y pienso que todas esas cualidades las hizo aflorar un día <a href=\"https://heropress.com/contributors/hari-shanker/\">Hari Shanker</a>, en el <a href=\"https://make.wordpress.org/community/handbook/contributor-day/contributor-working-group/contributor-mentorship-program-for-wordpress/\">Mentorship Program</a>, junto con WordPress y toda su comunidad.<br /><br /><strong>A todos ellos gracias.</strong></p>\n<p>The post <a href=\"https://heropress.com/essays/from-carpentry-to-digital-marketing-this-is-the-story-of-how-wordpress-helped-me-rebuild-my-life/\">From carpentry to digital marketing, this is the story of how WordPress helped me rebuild my life. &#8211; De la carpintería al marketing digital, esta es la historia de cómo WordPress me ayudó a reconstruir mi vida.</a> appeared first on <a href=\"https://heropress.com\">HeroPress</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 19 Nov 2025 09:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Josep Morán\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"WordPress.org blog: WordPress 6.9 Release Candidate 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=19350\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://wordpress.org/news/2025/11/wordpress-6-9-release-candidate-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:10460:\"<p>The second Release Candidate (“RC2”) for WordPress 6.9 is ready for download and testing!</p>\n\n\n\n<p><strong>This version of the WordPress software is under development</strong>.<strong> Please do not install, run, or test this version of WordPress on production or mission-critical websites.</strong> Instead, it’s recommended that you evaluate RC2 on a test server and site.</p>\n\n\n\n<p>Reaching this phase of the release cycle is an important milestone. While release candidates are considered ready for release, testing remains crucial to ensure that everything in WordPress 6.9 is the best it can be.</p>\n\n\n\n<p>You can test WordPress 6.9 RC2 in four ways:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Install and activate the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> plugin on a WordPress install. (Select the “Bleeding edge” channel and “Beta/RC Only” stream).</td></tr><tr><td><strong>Direct Download</strong></td><td>Download the <a href=\"https://wordpress.org/wordpress-6.9-RC2.zip\">RC2 version (zip)</a> and install it on a WordPress website.</td></tr><tr><td><strong>Command Line</strong></td><td>Use the following <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> command:<br /><code>wp core update --version=6.9-RC2</code></td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use the <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn85xn\">6.9 RC2 WordPress Playground instance</a> to test the software directly in your browser without the need for a separate site or setup.</td></tr></tbody></table></figure>\n\n\n\n<p>The scheduled final release date for WordPress 6.9 is <strong>December 2, 2025</strong>. The full <a href=\"https://make.wordpress.org/core/6-9/\">release schedule can be found here</a>. Your help testing RC versions is vital to making this release as stable and powerful as possible.</p>\n\n\n\n<p>Please continue checking the <a href=\"https://make.wordpress.org/core/\">Make WordPress Core blog</a> for <a href=\"https://make.wordpress.org/core/tag/6-9/\">6.9-related posts</a> in the coming weeks for more information.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What’s in WordPress 6.9 RC2?</h2>\n\n\n\n<p>Get a recap of WordPress 6.9’s highlighted features in the <a href=\"https://make.wordpress.org/core/2025/10/21/wordpress-6-9-beta-1/\">Beta 1 announcement</a>. For more technical information related to issues addressed since RC1, you can browse the following links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/6.9?since=2025-11-11&amp;until=2025-11-18\">GitHub commits for 6.9</a> since November 11</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=11%2F11%2F2025..11%2F18%2F2025&amp;milestone=6.9&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=changetime&amp;col=type&amp;order=id\">Closed Trac tickets</a> since November 11</li>\n</ul>\n\n\n\n<p>Want to look deeper into the details and technical notes for this release? These recent posts cover some of the latest updates:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/core/2025/11/15/notes-feature-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Notes Feature in 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/10/abilities-api-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Abilities API in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/18/wordpress-6-9-frontend-performance-field-guide/\">WordPress 6.9 Frontend Performance Field Guide</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/interactivity-apis-client-navigation-improvements-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Interactivity API’s client navigation improvements in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/block-bindings-improvements-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Block Bindings improvements in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/changes-to-the-interactivity-api-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Changes to the Interactivity API in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/17/consistent-cache-keys-for-query-groups-in-wordpress-6-9/\">Consistent Cache Keys for Query Groups in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/11/dataviews-dataform-et-al-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">DataViews, DataForm, et al. in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/preparing-the-post-editor-for-full-iframe-integration/\" rel=\"noreferrer noopener\" target=\"_blank\">Preparing the Post Editor for Full iframe Integration</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/theme-json-border-radius-presets-support-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Theme.json Border Radius Presets Support in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/12/heading-block-css-specificity-fix-in-wordpress-6-9/\" rel=\"noreferrer noopener\" target=\"_blank\">Heading Block CSS Specificity Fix in WordPress 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/17/miscellaneous-developer-focused-changes-in-6-9/\">Miscellaneous Developer-focused Changes in 6.9</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/core/2025/11/18/modernizing-utf-8-support-in-wordpress-6-9/\">Modernizing UTF-8 support in WordPress 6.9</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">How you can contribute</h2>\n\n\n\n<p>WordPress is open source software made possible by a passionate community of people collaborating on and contributing to its development. The resources below outline various ways you can help the world’s most popular open source web platform, regardless of your technical expertise.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Get involved in testing</h2>\n\n\n\n<p>Testing for issues is crucial to the development of any software. It’s also a meaningful way for anyone to contribute. </p>\n\n\n\n<p>Your help testing the WordPress 6.9 RC2 version is key to ensuring that the final release is the best it can be. While testing the upgrade process is essential, trying out new features is equally important. This <a href=\"https://make.wordpress.org/test/2025/10/21/help-test-wordpress-6-9/\">detailed guide</a> will walk you through testing features in WordPress 6.9. For those new to testing, follow <a href=\"https://make.wordpress.org/test/handbook/get-setup-for-testing/\">this general testing guide</a> for more details on getting set up.</p>\n\n\n\n<p>If you encounter an issue, please report it to the <a href=\"https://wordpress.org/support/forum/alphabeta/\">Alpha/Beta area</a> of the support forums or directly to <a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a> if you are comfortable writing a reproducible bug report.  You can also check your issue against a list of <a href=\"https://core.trac.wordpress.org/tickets/major\">known bugs</a>. </p>\n\n\n\n<p>Curious about testing releases in general?  Follow along with the <a href=\"https://make.wordpress.org/test/\">testing initiatives in Make Core</a> and join the<a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test channel</a> on <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Update your theme or plugin</h2>\n\n\n\n<p>For plugin and theme authors, your products play an integral role in extending the functionality and value of WordPress for all users.</p>\n\n\n\n<p>Thanks for continuing to test your themes and plugins with the WordPress 6.9 beta releases. If you haven’t yet, make sure to conclude your testing and update the <em>“Tested up to”</em> version in your <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">plugin’s readme file</a> to 6.9.</p>\n\n\n\n<p>If you find compatibility issues, please post detailed information to the <a href=\"https://wordpress.org/support/forum/alphabeta/\">support forum</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Test on your hosting platforms</h2>\n\n\n\n<p>Web hosts provide vital infrastructure for supporting WordPress and its users. Testing on hosting systems helps inform the development process while ensuring that WordPress and hosting platforms are fully compatible, free of errors, optimized for the best possible user experience, and that updates roll out to customer sites without issue.</p>\n\n\n\n<p>Want to test WordPress on your hosting system? <a href=\"https://make.wordpress.org/hosting/test-results-getting-started/\">Get started with configuring distributed hosting tests here</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Help translate WordPress</h2>\n\n\n\n<p>Do you speak a language other than English? ¿Español? Français? Русский? 日本語? हिन्दी? বাংলা? मराठी? ಕನ್ನಡ?  You can<a href=\"https://translate.wordpress.org/projects/wp/dev/\"> help translate WordPress into more than 100 languages</a>. This release milestone (RC2) also marks the<a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\"> hard string freeze</a> point of the <a href=\"https://make.wordpress.org/core/2025/11/11/wordpress-6-9-release-candidate-phase/\">6.9 release cycle</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">An RC2 haiku</h2>\n\n\n\n<p>A calm hillside sighs,<br />Work of many now complete —<br />RC2 stays true.</p>\n\n\n\n<p class=\"has-text-align-right\"><em>Props to <a class=\"mention\" href=\"https://profiles.wordpress.org/amykamala/\"><span class=\"mentions-prefix\">@</span>amykamala</a>, <a class=\"mention\" href=\"https://profiles.wordpress.org/annezazu/\"><span class=\"mentions-prefix\">@</span>annezazu</a>, <a class=\"mention\" href=\"https://profiles.wordpress.org/davidbaumwald/\"><span class=\"mentions-prefix\">@</span>davidbaumwald</a>, <a class=\"mention\" href=\"https://profiles.wordpress.org/westonruter/\"><span class=\"mentions-prefix\">@</span>westonruter</a> and <a class=\"mention\" href=\"https://profiles.wordpress.org/joedolson/\"><span class=\"mentions-prefix\">@</span>joedolson</a> for proofreading and review.</em></p>\n\n\n\n<p></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 18 Nov 2025 15:26:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Akshaya Rane\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:13;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"Weston Ruter: WordPress 6.9 Performance Landings\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://weston.ruter.net/?p=38085\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://weston.ruter.net/2025/11/17/wordpress-6-9-performance-landings/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:7991:\"<p>WordPress 6.9 includes so many performance improvements! Scripts with <code>fetchpriority</code>, increased inline CSS, minified theme styles, on demand block styles in classic themes, the template enhancement output buffer, and much more! Check out the <a href=\"https://make.wordpress.org/core/2025/11/18/wordpress-6-9-frontend-performance-field-guide/\">field guide</a> I just published:</p>\n\n\n\n<figure class=\"wp-block-embed is-type-wp-embed is-provider-make-wordpress-core wp-block-embed-make-wordpress-core\"><div class=\"wp-block-embed__wrapper\">\n<blockquote class=\"wp-embedded-content\"><a href=\"https://make.wordpress.org/core/2025/11/18/wordpress-6-9-frontend-performance-field-guide/\">WordPress 6.9 Frontend Performance Field Guide</a></blockquote>\n</div></figure>\n\n\n\n<p>There were many contributors from the <a href=\"https://make.wordpress.org/performance/handbook/about-the-team/\">Core Performance Team</a> involved in making this possible. Personally, this is a culmination of a year of work, including a bunch of research and development I <a href=\"https://weston.ruter.net/2025/08/27/the-site-speed-frontier-with-performance-lab-and-beyond/\">wrote about previously</a> and spoke about at WordCamp US:</p>\n\n\n\n<figure class=\"wp-block-embed is-type-wp-embed is-provider-weston-ruter wp-block-embed-weston-ruter\"><div class=\"wp-block-embed__wrapper\">\n<blockquote class=\"wp-embedded-content\"><a href=\"https://weston.ruter.net/2025/08/27/the-site-speed-frontier-with-performance-lab-and-beyond/\">The Site Speed Frontier with Performance Lab and Beyond</a></blockquote>\n</div></figure>\n\n\n\n<p>I&#8217;ve been working nights and weekends (and days) to help make sure all of this lands in time for the December 2nd release. This is evident from looking at the <a href=\"https://make.wordpress.org/updates/2025/11/15/a-month-in-core-october-2025/\">“A Month in Core” post for October</a>! It has been fun—feeling like the <a href=\"https://weston.ruter.net/2025/05/14/a-decade-as-a-core-committer-my-wordpress-contribution-history/\">good ol&#8217; contribution days</a> when I was deep in the Customizer up through <a href=\"https://weston.ruter.net/2017/11/03/wordpress-4-9/\">WordPress 4.9</a> (2013–2017). But I&#8217;m really looking forward to being able to unwind for the holidays.</p>\n\n\n\n<p><em>I hope your sites get a great speed boost for Christmas!</em> <img alt=\"🎄\" class=\"wp-smiley\" src=\"https://weston.ruter.net/wp-content/plugins/local-twemoji/images/emoji/72x72/1f384.png?ver=17-0-2-2\" style=\"height: 1em;\" /></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-medium-font-size\">Where I&#8217;ve shared the field guide:</p>\n\n\n\n<ul class=\"wp-block-social-links is-layout-flex wp-block-social-links-is-layout-flex\"><li class=\"wp-social-link wp-social-link-linkedin  wp-block-social-link\"><a class=\"wp-block-social-link-anchor\" href=\"https://www.linkedin.com/posts/westonruter_wordpress-69-frontend-performance-field-activity-7396418643473002498-7XFC\"><svg height=\"24\" version=\"1.1\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/svg\"><path d=\"M19.7,3H4.3C3.582,3,3,3.582,3,4.3v15.4C3,20.418,3.582,21,4.3,21h15.4c0.718,0,1.3-0.582,1.3-1.3V4.3 C21,3.582,20.418,3,19.7,3z M8.339,18.338H5.667v-8.59h2.672V18.338z M7.004,8.574c-0.857,0-1.549-0.694-1.549-1.548 c0-0.855,0.691-1.548,1.549-1.548c0.854,0,1.547,0.694,1.547,1.548C8.551,7.881,7.858,8.574,7.004,8.574z M18.339,18.338h-2.669 v-4.177c0-0.996-0.017-2.278-1.387-2.278c-1.389,0-1.601,1.086-1.601,2.206v4.249h-2.667v-8.59h2.559v1.174h0.037 c0.356-0.675,1.227-1.387,2.526-1.387c2.703,0,3.203,1.779,3.203,4.092V18.338z\"></path></svg><span class=\"wp-block-social-link-label screen-reader-text\">LinkedIn</span></a></li>\n\n<li class=\"wp-social-link wp-social-link-bluesky  wp-block-social-link\"><a class=\"wp-block-social-link-anchor\" href=\"https://bsky.app/profile/weston.ruter.net/post/3m5uyyujouk2o\"><svg height=\"24\" version=\"1.1\" viewBox=\"0 0 24 24\" width=\"24\" xmlns=\"http://www.w3.org/2000/