graph {\"style\":{\"typography\":{\"fontSize\":\"0.7em\"},\"color\":{\"text\":\"#C51313\"}}} -->\n<p class=\"has-text-color\" style=\"color:#C51313;font-size:0.7em\"><strong>9% de descuento</strong></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"style\":{\"spacing\":{\"blockGap\":\"0px\",\"margin\":{\"top\":\"5px\"}}},\"layout\":{\"type\":\"constrained\"}} -->\n<div class=\"wp-block-group\" style=\"margin-top:5px\"><!-- wp:paragraph {\"style\":{\"color\":{\"text\":\"#00A510\"},\"typography\":{\"fontSize\":\"0.7em\"},\"spacing\":{\"margin\":{\"top\":\"0px\",\"right\":\"0px\",\"bottom\":\"0px\",\"left\":\"0px\"}}}} -->\n<p class=\"has-text-color\" style=\"color:#00A510;margin-top:0px;margin-right:0px;margin-bottom:0px;margin-left:0px;font-size:0.7em\"><strong>Gratuito Envío en 2 Días</strong></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:paragraph {\"style\":{\"typography\":{\"fontSize\":\"0.8em\"},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color\" style=\"color:#000000;font-size:0.8em\">El \"Modern Elegance: Sofá Tapizado de Lujo en Gris Carbón\" armoniza estilo y comodidad para redefinir tu espacio vital. Esta impresionante pieza está hecha con cojines de espuma de alta densidad y suave al tacto, envueltos en una rica tela gris carbón que invita a tocarla. Sus líneas limpias y su silueta contemporánea se complementan con un robusto marco de madera, lo que lo convierte en una adición duradera y elegante a cualquier decoración del hogar. Ya sea que estés relajándote o entreteniendo, este sofá promete una comodidad inigualable y un aspecto que es perfectamente chic.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"constrained\",\"justifyContent\":\"left\"}} -->\n<div class=\"wp-block-group\"><!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-